					}
					return BoundaryType.ImmediateEndBoundary;
				}
				if (IsBoundary(start, length, boundary.Marker, boundary.Length))
				{
					if (i != 0)
					{
						return BoundaryType.ParentBoundary;
					}
					return BoundaryType.ImmediateBoundary;
				}
			}
			if (contentEnd > 0)
			{
