			}
			state = MimeParserState.MessageHeaders;
			if (Step(inbuf, cancellationToken) == MimeParserState.Error)
			{
				return BoundaryType.Eos;
			}
			MimeMessage mimeMessage = new MimeMessage(options, headers, RfcComplianceMode.Loose);
			ContentType contentType = GetContentType(null);
			if (preHeaderBuffer.Length != 0)
			{
				mimeMessage.MboxMarker = new byte[preHeaderLength];
				Buffer.BlockCopy(preHeaderBuffer, 0, mimeMessage.MboxMarker, 0, preHeaderLength);
			}
			MimeEntity mimeEntity = (mimeMessage.Body = options.CreateEntity(contentType, headers, toplevel: true));
			boundaryType = ((mimeEntity is Multipart) ? ConstructMultipart((Multipart)mimeEntity, inbuf, cancellationToken) : ((!(mimeEntity is MessagePart)) ? ConstructMimePart((MimePart)mimeEntity, inbuf, cancellationToken) : ConstructMessagePart((MessagePart)mimeEntity, inbuf, cancellationToken)));
			part.Message = mimeMessage;
			return boundaryType;
		}

		private unsafe BoundaryType MultipartScanPreamble(Multipart multipart, byte* inbuf, CancellationToken cancellationToken)
		{
			using MemoryStream memoryStream = new MemoryStream();
			bool empty;
			BoundaryType result = ScanContent(inbuf, memoryStream, trimNewLine: false, out empty, cancellationToken);
			multipart.RawPreamble = memoryStream.ToArray();
			return result;
		}

		private unsafe BoundaryType MultipartScanEpilogue(Multipart multipart, byte* inbuf, CancellationToken cancellationToken)
		{
			using MemoryStream memoryStream = new MemoryStream();
			bool empty;
			BoundaryType result = ScanContent(inbuf, memoryStream, trimNewLine: true, out empty, cancellationToken);
			multipart.RawEpilogue = (empty ? null : memoryStream.ToArray());
			return result;
		}

		private unsafe BoundaryType MultipartScanSubparts(Multipart multipart, byte* inbuf, CancellationToken cancellationToken)
		{
			BoundaryType boundaryType;
			do
			{
				if (!SkipLine(inbuf, consumeNewLine: true, cancellationToken))
				{
					return BoundaryType.Eos;
				}
				state = MimeParserState.Headers;
				if (Step(inbuf, cancellationToken) == MimeParserState.Error)
				{
					return BoundaryType.Eos;
				}
				ContentType contentType = GetContentType(multipart.ContentType);
				MimeEntity mimeEntity = options.CreateEntity(contentType, headers, toplevel: false);
				boundaryType = ((mimeEntity is Multipart) ? ConstructMultipart((Multipart)mimeEntity, inbuf, cancellationToken) : ((!(mimeEntity is MessagePart)) ? ConstructMimePart((MimePart)mimeEntity, inbuf, cancellationToken) : ConstructMessagePart((MessagePart)mimeEntity, inbuf, cancellationToken)));
				multipart.Add(mimeEntity);
			}
			while (boundaryType == BoundaryType.ImmediateBoundary);
			return boundaryType;
		}

		private void PushBoundary(string boundary)
		{
			if (bounds.Count > 0)
			{
				bounds.Insert(0, new Boundary(boundary, bounds[0].MaxLength));
			}
			else
			{
				bounds.Add(new Boundary(boundary, 0));
			}
		}

		private void PopBoundary()
		{
			bounds.RemoveAt(0);
		}

		private unsafe BoundaryType ConstructMultipart(Multipart multipart, byte* inbuf, CancellationToken cancellationToken)
		{
			string boundary = multipart.Boundary;
			if (boundary == null)
			{
				return MultipartScanPreamble(multipart, inbuf, cancellationToken);
			}
			PushBoundary(boundary);
			BoundaryType boundaryType = MultipartScanPreamble(multipart, inbuf, cancellationToken);
			if (boundaryType == BoundaryType.ImmediateBoundary)
			{
				boundaryType = MultipartScanSubparts(multipart, inbuf, cancellationToken);
			}
			if (boundaryType == BoundaryType.ImmediateEndBoundary)
			{
				multipart.WriteEndBoundary = true;
				SkipLine(inbuf, consumeNewLine: false, cancellationToken);
				PopBoundary();
				return MultipartScanEpilogue(multipart, inbuf, cancellationToken);
			}
			multipart.WriteEndBoundary = false;
			PopBoundary();
			if (boundaryType == BoundaryType.ParentEndBoundary && FoundImmediateBoundary(inbuf, final: true))
			{
				return BoundaryType.ImmediateEndBoundary;
			}
			if (boundaryType == BoundaryType.ParentBoundary && FoundImmediateBoundary(inbuf, final: false))
			{
				return BoundaryType.ImmediateBoundary;
			}
			return boundaryType;
		}

		private unsafe HeaderList ParseHeaders(byte* inbuf, CancellationToken cancellationToken)
		{
			state = MimeParserState.Headers;
			if (Step(inbuf, cancellationToken) == MimeParserState.Error)
			{
				throw new FormatException("Failed to parse headers.");
			}
			state = (eos ? MimeParserState.Eos : MimeParserState.Complete);
			HeaderList headerList = new HeaderList(options);
			foreach (Header header in headers)
			{
				headerList.Add(header);
			}
			return headerList;
		}

		public unsafe HeaderList ParseHeaders(CancellationToken cancellationToken = default(CancellationToken))
		{
			fixed (byte* inbuf = input)
			{
				return ParseHeaders(inbuf, cancellationToken);
			}
		}

		private unsafe MimeEntity ParseEntity(byte* inbuf, CancellationToken cancellationToken)
		{
			if (persistent && stream.Position != offset)
			{
				stream.Seek(offset, SeekOrigin.Begin);
			}
			state = MimeParserState.Headers;
			toplevel = true;
			if (Step(inbuf, cancellationToken) == MimeParserState.Error)
			{
				throw new FormatException("Failed to parse entity headers.");
			}
			ContentType contentType = GetContentType(null);
			MimeEntity mimeEntity = options.CreateEntity(contentType, headers, toplevel: false);
			BoundaryType boundaryType = ((mimeEntity is Multipart) ? ConstructMultipart((Multipart)mimeEntity, inbuf, cancellationToken) : ((!(mimeEntity is MessagePart)) ? ConstructMimePart((MimePart)mimeEntity, inbuf, cancellationToken) : ConstructMessagePart((MessagePart)mimeEntity, inbuf, cancellationToken)));
			if (boundaryType != BoundaryType.Eos)
			{
				state = MimeParserState.Complete;
			}
			else
			{
				state = MimeParserState.Eos;
			}
			return mimeEntity;
		}

		public unsafe MimeEntity ParseEntity(CancellationToken cancellationToken = default(CancellationToken))
		{
			fixed (byte* inbuf = input)
			{
				return ParseEntity(inbuf, cancellationToken);
			}
		}

		private unsafe MimeMessage ParseMessage(byte* inbuf, CancellationToken cancellationToken)
		{
			if (persistent && stream.Position != offset)
			{
				stream.Seek(offset, SeekOrigin.Begin);
			}
			while (state != MimeParserState.MessageHeaders)
			{
				switch (Step(inbuf, cancellationToken))
				{
				case MimeParserState.Error:
					throw new FormatException("Failed to find mbox From marker.");
				case MimeParserState.Eos:
					throw new FormatException("End of stream.");
				}
			}
			toplevel = true;
			if (state < MimeParserState.Content && Step(inbuf, cancellationToken) == MimeParserState.Error)
			{
				throw new FormatException("Failed to parse message headers.");
			}
			MimeMessage mimeMessage = new MimeMessage(options, headers, RfcComplianceMode.Loose);
			if (format == MimeFormat.Mbox && options.RespectContentLength)
			{
				contentEnd = 0L;
				for (int i = 0; i < headers.Count; i++)
				{
					if (headers[i].Id == HeaderId.ContentLength)
					{
						byte[] rawValue = headers[i].RawValue;
						int index = 0;
						if (ParseUtils.SkipWhiteSpace(rawValue, ref index, rawValue.Length) && ParseUtils.TryParseInt32(rawValue, ref index, rawValue.Length, out var value))
						{
							long num = GetOffset(inputIndex) + value;
							contentEnd = num;
							break;
						}
					}
				}
			}
			ContentType contentType = GetContentType(null);
			MimeEntity mimeEntity = (mimeMessage.Body = options.CreateEntity(contentType, headers, toplevel: true));
			BoundaryType boundaryType = ((mimeEntity is Multipart) ? ConstructMultipart((Multipart)mimeEntity, inbuf, cancellationToken) : ((!(mimeEntity is MessagePart)) ? ConstructMimePart((MimePart)mimeEntity, inbuf, cancellationToken) : ConstructMessagePart((MessagePart)mimeEntity, inbuf, cancellationToken)));
			if (boundaryType != BoundaryType.Eos)
			{
				if (format == MimeFormat.Mbox)
				{
					state = MimeParserState.MboxMarker;
				}
				else
				{
					state = MimeParserState.Complete;
				}
			}
			else
			{
				state = MimeParserState.Eos;
			}
			return mimeMessage;
		}

		public unsafe MimeMessage ParseMessage(CancellationToken cancellationToken = default(CancellationToken))
		{
			fixed (byte* inbuf = input)
			{
				return ParseMessage(inbuf, cancellationToken);
			}
		}

		public IEnumerator<MimeMessage> GetEnumerator()
		{
			while (!IsEndOfStream)
			{
				yield return ParseMessage();
			}
		}

		IEnumerator IEnumerable.GetEnumerator()
		{
			return GetEnumerator();
		}
	}
	public class AttachmentCollection : IList<MimeEntity>, ICollection<MimeEntity>, IEnumerable<MimeEntity>, IEnumerable
	{
		private readonly List<MimeEntity> attachments;

		private readonly bool linked;

		public int Count => attachments.Count;

		public bool IsReadOnly => false;

		public MimeEntity this[int index]
		{
			get
			{
				if (index < 0 || index >= Count)
				{
					throw new ArgumentOutOfRangeException("index");
				}
				return attachments[index];
			}
			set
			{
				if (index < 0 || index >= Count)
				{
					throw new ArgumentOutOfRangeException("index");
				}
				if (value == null)
				{
					throw new ArgumentNullException("value");
				}
				attachments[index] = value;
			}
		}

		public AttachmentCollection(bool linkedResources)
		{
			attachments = new List<MimeEntity>();
			linked = linkedResources;
		}

		public AttachmentCollection()
			: this(linkedResources: false)
		{
		}

		private static void LoadContent(MimePart attachment, Stream stream)
		{
			MemoryBlockStream memoryBlockStream = new MemoryBlockStream();
			BestEncodingFilter bestEncodingFilter = new BestEncodingFilter();
			byte[] array = new byte[4096];
			int num;
			int outputIndex;
			int outputLength;
			while ((num = stream.Read(array, 0, array.Length)) > 0)
			{
				bestEncodingFilter.Filter(array, 0, num, out outputIndex, out outputLength);
				memoryBlockStream.Write(array, 0, num);
			}
			bestEncodingFilter.Flush(array, 0, 0, out outputIndex, out outputLength);
			memoryBlockStream.Position = 0L;
			attachment.ContentTransferEncoding = bestEncodingFilter.GetBestEncoding(EncodingConstraint.SevenBit);
			attachment.Content = new MimeContent(memoryBlockStream);
		}

		private static ContentType GetMimeType(string fileName)
		{
			return ContentType.Parse(MimeTypes.GetMimeType(fileName));
		}

		private MimeEntity CreateAttachment(ContentType contentType, string fileName, Stream stream)
		{
			MimeEntity mimeEntity;
			if (contentType.IsMimeType("message", "rfc822"))
			{
				MimeMessage message = MimeMessage.Load(stream);
				MessagePart messagePart = new MessagePart();
				messagePart.Message = message;
				messagePart.ContentDisposition = new ContentDisposition(linked ? "inline" : "attachment");
				messagePart.ContentDisposition.FileName = Path.GetFileName(fileName);
				messagePart.ContentType.Name = Path.GetFileName(fileName);
				mimeEntity = messagePart;
			}
			else
			{
				MimePart mimePart = ((!contentType.IsMimeType("text", "*")) ? new MimePart(contentType) : new TextPart(contentType));
				mimePart.FileName = Path.GetFileName(fileName);
				mimePart.IsAttachment = !linked;
				LoadContent(mimePart, stream);
				mimeEntity = mimePart;
			}
			if (linked)
			{
				mimeEntity.ContentLocation = new Uri(Path.GetFileName(fileName), UriKind.Relative);
			}
			return mimeEntity;
		}

		public MimeEntity Add(string fileName, byte[] data, ContentType contentType)
		{
			if (fileName == null)
			{
				throw new ArgumentNullException("fileName");
			}
			if (fileName.Length == 0)
			{
				throw new ArgumentException("The specified file path is empty.", "fileName");
			}
			if (data == null)
			{
				throw new ArgumentNullException("data");
			}
			if (contentType == null)
			{
				throw new ArgumentNullException("contentType");
			}
			using MemoryStream stream = new MemoryStream(data, writable: false);
			MimeEntity mimeEntity = CreateAttachment(contentType, fileName, stream);
			attachments.Add(mimeEntity);
			return mimeEntity;
		}

		public MimeEntity Add(string fileName, Stream stream, ContentType contentType)
		{
			if (fileName == null)
			{
				throw new ArgumentNullException("fileName");
			}
			if (fileName.Length == 0)
			{
				throw new ArgumentException("The specified file path is empty.", "fileName");
			}
			if (stream == null)
			{
				throw new ArgumentNullException("stream");
			}
			if (!stream.CanRead)
			{
				throw new ArgumentException("The stream cannot be read.", "stream");
			}
			if (contentType == null)
			{
				throw new ArgumentNullException("contentType");
			}
			MimeEntity mimeEntity = CreateAttachment(contentType, fileName, stream);
			attachments.Add(mimeEntity);
			return mimeEntity;
		}

		public MimeEntity Add(string fileName, byte[] data)
		{
			if (fileName == null)
			{
				throw new ArgumentNullException("fileName");
			}
			if (fileName.Length == 0)
			{
				throw new ArgumentException("The specified file path is empty.", "fileName");
			}
			if (data == null)
			{
				throw new ArgumentNullException("data");
			}
			using MemoryStream stream = new MemoryStream(data, writable: false);
			MimeEntity mimeEntity = CreateAttachment(GetMimeType(fileName), fileName, stream);
			attachments.Add(mimeEntity);
			return mimeEntity;
		}

		public MimeEntity Add(string fileName, Stream stream)
		{
			if (fileName == null)
			{
				throw new ArgumentNullException("fileName");
			}
			if (fileName.Length == 0)
			{
				throw new ArgumentException("The specified file path is empty.", "fileName");
			}
			if (stream == null)
			{
				throw new ArgumentNullException("stream");
			}
			if (!stream.CanRead)
			{
				throw new ArgumentException("The stream cannot be read.", "stream");
			}
			MimeEntity mimeEntity = CreateAttachment(GetMimeType(fileName), fileName, stream);
			attachments.Add(mimeEntity);
			return mimeEntity;
		}

		public MimeEntity Add(string fileName, ContentType contentType)
		{
			if (fileName == null)
			{
				throw new ArgumentNullException("fileName");
			}
			if (fileName.Length == 0)
			{
				throw new ArgumentException("The specified file path is empty.", "fileName");
			}
			if (contentType == null)
			{
				throw new ArgumentNullException("contentType");
			}
			using FileStream stream = File.OpenRead(fileName);
			MimeEntity mimeEntity = CreateAttachment(contentType, fileName, stream);
			attachments.Add(mimeEntity);
			return mimeEntity;
		}

		public MimeEntity Add(string fileName)
		{
			if (fileName == null)
			{
				throw new ArgumentNullException("fileName");
			}
			if (fileName.Length == 0)
			{
				throw new ArgumentException("The specified file path is empty.", "fileName");
			}
			using FileStream stream = File.OpenRead(fileName);
			MimeEntity mimeEntity = CreateAttachment(GetMimeType(fileName), fileName, stream);
			attachments.Add(mimeEntity);
			return mimeEntity;
		}

		public void Add(MimeEntity attachment)
		{
			if (attachment == null)
			{
				throw new ArgumentNullException("attachment");
			}
			attachments.Add(attachment);
		}

		public void Clear()
		{
			attachments.Clear();
		}

		public bool Contains(MimeEntity attachment)
		{
			if (attachment == null)
			{
				throw new ArgumentNullException("attachment");
			}
			return attachments.Contains(attachment);
		}

		public void CopyTo(MimeEntity[] array, int arrayIndex)
		{
			if (array == null)
			{
				throw new ArgumentNullException("array");
			}
			if (arrayIndex < 0 || arrayIndex >= array.Length)
			{
				throw new ArgumentOutOfRangeException("arrayIndex");
			}
			attachments.CopyTo(array, arrayIndex);
		}

		public int IndexOf(MimeEntity attachment)
		{
			if (attachment == null)
			{
				throw new ArgumentNullException("attachment");
			}
			return attachments.IndexOf(attachment);
		}

		public void Insert(int index, MimeEntity attachment)
		{
			if (index < 0 || index >= Count)
			{
				throw new ArgumentOutOfRangeException("index");
			}
			if (attachment == null)
			{
				throw new ArgumentNullException("attachment");
			}
			attachments.Insert(index, attachment);
		}

		public bool Remove(MimeEntity attachment)
		{
			if (attachment == null)
			{
				throw new ArgumentNullException("attachment");
			}
			return attachments.Remove(attachment);
		}

		public void RemoveAt(int index)
		{
			if (index < 0 || index >= Count)
			{
				throw new ArgumentOutOfRangeException("index");
			}
			attachments.RemoveAt(index);
		}

		public IEnumerator<MimeEntity> GetEnumerator()
		{
			return attachments.GetEnumerator();
		}

		IEnumerator IEnumerable.GetEnumerator()
		{
			return GetEnumerator();
		}
	}
	public class BodyBuilder
	{
		public AttachmentCollection Attachments { get; private set; }

		public AttachmentCollection LinkedResources { get; private set; }

		public string TextBody { get; set; }

		public string HtmlBody { get; set; }

		public BodyBuilder()
		{
			LinkedResources = new AttachmentCollection(linkedResources: true);
			Attachments = new AttachmentCollection();
		}

		public MimeEntity ToMessageBody()
		{
			MultipartAlternative multipartAlternative = null;
			MimeEntity mimeEntity = null;
			if (TextBody != null)
			{
				TextPart textPart = new TextPart("plain");
				textPart.Text = TextBody;
				if (!string.IsNullOrEmpty(HtmlBody))
				{
					multipartAlternative = new MultipartAlternative();
					multipartAlternative.Add(textPart);
					mimeEntity = multipartAlternative;
				}
				else
				{
					mimeEntity = textPart;
				}
			}
			if (HtmlBody != null)
			{
				TextPart textPart2 = new TextPart("html");
				textPart2.ContentId = MimeUtils.GenerateMessageId();
				textPart2.Text = HtmlBody;
				MimeEntity mimeEntity2;
				if (LinkedResources.Count > 0)
				{
					MultipartRelated multipartRelated = new MultipartRelated
					{
						Root = textPart2
					};
					foreach (MimeEntity linkedResource in LinkedResources)
					{
						multipartRelated.Add(linkedResource);
					}
					mimeEntity2 = multipartRelated;
				}
				else
				{
					mimeEntity2 = textPart2;
				}
				if (multipartAlternative != null)
				{
					multipartAlternative.Add(mimeEntity2);
				}
				else
				{
					mimeEntity = mimeEntity2;
				}
			}
			if (Attachments.Count > 0)
			{
				if (mimeEntity == null && Attachments.Count == 1)
				{
					return Attachments[0];
				}
				Multipart multipart = new Multipart("mixed");
				if (mimeEntity != null)
				{
					multipart.Add(mimeEntity);
				}
				foreach (MimeEntity attachment in Attachments)
				{
					multipart.Add(attachment);
				}
				mimeEntity = multipart;
			}
			return mimeEntity ?? new TextPart("plain")
			{
				Text = string.Empty
			};
		}
	}
	public class ContentDisposition
	{
		public const string Attachment = "attachment";

		public const string FormData = "form-data";

		public const string Inline = "inline";

		private ParameterList parameters;

		private string disposition;

		public string Disposition
		{
			get
			{
				return disposition;
			}
			set
			{
				if (value == null)
				{
					throw new ArgumentNullException("value");
				}
				if (value.Length == 0)
				{
					throw new ArgumentException("The disposition is not allowed to be empty.", "value");
				}
				for (int i = 0; i < value.Length; i++)
				{
					if (value[i] >= '\u007f' || !IsAsciiAtom((byte)value[i]))
					{
						throw new ArgumentException("Illegal characters in disposition value.", "value");
					}
				}
				if (!(disposition == value))
				{
					disposition = value;
					OnChanged();
				}
			}
		}

		public bool IsAttachment
		{
			get
			{
				return disposition.Equals("attachment", StringComparison.OrdinalIgnoreCase);
			}
			set
			{
				disposition = (value ? "attachment" : "inline");
			}
		}

		public ParameterList Parameters
		{
			get
			{
				return parameters;
			}
			private set
			{
				if (parameters != null)
				{
					parameters.Changed -= OnParametersChanged;
				}
				value.Changed += OnParametersChanged;
				parameters = value;
			}
		}

		public string FileName
		{
			get
			{
				return Parameters["filename"];
			}
			set
			{
				if (value != null)
				{
					Parameters["filename"] = value;
				}
				else
				{
					Parameters.Remove("filename");
				}
			}
		}

		public DateTimeOffset? CreationDate
		{
			get
			{
				string text = Parameters["creation-date"];
				if (IsNullOrWhiteSpace(text))
				{
					return null;
				}
				byte[] bytes = Encoding.UTF8.GetBytes(text);
				if (!DateUtils.TryParse(bytes, 0, bytes.Length, out var date))
				{
					return null;
				}
				return date;
			}
			set
			{
				if (value.HasValue)
				{
					Parameters["creation-date"] = DateUtils.FormatDate(value.Value);
				}
				else
				{
					Parameters.Remove("creation-date");
				}
			}
		}

		public DateTimeOffset? ModificationDate
		{
			get
			{
				string text = Parameters["modification-date"];
				if (IsNullOrWhiteSpace(text))
				{
					return null;
				}
				byte[] bytes = Encoding.UTF8.GetBytes(text);
				if (!DateUtils.TryParse(bytes, 0, bytes.Length, out var date))
				{
					return null;
				}
				return date;
			}
			set
			{
				if (value.HasValue)
				{
					Parameters["modification-date"] = DateUtils.FormatDate(value.Value);
				}
				else
				{
					Parameters.Remove("modification-date");
				}
			}
		}

		public DateTimeOffset? ReadDate
		{
			get
			{
				string text = Parameters["read-date"];
				if (IsNullOrWhiteSpace(text))
				{
					return null;
				}
				byte[] bytes = Encoding.UTF8.GetBytes(text);
				if (!DateUtils.TryParse(bytes, 0, bytes.Length, out var date))
				{
					return null;
				}
				return date;
			}
			set
			{
				if (value.HasValue)
				{
					Parameters["read-date"] = DateUtils.FormatDate(value.Value);
				}
				else
				{
					Parameters.Remove("read-date");
				}
			}
		}

		public long? Size
		{
			get
			{
				string text = Parameters["size"];
				if (IsNullOrWhiteSpace(text))
				{
					return null;
				}
				if (!long.TryParse(text, out var result))
				{
