		internal static bool TryParse(ParserOptions options, byte[] text, ref int index, int endIndex, bool throwOnError, out ContentDisposition disposition)
		{
			disposition = null;
			if (!ParseUtils.SkipCommentsAndWhiteSpace(text, ref index, endIndex, throwOnError))
			{
				return false;
			}
			if (index >= endIndex)
			{
				if (throwOnError)
				{
					throw new ParseException($"Expected atom token at position {index}", index, index);
				}
				return false;
			}
			int num = index;
			string text2;
			if (text[index] == 34)
			{
				if (throwOnError)
				{
					throw new ParseException($"Unxpected qstring token at position {num}", num, index);
				}
				if (!ParseUtils.SkipQuoted(text, ref index, endIndex, throwOnError))
				{
					return false;
				}
				text2 = CharsetUtils.ConvertToUnicode(options, text, num, index - num);
				text2 = MimeUtils.Unquote(text2);
				if (string.IsNullOrEmpty(text2))
				{
					text2 = "attachment";
				}
			}
			else if (!ParseUtils.SkipAtom(text, ref index, endIndex))
			{
				if (throwOnError)
				{
					throw new ParseException($"Invalid atom token at position {num}", num, index);
				}
				if (index > num || text[index] != 59)
				{
					return false;
				}
				text2 = "attachment";
			}
			else
			{
				text2 = Encoding.ASCII.GetString(text, num, index - num);
			}
			disposition = new ContentDisposition();
			disposition.disposition = text2;
			if (!ParseUtils.SkipCommentsAndWhiteSpace(text, ref index, endIndex, throwOnError))
			{
				return false;
			}
			if (index >= endIndex)
			{
				return true;
			}
			if (text[index] != 59)
			{
				if (throwOnError)
				{
					throw new ParseException($"Expected ';' at position {index}", index, index);
				}
				return false;
			}
			index++;
			if (!ParseUtils.SkipCommentsAndWhiteSpace(text, ref index, endIndex, throwOnError))
			{
				return false;
			}
			if (index >= endIndex)
			{
				return true;
			}
			if (!ParameterList.TryParse(options, text, ref index, endIndex, throwOnError, out var paramList))
			{
				return false;
			}
			disposition.Parameters = paramList;
			return true;
		}

