	public class FormatOptions
	{
		private static readonly byte[][] NewLineFormats;

		internal const int MaximumLineLength = 998;

		internal const int MinimumLineLength = 60;

		private const int DefaultMaxLineLength = 78;

		private ParameterEncodingMethod parameterEncodingMethod;

		private bool allowMixedHeaderCharsets;

		private NewLineFormat newLineFormat;

		private bool ensureNewLine;

		private bool international;

		private int maxLineLength;

		public static readonly FormatOptions Default;

		public int MaxLineLength
		{
			get
			{
				return maxLineLength;
			}
			set
			{
				if (this == Default)
				{
					throw new InvalidOperationException("The default formatting options cannot be changed.");
				}
				if (value < 60 || value > 998)
				{
					throw new ArgumentOutOfRangeException("value");
				}
				maxLineLength = value;
			}
		}

		public NewLineFormat NewLineFormat
		{
			get
			{
				return newLineFormat;
			}
			set
			{
				if (this == Default)
				{
					throw new InvalidOperationException("The default formatting options cannot be changed.");
				}
				newLineFormat = value;
			}
		}

		public bool EnsureNewLine
		{
			get
			{
				return ensureNewLine;
			}
			set
			{
				if (this == Default)
				{
					throw new InvalidOperationException("The default formatting options cannot be changed.");
				}
				ensureNewLine = value;
			}
		}

		internal string NewLine
		{
			get
			{
				if (NewLineFormat != NewLineFormat.Unix)
				{
					return "\r\n";
				}
				return "\n";
			}
		}

		internal byte[] NewLineBytes => NewLineFormats[(uint)NewLineFormat];

		public HashSet<HeaderId> HiddenHeaders { get; private set; }

		public bool International
		{
			get
			{
				return international;
			}
			set
			{
				if (this == Default)
				{
					throw new InvalidOperationException("The default formatting options cannot be changed.");
				}
				international = value;
			}
		}

		public bool AllowMixedHeaderCharsets
		{
			get
			{
				return allowMixedHeaderCharsets;
			}
			set
			{
				if (this == Default)
				{
					throw new InvalidOperationException("The default formatting options cannot be changed.");
				}
				allowMixedHeaderCharsets = value;
			}
		}

		public ParameterEncodingMethod ParameterEncodingMethod
		{
			get
			{
				return parameterEncodingMethod;
			}
			set
			{
				if (this == Default)
				{
					throw new InvalidOperationException("The default formatting options cannot be changed.");
				}
				if ((uint)(value - 1) <= 1u)
				{
					parameterEncodingMethod = value;
					return;
				}
				throw new ArgumentOutOfRangeException("value");
			}
		}

		internal IMimeFilter CreateNewLineFilter(bool ensureNewLine = false)
		{
			if (NewLineFormat == NewLineFormat.Unix)
			{
				return new Dos2UnixFilter(ensureNewLine);
			}
			return new Unix2DosFilter(ensureNewLine);
		}

		static FormatOptions()
		{
			NewLineFormats = new byte[2][]
			{
				new byte[1] { 10 },
				new byte[2] { 13, 10 }
			};
			Default = new FormatOptions();
		}

		public FormatOptions()
		{
			HiddenHeaders = new HashSet<HeaderId>();
			parameterEncodingMethod = ParameterEncodingMethod.Rfc2231;
			maxLineLength = 78;
			allowMixedHeaderCharsets = false;
			ensureNewLine = false;
			international = false;
			if (Environment.NewLine.Length == 1)
			{
				newLineFormat = NewLineFormat.Unix;
			}
			else
			{
				newLineFormat = NewLineFormat.Dos;
			}
		}

		public FormatOptions Clone()
		{
			return new FormatOptions
			{
				maxLineLength = maxLineLength,
				newLineFormat = newLineFormat,
				ensureNewLine = ensureNewLine,
				HiddenHeaders = new HashSet<HeaderId>(HiddenHeaders),
				allowMixedHeaderCharsets = allowMixedHeaderCharsets,
				parameterEncodingMethod = parameterEncodingMethod,
				international = international
			};
		}

		internal static FormatOptions CloneDefault()
		{
			lock (Default)
			{
				return Default.Clone();
			}
		}
	}
	public class GroupAddress : InternetAddress
	{
		public InternetAddressList Members { get; private set; }

		public GroupAddress(Encoding encoding, string name, IEnumerable<InternetAddress> addresses)
			: base(encoding, name)
		{
			Members = new InternetAddressList(addresses);
			Members.Changed += MembersChanged;
		}

		public GroupAddress(string name, IEnumerable<InternetAddress> addresses)
			: this(Encoding.UTF8, name, addresses)
		{
		}

		public GroupAddress(Encoding encoding, string name)
			: base(encoding, name)
		{
			Members = new InternetAddressList();
			Members.Changed += MembersChanged;
		}

		public GroupAddress(string name)
			: this(Encoding.UTF8, name)
		{
		}

		public override InternetAddress Clone()
		{
			return new GroupAddress(base.Encoding, base.Name, Members.Select((InternetAddress x) => x.Clone()));
		}

		internal override void Encode(FormatOptions options, StringBuilder builder, bool firstToken, ref int lineLength)
		{
			if (!string.IsNullOrEmpty(base.Name))
			{
				string text;
				if (!options.International)
				{
					byte[] array = Rfc2047.EncodePhrase(options, base.Encoding, base.Name);
					text = Encoding.ASCII.GetString(array, 0, array.Length);
				}
				else
				{
					text = InternetAddress.EncodeInternationalizedPhrase(base.Name);
				}
				if (lineLength + text.Length > options.MaxLineLength)
				{
					if (text.Length > options.MaxLineLength)
					{
						builder.AppendFolded(options, firstToken, text, ref lineLength);
					}
					else
					{
						if (!firstToken && lineLength > 1)
						{
							builder.LineWrap(options);
							lineLength = 1;
						}
						lineLength += text.Length;
						builder.Append(text);
					}
				}
				else
				{
					lineLength += text.Length;
					builder.Append(text);
				}
			}
			builder.Append(": ");
			lineLength += 2;
			Members.Encode(options, builder, firstToken: false, ref lineLength);
			builder.Append(';');
			lineLength++;
		}

		public override string ToString(FormatOptions options, bool encode)
		{
			if (options == null)
			{
				throw new ArgumentNullException("options");
			}
			StringBuilder stringBuilder = new StringBuilder();
			if (encode)
			{
				int lineLength = 0;
				Encode(options, stringBuilder, firstToken: true, ref lineLength);
			}
			else
			{
				stringBuilder.Append(base.Name);
				stringBuilder.Append(':');
				stringBuilder.Append(' ');
				for (int i = 0; i < Members.Count; i++)
				{
					if (i > 0)
					{
						stringBuilder.Append(", ");
					}
					stringBuilder.Append(Members[i]);
				}
				stringBuilder.Append(';');
			}
			return stringBuilder.ToString();
		}

		public override bool Equals(InternetAddress other)
		{
			if (!(other is GroupAddress groupAddress))
			{
				return false;
			}
			if (base.Name == groupAddress.Name)
			{
				return Members.Equals(groupAddress.Members);
			}
			return false;
		}

		private void MembersChanged(object sender, EventArgs e)
		{
			OnChanged();
		}

		private static bool TryParse(ParserOptions options, byte[] text, ref int index, int endIndex, bool throwOnError, out GroupAddress group)
		{
			AddressParserFlags addressParserFlags = AddressParserFlags.AllowGroupAddress;
			if (throwOnError)
			{
				addressParserFlags |= AddressParserFlags.ThrowOnError;
			}
			if (!InternetAddress.TryParse(options, text, ref index, endIndex, 0, addressParserFlags, out var address))
			{
				group = null;
				return false;
			}
			group = (GroupAddress)address;
			return true;
		}

		public static bool TryParse(ParserOptions options, byte[] buffer, int startIndex, int length, out GroupAddress group)
		{
			ParseUtils.ValidateArguments(options, buffer, startIndex, length);
			int num = startIndex + length;
			int index = startIndex;
			if (!TryParse(options, buffer, ref index, num, throwOnError: false, out group))
			{
				return false;
			}
			if (!ParseUtils.SkipCommentsAndWhiteSpace(buffer, ref index, num, throwOnError: false) || index != num)
			{
				group = null;
				return false;
			}
			return true;
		}

