			{
				if (index < 0 || index >= Count)
				{
					throw new ArgumentOutOfRangeException("index");
				}
				if (value == null)
				{
					throw new ArgumentNullException("value");
				}
				if (groups[index] != value)
				{
					groups[index].Changed -= OnGroupChanged;
					value.Changed += OnGroupChanged;
					groups[index] = value;
