	public class MailboxAddress : InternetAddress
	{
		private string address;

		private int at;

		public DomainList Route { get; private set; }

		public string Address
		{
			get
			{
				return address;
			}
			set
			{
				if (value == null)
				{
					throw new ArgumentNullException("value");
				}
				if (value == address)
				{
					return;
				}
				if (value.Length > 0)
				{
					byte[] bytes = CharsetUtils.UTF8.GetBytes(value);
					int index = 0;
					InternetAddress.TryParseAddrspec(bytes, ref index, bytes.Length, new byte[0], throwOnError: true, out var addrspec, out var num);
					if (index != bytes.Length)
					{
						throw new ParseException($"Unexpected token at offset {index}", index, index);
					}
					address = addrspec;
					at = num;
				}
				else
				{
					address = string.Empty;
					at = -1;
				}
				OnChanged();
			}
		}

		public bool IsInternational
		{
			get
			{
				if (address == null)
				{
					return false;
				}
				if (ParseUtils.IsInternational(address))
				{
					return true;
				}
				foreach (string item in Route)
				{
					if (ParseUtils.IsInternational(item))
					{
						return true;
					}
				}
				return false;
			}
		}

