	public class MimeContent : IMimeContent
	{
		public ContentEncoding Encoding { get; private set; }

		public Stream Stream { get; private set; }

		public MimeContent(Stream stream, ContentEncoding encoding = ContentEncoding.Default)
		{
			if (stream == null)
			{
				throw new ArgumentNullException("stream");
			}
			if (!stream.CanRead)
			{
				throw new ArgumentException("The stream does not support reading.", "stream");
			}
			if (!stream.CanSeek)
			{
				throw new ArgumentException("The stream does not support seeking.", "stream");
			}
			Encoding = encoding;
			Stream = stream;
		}

		public Stream Open()
		{
			Stream.Seek(0L, SeekOrigin.Begin);
			FilteredStream filteredStream = new FilteredStream(Stream);
			filteredStream.Add(DecoderFilter.Create(Encoding));
			return filteredStream;
		}

		public void WriteTo(Stream stream, CancellationToken cancellationToken = default(CancellationToken))
		{
			if (stream == null)
			{
				throw new ArgumentNullException("stream");
			}
			ICancellableStream cancellableStream = Stream as ICancellableStream;
			ICancellableStream cancellableStream2 = stream as ICancellableStream;
			byte[] array = new byte[4096];
			Stream.Seek(0L, SeekOrigin.Begin);
			try
			{
				while (true)
				{
					int count;
					if (cancellableStream != null)
					{
						if ((count = cancellableStream.Read(array, 0, array.Length, cancellationToken)) <= 0)
						{
							break;
						}
					}
					else
					{
						cancellationToken.ThrowIfCancellationRequested();
						if ((count = Stream.Read(array, 0, array.Length)) <= 0)
						{
							break;
						}
					}
					if (cancellableStream2 != null)
					{
						cancellableStream2.Write(array, 0, count, cancellationToken);
						continue;
					}
					cancellationToken.ThrowIfCancellationRequested();
					stream.Write(array, 0, count);
				}
				Stream.Seek(0L, SeekOrigin.Begin);
			}
			catch (OperationCanceledException)
			{
				try
				{
					Stream.Seek(0L, SeekOrigin.Begin);
				}
				catch (IOException)
				{
				}
				throw;
			}
		}

		public async Task WriteToAsync(Stream stream, CancellationToken cancellationToken = default(CancellationToken))
		{
			if (stream == null)
			{
				throw new ArgumentNullException("stream");
			}
			byte[] buf = new byte[4096];
			Stream.Seek(0L, SeekOrigin.Begin);
			try
			{
				int count;
				while ((count = await Stream.ReadAsync(buf, 0, buf.Length, cancellationToken).ConfigureAwait(continueOnCapturedContext: false)) > 0)
				{
					await stream.WriteAsync(buf, 0, count, cancellationToken).ConfigureAwait(continueOnCapturedContext: false);
				}
				Stream.Seek(0L, SeekOrigin.Begin);
			}
			catch (OperationCanceledException)
			{
				try
				{
					Stream.Seek(0L, SeekOrigin.Begin);
				}
				catch (IOException)
				{
				}
				throw;
			}
		}

		public void DecodeTo(Stream stream, CancellationToken cancellationToken = default(CancellationToken))
		{
			if (stream == null)
			{
				throw new ArgumentNullException("stream");
			}
			using FilteredStream filteredStream = new FilteredStream(stream);
			filteredStream.Add(DecoderFilter.Create(Encoding));
			WriteTo(filteredStream, cancellationToken);
			filteredStream.Flush(cancellationToken);
		}

		public async Task DecodeToAsync(Stream stream, CancellationToken cancellationToken = default(CancellationToken))
		{
			if (stream == null)
			{
				throw new ArgumentNullException("stream");
			}
			using FilteredStream filtered = new FilteredStream(stream);
			filtered.Add(DecoderFilter.Create(Encoding));
			await WriteToAsync(filtered, cancellationToken).ConfigureAwait(continueOnCapturedContext: false);
			await filtered.FlushAsync(cancellationToken).ConfigureAwait(continueOnCapturedContext: false);
		}
	}
	public abstract class MimeEntity
	{
		internal bool EnsureNewLine;

		private ContentDisposition disposition;

		private string contentId;

		private Uri location;

		private Uri baseUri;

		public HeaderList Headers { get; private set; }

		public ContentDisposition ContentDisposition
		{
			get
			{
				return disposition;
			}
			set
			{
				if (disposition != value)
				{
					if (disposition != null)
					{
						disposition.Changed -= ContentDispositionChanged;
						RemoveHeader("Content-Disposition");
					}
					disposition = value;
					if (disposition != null)
					{
						disposition.Changed += ContentDispositionChanged;
						SerializeContentDisposition();
					}
				}
			}
		}

		public ContentType ContentType { get; private set; }

		public Uri ContentBase
		{
			get
			{
				return baseUri;
			}
			set
			{
				if (!(baseUri == value))
				{
					if (value != null && !value.IsAbsoluteUri)
					{
						throw new ArgumentException("The Content-Base URI may only be set to an absolute URI.", "value");
					}
					baseUri = value;
					if (value != null)
					{
						SetHeader("Content-Base", value.ToString());
					}
					else
					{
						RemoveHeader("Content-Base");
					}
				}
			}
		}

		public Uri ContentLocation
		{
			get
			{
				return location;
			}
			set
			{
				if (!(location == value))
				{
					location = value;
					if (value != null)
					{
						SetHeader("Content-Location", value.ToString());
					}
					else
					{
						RemoveHeader("Content-Location");
					}
				}
			}
		}

		public string ContentId
		{
			get
			{
				return contentId;
			}
			set
			{
				if (contentId == value)
				{
					return;
				}
				if (value == null)
				{
					RemoveHeader("Content-Id");
					contentId = null;
					return;
				}
				byte[] bytes = Encoding.UTF8.GetBytes(value);
				int index = 0;
				if (!MailboxAddress.TryParse(Headers.Options, bytes, ref index, bytes.Length, throwOnError: false, out var mailbox))
				{
					throw new ArgumentException("Invalid Content-Id format.", "value");
				}
				contentId = mailbox.Address;
				SetHeader("Content-Id", "<" + contentId + ">");
			}
		}

		public bool IsAttachment
		{
			get
			{
				if (ContentDisposition != null)
				{
					return ContentDisposition.IsAttachment;
				}
				return false;
			}
			set
			{
				if (value)
				{
					if (ContentDisposition == null)
					{
						ContentDisposition = new ContentDisposition("attachment");
					}
					else if (!ContentDisposition.IsAttachment)
					{
						ContentDisposition.Disposition = "attachment";
					}
				}
				else if (ContentDisposition != null && ContentDisposition.IsAttachment)
				{
					ContentDisposition.Disposition = "inline";
				}
			}
		}

		protected MimeEntity(MimeEntityConstructorArgs args)
		{
			if (args == null)
			{
				throw new ArgumentNullException("args");
			}
			Headers = new HeaderList(args.ParserOptions);
			ContentType = args.ContentType;
			ContentType.Changed += ContentTypeChanged;
			Headers.Changed += HeadersChanged;
			foreach (Header header in args.Headers)
			{
				if (!args.IsTopLevel || header.Field.StartsWith("Content-", StringComparison.OrdinalIgnoreCase))
				{
					Headers.Add(header);
				}
			}
		}

		protected MimeEntity(string mediaType, string mediaSubtype)
			: this(new ContentType(mediaType, mediaSubtype))
		{
		}

		protected MimeEntity(ContentType contentType)
		{
			if (contentType == null)
			{
				throw new ArgumentNullException("contentType");
			}
			Headers = new HeaderList();
			ContentType = contentType;
			ContentType.Changed += ContentTypeChanged;
			Headers.Changed += HeadersChanged;
			SerializeContentType();
		}

		protected bool TryInit(object obj)
		{
			if (obj is Header header)
			{
				Headers.Add(header);
				return true;
			}
			if (obj is IEnumerable<Header> enumerable)
			{
				foreach (Header item in enumerable)
				{
					Headers.Add(item);
				}
				return true;
			}
			return false;
		}

		public override string ToString()
		{
			using MemoryStream memoryStream = new MemoryStream();
			WriteTo(memoryStream);
			byte[] buffer = memoryStream.GetBuffer();
			int count = (int)memoryStream.Length;
			return CharsetUtils.Latin1.GetString(buffer, 0, count);
		}

		public virtual void Accept(MimeVisitor visitor)
		{
			if (visitor == null)
			{
				throw new ArgumentNullException("visitor");
			}
			visitor.VisitMimeEntity(this);
		}

