		private MailboxAddress GetMessageSigner()
		{
			if (ResentSender != null)
			{
				return ResentSender;
			}
			if (ResentFrom.Count > 0)
			{
				return ResentFrom.Mailboxes.FirstOrDefault();
			}
			if (Sender != null)
			{
				return Sender;
			}
			if (From.Count > 0)
			{
				return From.Mailboxes.FirstOrDefault();
			}
			return null;
		}

		private IList<MailboxAddress> GetMessageRecipients(bool includeSenders)
		{
			HashSet<MailboxAddress> hashSet = new HashSet<MailboxAddress>();
			if (ResentSender != null || ResentFrom.Count > 0)
			{
				if (includeSenders)
				{
					if (ResentSender != null)
					{
						hashSet.Add(ResentSender);
					}
					if (ResentFrom.Count > 0)
					{
						foreach (MailboxAddress mailbox in ResentFrom.Mailboxes)
						{
							hashSet.Add(mailbox);
						}
					}
				}
				foreach (MailboxAddress mailbox2 in ResentTo.Mailboxes)
				{
					hashSet.Add(mailbox2);
				}
				foreach (MailboxAddress mailbox3 in ResentCc.Mailboxes)
				{
					hashSet.Add(mailbox3);
				}
				foreach (MailboxAddress mailbox4 in ResentBcc.Mailboxes)
				{
					hashSet.Add(mailbox4);
				}
			}
			else
			{
				if (includeSenders)
				{
					if (Sender != null)
					{
						hashSet.Add(Sender);
					}
					if (From.Count > 0)
					{
						foreach (MailboxAddress mailbox5 in From.Mailboxes)
						{
							hashSet.Add(mailbox5);
						}
					}
				}
				foreach (MailboxAddress mailbox6 in To.Mailboxes)
				{
					hashSet.Add(mailbox6);
				}
				foreach (MailboxAddress mailbox7 in Cc.Mailboxes)
				{
					hashSet.Add(mailbox7);
				}
				foreach (MailboxAddress mailbox8 in Bcc.Mailboxes)
				{
					hashSet.Add(mailbox8);
				}
			}
			return hashSet.ToList();
		}

		private static void DkimWriteHeaderRelaxed(FormatOptions options, Stream stream, Header header, bool isDkimSignature)
		{
			byte[] bytes = Encoding.ASCII.GetBytes(header.Field.ToLowerInvariant());
			byte[] rawValue = header.GetRawValue(options);
			int i = 0;
			stream.Write(bytes, 0, bytes.Length);
			stream.WriteByte(58);
			for (; i < rawValue.Length && rawValue[i].IsWhitespace(); i++)
			{
			}
			while (i < rawValue.Length)
			{
				int num = i;
				for (; i < rawValue.Length && rawValue[i].IsWhitespace(); i++)
				{
				}
				if (i >= rawValue.Length)
				{
					break;
				}
				if (i > num)
				{
					stream.WriteByte(32);
				}
				num = i;
				for (; i < rawValue.Length && !rawValue[i].IsWhitespace(); i++)
				{
				}
				if (i > num)
				{
					stream.Write(rawValue, num, i - num);
				}
			}
			if (!isDkimSignature)
			{
				stream.Write(options.NewLineBytes, 0, options.NewLineBytes.Length);
			}
		}

		private static void DkimWriteHeaderSimple(FormatOptions options, Stream stream, Header header, bool isDkimSignature)
		{
			byte[] rawValue = header.GetRawValue(options);
			int num = rawValue.Length;
			if (isDkimSignature && num > 0 && rawValue[num - 1] == 10)
			{
				num--;
				if (num > 0 && rawValue[num - 1] == 13)
				{
					num--;
				}
			}
			stream.Write(header.RawField, 0, header.RawField.Length);
			stream.Write(Header.Colon, 0, Header.Colon.Length);
			stream.Write(rawValue, 0, num);
		}

		private static ISigner DkimGetDigestSigner(DkimSignatureAlgorithm algorithm, AsymmetricKeyParameter key)
		{
			DerObjectIdentifier id = ((algorithm != DkimSignatureAlgorithm.RsaSha256) ? PkcsObjectIdentifiers.Sha1WithRsaEncryption : PkcsObjectIdentifiers.Sha256WithRsaEncryption);
			ISigner signer = SignerUtilities.GetSigner(id);
			signer.Init(key.IsPrivate, key);
			return signer;
		}

		private byte[] DkimHashBody(FormatOptions options, DkimSignatureAlgorithm signatureAlgorithm, DkimCanonicalizationAlgorithm bodyCanonicalizationAlgorithm, int maxLength)
		{
			using DkimHashStream dkimHashStream = new DkimHashStream(signatureAlgorithm, maxLength);
			using (FilteredStream filteredStream = new FilteredStream(dkimHashStream))
			{
				DkimBodyFilter dkimBodyFilter = ((bodyCanonicalizationAlgorithm != DkimCanonicalizationAlgorithm.Relaxed) ? ((DkimBodyFilter)new DkimSimpleBodyFilter()) : ((DkimBodyFilter)new DkimRelaxedBodyFilter()));
				filteredStream.Add(options.CreateNewLineFilter());
				filteredStream.Add(dkimBodyFilter);
				if (Body != null)
				{
					try
					{
						Body.EnsureNewLine = compliance == RfcComplianceMode.Strict || options.EnsureNewLine;
						Body.WriteTo(options, filteredStream, contentOnly: true, CancellationToken.None);
					}
					finally
					{
						Body.EnsureNewLine = false;
					}
				}
				filteredStream.Flush();
				if (!dkimBodyFilter.LastWasNewLine)
				{
					dkimHashStream.Write(options.NewLineBytes, 0, options.NewLineBytes.Length);
				}
			}
			return dkimHashStream.GenerateHash();
		}

		private void DkimWriteHeaders(FormatOptions options, IList<string> fields, DkimCanonicalizationAlgorithm headerCanonicalizationAlgorithm, Stream stream)
		{
			Dictionary<string, int> dictionary = new Dictionary<string, int>(StringComparer.Ordinal);
			for (int i = 0; i < fields.Count; i++)
			{
				HeaderList headerList = (fields[i].StartsWith("Content-", StringComparison.OrdinalIgnoreCase) ? Body.Headers : Headers);
				string text = fields[i].ToLowerInvariant();
				int num = 0;
				if (!dictionary.TryGetValue(text, out var value))
				{
					value = 0;
				}
				int num2 = headerList.LastIndexOf(text);
				while (num < value && --num2 >= 0)
				{
					if (headerList[num2].Field.Equals(text, StringComparison.OrdinalIgnoreCase))
					{
						num++;
					}
				}
				if (num2 >= 0)
				{
					Header header = headerList[num2];
					if (headerCanonicalizationAlgorithm == DkimCanonicalizationAlgorithm.Relaxed)
					{
						DkimWriteHeaderRelaxed(options, stream, header, isDkimSignature: false);
					}
					else
					{
						DkimWriteHeaderSimple(options, stream, header, isDkimSignature: false);
					}
					value = (dictionary[text] = value + 1);
				}
			}
		}

		private void DkimSign(FormatOptions options, DkimSigner signer, IList<string> fields, DkimCanonicalizationAlgorithm headerCanonicalizationAlgorithm, DkimCanonicalizationAlgorithm bodyCanonicalizationAlgorithm)
		{
			if (version == null && Body != null && Body.Headers.Count > 0)
			{
				MimeVersion = new Version(1, 0);
			}
			TimeSpan timeSpan = DateTime.UtcNow - DateUtils.UnixEpoch;
			StringBuilder stringBuilder = new StringBuilder("v=1");
			options = options.Clone();
			options.NewLineFormat = NewLineFormat.Dos;
			DkimSignatureAlgorithm signatureAlgorithm = signer.SignatureAlgorithm;
			if (signatureAlgorithm == DkimSignatureAlgorithm.RsaSha256)
			{
				stringBuilder.Append("; a=rsa-sha256");
			}
			else
			{
				stringBuilder.Append("; a=rsa-sha1");
			}
			stringBuilder.AppendFormat("; d={0}; s={1}", signer.Domain, signer.Selector);
			stringBuilder.AppendFormat("; c={0}/{1}", headerCanonicalizationAlgorithm.ToString().ToLowerInvariant(), bodyCanonicalizationAlgorithm.ToString().ToLowerInvariant());
			if (!string.IsNullOrEmpty(signer.QueryMethod))
			{
				stringBuilder.AppendFormat("; q={0}", signer.QueryMethod);
			}
			if (!string.IsNullOrEmpty(signer.AgentOrUserIdentifier))
			{
				stringBuilder.AppendFormat("; i={0}", signer.AgentOrUserIdentifier);
			}
			stringBuilder.AppendFormat("; t={0}", (long)timeSpan.TotalSeconds);
			using DkimSignatureStream dkimSignatureStream = new DkimSignatureStream(signer.DigestSigner);
			Header header;
			using (FilteredStream filteredStream = new FilteredStream(dkimSignatureStream))
			{
				filteredStream.Add(options.CreateNewLineFilter());
				DkimWriteHeaders(options, fields, headerCanonicalizationAlgorithm, filteredStream);
				stringBuilder.AppendFormat("; h={0}", string.Join(":", fields.ToArray()));
				byte[] inArray = DkimHashBody(options, signer.SignatureAlgorithm, bodyCanonicalizationAlgorithm, -1);
				stringBuilder.AppendFormat("; bh={0}", Convert.ToBase64String(inArray));
				stringBuilder.Append("; b=");
				header = new Header(HeaderId.DkimSignature, stringBuilder.ToString());
				Headers.Insert(0, header);
				if (headerCanonicalizationAlgorithm == DkimCanonicalizationAlgorithm.Relaxed)
				{
					DkimWriteHeaderRelaxed(options, filteredStream, header, isDkimSignature: true);
				}
				else
				{
					DkimWriteHeaderSimple(options, filteredStream, header, isDkimSignature: true);
				}
				filteredStream.Flush();
			}
			byte[] inArray2 = dkimSignatureStream.GenerateSignature();
			header.Value += Convert.ToBase64String(inArray2);
		}

		public void Sign(FormatOptions options, DkimSigner signer, IList<string> headers, DkimCanonicalizationAlgorithm headerCanonicalizationAlgorithm = DkimCanonicalizationAlgorithm.Simple, DkimCanonicalizationAlgorithm bodyCanonicalizationAlgorithm = DkimCanonicalizationAlgorithm.Simple)
		{
			if (options == null)
			{
				throw new ArgumentNullException("options");
			}
			if (signer == null)
			{
				throw new ArgumentNullException("signer");
			}
			if (headers == null)
			{
				throw new ArgumentNullException("headers");
			}
			string[] array = new string[headers.Count];
			bool flag = false;
			for (int i = 0; i < headers.Count; i++)
			{
				if (headers[i] == null)
				{
					throw new ArgumentException("The list of headers cannot contain null.", "headers");
				}
				if (headers[i].Length == 0)
				{
					throw new ArgumentException("The list of headers cannot contain empty string.", "headers");
				}
				array[i] = headers[i].ToLowerInvariant();
				if (DkimShouldNotInclude.Contains(array[i]))
				{
					throw new ArgumentException($"The list of headers to sign SHOULD NOT include the '{headers[i]}' header.", "headers");
				}
				if (array[i] == "from")
				{
					flag = true;
				}
			}
			if (!flag)
			{
				throw new ArgumentException("The list of headers to sign MUST include the 'From' header.", "headers");
			}
			DkimSign(options, signer, array, headerCanonicalizationAlgorithm, bodyCanonicalizationAlgorithm);
		}

		public void Sign(DkimSigner signer, IList<string> headers, DkimCanonicalizationAlgorithm headerCanonicalizationAlgorithm = DkimCanonicalizationAlgorithm.Simple, DkimCanonicalizationAlgorithm bodyCanonicalizationAlgorithm = DkimCanonicalizationAlgorithm.Simple)
		{
			Sign(FormatOptions.Default, signer, headers, headerCanonicalizationAlgorithm, bodyCanonicalizationAlgorithm);
		}

		public void Sign(FormatOptions options, DkimSigner signer, IList<HeaderId> headers, DkimCanonicalizationAlgorithm headerCanonicalizationAlgorithm = DkimCanonicalizationAlgorithm.Simple, DkimCanonicalizationAlgorithm bodyCanonicalizationAlgorithm = DkimCanonicalizationAlgorithm.Simple)
		{
			if (options == null)
			{
				throw new ArgumentNullException("options");
			}
			if (signer == null)
			{
				throw new ArgumentNullException("signer");
			}
			if (headers == null)
			{
				throw new ArgumentNullException("headers");
			}
			string[] array = new string[headers.Count];
			bool flag = false;
			for (int i = 0; i < headers.Count; i++)
			{
				if (headers[i] == HeaderId.Unknown)
				{
					throw new ArgumentException("The list of headers to sign cannot include the 'Unknown' header.", "headers");
				}
				array[i] = headers[i].ToHeaderName().ToLowerInvariant();
				if (DkimShouldNotInclude.Contains(array[i]))
				{
					throw new ArgumentException($"The list of headers to sign SHOULD NOT include the '{headers[i].ToHeaderName()}' header.", "headers");
				}
				if (headers[i] == HeaderId.From)
				{
					flag = true;
				}
			}
			if (!flag)
			{
				throw new ArgumentException("The list of headers to sign MUST include the 'From' header.", "headers");
			}
			DkimSign(options, signer, array, headerCanonicalizationAlgorithm, bodyCanonicalizationAlgorithm);
		}

		public void Sign(DkimSigner signer, IList<HeaderId> headers, DkimCanonicalizationAlgorithm headerCanonicalizationAlgorithm = DkimCanonicalizationAlgorithm.Simple, DkimCanonicalizationAlgorithm bodyCanonicalizationAlgorithm = DkimCanonicalizationAlgorithm.Simple)
		{
			Sign(FormatOptions.Default, signer, headers, headerCanonicalizationAlgorithm, bodyCanonicalizationAlgorithm);
		}

		private static bool IsWhiteSpace(char c)
		{
			if (c != ' ')
			{
				return c == '\t';
			}
			return true;
		}

		private static IDictionary<string, string> ParseDkimSignature(string signature)
		{
			Dictionary<string, string> dictionary = new Dictionary<string, string>(MimeUtils.OrdinalIgnoreCase);
			string[] array = signature.Split(';');
			foreach (string text in array)
			{
				StringBuilder stringBuilder = new StringBuilder();
				int j;
				for (j = 0; j < text.Length && IsWhiteSpace(text[j]); j++)
				{
				}
				int num = j;
				for (; j < text.Length && text[j] != '='; j++)
				{
				}
				if (j + 1 >= text.Length)
				{
					continue;
				}
				string text2 = text.Substring(num, j - num).Trim();
				for (j++; j < text.Length; j++)
				{
					if (!IsWhiteSpace(text[j]))
					{
						stringBuilder.Append(text[j]);
					}
				}
				if (dictionary.ContainsKey(text2))
				{
					throw new FormatException($"Malformed DKIM-Signature value: duplicate parameter '{text2}'.");
				}
				dictionary.Add(text2, stringBuilder.ToString());
			}
			return dictionary;
		}

		private static void ValidateDkimSignatureParameters(IDictionary<string, string> parameters, out DkimSignatureAlgorithm algorithm, out DkimCanonicalizationAlgorithm headerAlgorithm, out DkimCanonicalizationAlgorithm bodyAlgorithm, out string d, out string s, out string q, out string[] headers, out string bh, out string b, out int maxLength)
		{
			bool flag = false;
			if (!parameters.TryGetValue("v", out var value))
			{
				throw new FormatException("Malformed DKIM-Signature header: no version parameter detected.");
			}
			if (value != "1")
			{
				throw new FormatException($"Unrecognized DKIM-Signature version: v={value}");
			}
			if (!parameters.TryGetValue("a", out var value2))
			{
				throw new FormatException("Malformed DKIM-Signature header: no signature algorithm parameter detected.");
			}
			string text = value2.ToLowerInvariant();
			if (!(text == "rsa-sha256"))
			{
				if (!(text == "rsa-sha1"))
				{
					throw new FormatException($"Unrecognized DKIM-Signature algorithm parameter: a={value2}");
				}
				algorithm = DkimSignatureAlgorithm.RsaSha1;
			}
			else
			{
				algorithm = DkimSignatureAlgorithm.RsaSha256;
			}
			if (!parameters.TryGetValue("d", out d))
			{
				throw new FormatException("Malformed DKIM-Signature header: no domain parameter detected.");
			}
			if (parameters.TryGetValue("i", out var value3))
			{
				int num;
				if ((num = value3.LastIndexOf('@')) == -1)
				{
					throw new FormatException("Malformed DKIM-Signature header: no @ in the AUID value.");
				}
				string text2 = value3.Substring(num + 1);
				if (!text2.Equals(d, StringComparison.OrdinalIgnoreCase) && !text2.EndsWith("." + d, StringComparison.OrdinalIgnoreCase))
				{
					throw new FormatException("Invalid DKIM-Signature header: the domain in the AUID does not match the domain parameter.");
				}
			}
			if (!parameters.TryGetValue("s", out s))
			{
				throw new FormatException("Malformed DKIM-Signature header: no selector parameter detected.");
			}
			if (!parameters.TryGetValue("q", out q))
			{
				q = "dns/txt";
			}
			if (parameters.TryGetValue("l", out var value4))
			{
				if (!int.TryParse(value4, out maxLength))
				{
					throw new FormatException($"Malformed DKIM-Signature header: invalid length parameter: l={value4}");
				}
			}
			else
			{
				maxLength = -1;
			}
			if (parameters.TryGetValue("c", out var value5))
			{
				string[] array = value5.ToLowerInvariant().Split('/');
				if (array.Length == 0 || array.Length > 2)
				{
					throw new FormatException($"Malformed DKIM-Signature header: invalid canonicalization parameter: c={value5}");
				}
				text = array[0];
				if (!(text == "relaxed"))
				{
					if (!(text == "simple"))
					{
						throw new FormatException($"Malformed DKIM-Signature header: invalid canonicalization parameter: c={value5}");
					}
					headerAlgorithm = DkimCanonicalizationAlgorithm.Simple;
				}
				else
				{
					headerAlgorithm = DkimCanonicalizationAlgorithm.Relaxed;
				}
				if (array.Length == 2)
				{
					text = array[1];
					if (!(text == "relaxed"))
					{
						if (!(text == "simple"))
						{
							throw new FormatException($"Malformed DKIM-Signature header: invalid canonicalization parameter: c={value5}");
						}
						bodyAlgorithm = DkimCanonicalizationAlgorithm.Simple;
					}
					else
					{
						bodyAlgorithm = DkimCanonicalizationAlgorithm.Relaxed;
					}
				}
				else
				{
					bodyAlgorithm = DkimCanonicalizationAlgorithm.Simple;
				}
			}
			else
			{
				headerAlgorithm = DkimCanonicalizationAlgorithm.Simple;
				bodyAlgorithm = DkimCanonicalizationAlgorithm.Simple;
			}
			if (!parameters.TryGetValue("h", out var value6))
			{
				throw new FormatException("Malformed DKIM-Signature header: no signed header parameter detected.");
			}
			headers = value6.Split(':');
			for (int i = 0; i < headers.Length; i++)
			{
				if (headers[i].Equals("from", StringComparison.OrdinalIgnoreCase))
				{
					flag = true;
					break;
				}
			}
			if (!flag)
			{
				throw new FormatException($"Malformed DKIM-Signature header: From header not signed.");
			}
			if (!parameters.TryGetValue("bh", out bh))
			{
				throw new FormatException("Malformed DKIM-Signature header: no body hash parameter detected.");
			}
			if (!parameters.TryGetValue("b", out b))
			{
				throw new FormatException("Malformed DKIM-Signature header: no signature parameter detected.");
			}
		}

		private static Header GetSignedDkimSignatureHeader(Header dkimSignature)
		{
			byte[] array = (byte[])dkimSignature.RawValue.Clone();
			int newSize = 0;
			int i = 0;
			while (true)
			{
				if (i < array.Length && array[i].IsWhitespace())
				{
					i++;
					continue;
				}
				if (i + 2 < array.Length)
				{
					char c = (char)array[i++];
					for (; i < array.Length && array[i].IsWhitespace(); i++)
					{
					}
					if (i < array.Length && array[i] == 61 && c == 'b')
					{
						newSize = ++i;
						for (; i < array.Length && array[i] != 59; i++)
						{
						}
						if (i == array.Length && array[i - 1] == 10)
						{
							i--;
							if (array[i - 1] == 13)
							{
								i--;
							}
						}
						break;
					}
				}
				for (; i < array.Length && array[i] != 59; i++)
				{
				}
				if (i < array.Length)
				{
					i++;
				}
				if (i >= array.Length)
				{
					break;
				}
			}
			if (i == array.Length)
			{
				throw new FormatException("Malformed DKIM-Signature header: missing signature parameter.");
			}
			while (i < array.Length)
			{
				array[newSize++] = array[i++];
			}
			Array.Resize(ref array, newSize);
			return new Header(dkimSignature.Options, dkimSignature.RawField, array);
		}

		private async Task<bool> VerifyAsync(FormatOptions options, Header dkimSignature, IDkimPublicKeyLocator publicKeyLocator, bool doAsync, CancellationToken cancellationToken)
		{
			if (options == null)
			{
				throw new ArgumentNullException("options");
			}
			if (dkimSignature == null)
			{
				throw new ArgumentNullException("dkimSignature");
			}
			if (dkimSignature.Id != HeaderId.DkimSignature)
			{
				throw new ArgumentException("The dkimSignature parameter MUST be a DKIM-Signature header.", "dkimSignature");
			}
			if (publicKeyLocator == null)
			{
				throw new ArgumentNullException("publicKeyLocator");
			}
			ValidateDkimSignatureParameters(ParseDkimSignature(dkimSignature.Value), out var signatureAlgorithm, out var headerAlgorithm, out var bodyAlgorithm, out var d, out var s, out var q, out var headers, out var bh, out var b, out var maxLength);
			AsymmetricKeyParameter key = ((!doAsync) ? publicKeyLocator.LocatePublicKey(q, d, s, cancellationToken) : (await publicKeyLocator.LocatePublicKeyAsync(q, d, s, cancellationToken).ConfigureAwait(continueOnCapturedContext: false)));
			options = options.Clone();
			options.NewLineFormat = NewLineFormat.Dos;
			if (Convert.ToBase64String(DkimHashBody(options, signatureAlgorithm, bodyAlgorithm, maxLength)) != bh)
			{
				return false;
			}
			using DkimSignatureStream dkimSignatureStream = new DkimSignatureStream(DkimGetDigestSigner(signatureAlgorithm, key));
			using (FilteredStream filteredStream = new FilteredStream(dkimSignatureStream))
			{
				filteredStream.Add(options.CreateNewLineFilter());
				DkimWriteHeaders(options, headers, headerAlgorithm, filteredStream);
				Header signedDkimSignatureHeader = GetSignedDkimSignatureHeader(dkimSignature);
				if (headerAlgorithm == DkimCanonicalizationAlgorithm.Relaxed)
				{
					DkimWriteHeaderRelaxed(options, filteredStream, signedDkimSignatureHeader, isDkimSignature: true);
				}
				else
				{
					DkimWriteHeaderSimple(options, filteredStream, signedDkimSignatureHeader, isDkimSignature: true);
				}
				filteredStream.Flush();
			}
			return dkimSignatureStream.VerifySignature(b);
		}

		public bool Verify(FormatOptions options, Header dkimSignature, IDkimPublicKeyLocator publicKeyLocator, CancellationToken cancellationToken = default(CancellationToken))
		{
			return VerifyAsync(options, dkimSignature, publicKeyLocator, doAsync: false, cancellationToken).GetAwaiter().GetResult();
		}

		public Task<bool> VerifyAsync(FormatOptions options, Header dkimSignature, IDkimPublicKeyLocator publicKeyLocator, CancellationToken cancellationToken = default(CancellationToken))
		{
			return VerifyAsync(options, dkimSignature, publicKeyLocator, doAsync: true, cancellationToken);
		}

		public bool Verify(Header dkimSignature, IDkimPublicKeyLocator publicKeyLocator, CancellationToken cancellationToken = default(CancellationToken))
		{
			return Verify(FormatOptions.Default, dkimSignature, publicKeyLocator, cancellationToken);
		}

		public Task<bool> VerifyAsync(Header dkimSignature, IDkimPublicKeyLocator publicKeyLocator, CancellationToken cancellationToken = default(CancellationToken))
		{
			return VerifyAsync(FormatOptions.Default, dkimSignature, publicKeyLocator, cancellationToken);
		}

		public void Sign(CryptographyContext ctx, DigestAlgorithm digestAlgo)
		{
			if (ctx == null)
			{
				throw new ArgumentNullException("ctx");
			}
			if (Body == null)
			{
				throw new InvalidOperationException("No message body has been set.");
			}
			MailboxAddress messageSigner = GetMessageSigner();
			if (messageSigner == null)
			{
				throw new InvalidOperationException("The sender has not been set.");
			}
			Body = MultipartSigned.Create(ctx, messageSigner, digestAlgo, Body);
		}

		public void Sign(CryptographyContext ctx)
		{
			Sign(ctx, DigestAlgorithm.Sha1);
		}

		public void Encrypt(CryptographyContext ctx)
		{
			if (ctx == null)
			{
				throw new ArgumentNullException("ctx");
			}
			if (Body == null)
			{
				throw new InvalidOperationException("No message body has been set.");
			}
			IList<MailboxAddress> messageRecipients = GetMessageRecipients(includeSenders: true);
			if (messageRecipients.Count == 0)
			{
				throw new InvalidOperationException("No recipients have been set.");
			}
			if (ctx is SecureMimeContext)
			{
				Body = ApplicationPkcs7Mime.Encrypt((SecureMimeContext)ctx, messageRecipients, Body);
				return;
			}
			if (ctx is OpenPgpContext)
			{
				Body = MultipartEncrypted.Encrypt((OpenPgpContext)ctx, messageRecipients, Body);
				return;
			}
			throw new ArgumentException("Unknown type of cryptography context.", "ctx");
		}

		public void SignAndEncrypt(CryptographyContext ctx, DigestAlgorithm digestAlgo)
		{
			if (ctx == null)
			{
				throw new ArgumentNullException("ctx");
			}
			if (Body == null)
			{
				throw new InvalidOperationException("No message body has been set.");
			}
			MailboxAddress messageSigner = GetMessageSigner();
			if (messageSigner == null)
			{
				throw new InvalidOperationException("The sender has not been set.");
			}
			IList<MailboxAddress> messageRecipients = GetMessageRecipients(includeSenders: true);
			if (ctx is SecureMimeContext)
			{
				Body = ApplicationPkcs7Mime.SignAndEncrypt((SecureMimeContext)ctx, messageSigner, digestAlgo, messageRecipients, Body);
				return;
			}
			if (ctx is OpenPgpContext)
			{
				Body = MultipartEncrypted.SignAndEncrypt((OpenPgpContext)ctx, messageSigner, digestAlgo, messageRecipients, Body);
				return;
			}
			throw new ArgumentException("Unknown type of cryptography context.", "ctx");
		}

		public void SignAndEncrypt(CryptographyContext ctx)
		{
			SignAndEncrypt(ctx, DigestAlgorithm.Sha1);
		}

		private IEnumerable<Header> MergeHeaders()
		{
			int mesgIndex = 0;
			int bodyIndex = 0;
			while (mesgIndex < Headers.Count && bodyIndex < Body.Headers.Count)
			{
				Header header = Body.Headers[bodyIndex];
				if (!header.Offset.HasValue)
				{
					break;
				}
				Header header2 = Headers[mesgIndex];
				if (header2.Offset.HasValue && header2.Offset < header.Offset)
				{
					yield return header2;
					mesgIndex++;
				}
				else
				{
					yield return header;
					bodyIndex++;
				}
			}
			while (mesgIndex < Headers.Count)
			{
				yield return Headers[mesgIndex++];
			}
			while (bodyIndex < Body.Headers.Count)
			{
				yield return Body.Headers[bodyIndex++];
			}
		}

		private void RemoveHeader(HeaderId id)
		{
			Headers.Changed -= HeadersChanged;
			try
			{
				Headers.RemoveAll(id);
			}
			finally
			{
				Headers.Changed += HeadersChanged;
			}
		}

		private void ReplaceHeader(HeaderId id, string name, byte[] raw)
		{
			Headers.Changed -= HeadersChanged;
			try
			{
				Headers.Replace(new Header(Headers.Options, id, name, raw));
			}
			finally
			{
				Headers.Changed += HeadersChanged;
			}
		}

		private void SetHeader(string name, string value)
		{
			Headers.Changed -= HeadersChanged;
			try
			{
				Headers[name] = value;
			}
			finally
			{
				Headers.Changed += HeadersChanged;
			}
		}

		private void SerializeAddressList(string field, InternetAddressList list)
		{
			if (list.Count == 0)
			{
				RemoveHeader(field.ToHeaderId());
				return;
			}
			StringBuilder stringBuilder = new StringBuilder(" ");
			FormatOptions formatOptions = FormatOptions.Default;
			int lineLength = field.Length + 2;
			list.Encode(formatOptions, stringBuilder, firstToken: true, ref lineLength);
			stringBuilder.Append(formatOptions.NewLine);
			byte[] bytes = Encoding.UTF8.GetBytes(stringBuilder.ToString());
			ReplaceHeader(field.ToHeaderId(), field, bytes);
		}

		private void InternetAddressListChanged(object addrlist, EventArgs e)
		{
			InternetAddressList internetAddressList = (InternetAddressList)addrlist;
			string[] standardAddressHeaders = StandardAddressHeaders;
			foreach (string text in standardAddressHeaders)
			{
				if (addresses[text] == internetAddressList)
				{
					SerializeAddressList(text, internetAddressList);
					break;
				}
			}
		}

		private void ReferencesChanged(object o, EventArgs e)
		{
			if (references.Count > 0)
			{
				int num = "References".Length + 1;
				FormatOptions formatOptions = FormatOptions.Default;
				StringBuilder stringBuilder = new StringBuilder();
				for (int i = 0; i < references.Count; i++)
				{
					if (i > 0 && num + references[i].Length + 2 >= formatOptions.MaxLineLength)
					{
						stringBuilder.Append(formatOptions.NewLine);
						stringBuilder.Append('\t');
						num = 1;
					}
					else
					{
						stringBuilder.Append(' ');
						num++;
					}
					num += references[i].Length;
					stringBuilder.Append("<" + references[i] + ">");
				}
				stringBuilder.Append(formatOptions.NewLine);
				byte[] bytes = Encoding.UTF8.GetBytes(stringBuilder.ToString());
				ReplaceHeader(HeaderId.References, "References", bytes);
			}
			else
			{
				RemoveHeader(HeaderId.References);
			}
		}

		private void AddAddresses(Header header, InternetAddressList list)
		{
			int endIndex = header.RawValue.Length;
			int index = 0;
			if (InternetAddressList.TryParse(Headers.Options, header.RawValue, ref index, endIndex, isGroup: false, 0, throwOnError: false, out var list2))
			{
				list.Changed -= InternetAddressListChanged;
				list.AddRange(list2);
				list.Changed += InternetAddressListChanged;
			}
		}

		private void ReloadAddressList(HeaderId id, InternetAddressList list)
		{
			list.Changed -= InternetAddressListChanged;
			list.Clear();
			foreach (Header header in Headers)
			{
				if (header.Id == id)
				{
					int endIndex = header.RawValue.Length;
					int index = 0;
					if (InternetAddressList.TryParse(Headers.Options, header.RawValue, ref index, endIndex, isGroup: false, 0, throwOnError: false, out var list2))
					{
						list.AddRange(list2);
					}
				}
			}
			list.Changed += InternetAddressListChanged;
		}

		private void ReloadHeader(HeaderId id)
		{
			switch (id)
			{
			case HeaderId.Unknown:
				return;
			case HeaderId.ResentMessageId:
				resentMessageId = null;
				break;
			case HeaderId.ResentSender:
				resentSender = null;
				break;
			case HeaderId.ResentDate:
				resentDate = DateTimeOffset.MinValue;
				break;
			case HeaderId.References:
				references.Changed -= ReferencesChanged;
				references.Clear();
				references.Changed += ReferencesChanged;
				break;
			case HeaderId.InReplyTo:
				inreplyto = null;
				break;
			case HeaderId.MessageId:
				messageId = null;
				break;
			case HeaderId.Sender:
				sender = null;
				break;
			case HeaderId.Importance:
				importance = MessageImportance.Normal;
				break;
			case HeaderId.XPriority:
				xpriority = XMessagePriority.Normal;
				break;
			case HeaderId.Priority:
				priority = MessagePriority.Normal;
				break;
			case HeaderId.Date:
				date = DateTimeOffset.MinValue;
				break;
			}
			foreach (Header header in Headers)
			{
				if (header.Id != id)
				{
					continue;
				}
				byte[] rawValue = header.RawValue;
				int index = 0;
				switch (id)
				{
				case HeaderId.MimeVersion:
					MimeUtils.TryParse(rawValue, 0, rawValue.Length, out version);
					break;
				case HeaderId.References:
					references.Changed -= ReferencesChanged;
					foreach (string item in MimeUtils.EnumerateReferences(rawValue, 0, rawValue.Length))
					{
						references.Add(item);
					}
					references.Changed += ReferencesChanged;
					break;
				case HeaderId.InReplyTo:
					inreplyto = MimeUtils.EnumerateReferences(rawValue, 0, rawValue.Length).FirstOrDefault();
					break;
				case HeaderId.ResentMessageId:
					resentMessageId = MimeUtils.ParseMessageId(rawValue, 0, rawValue.Length);
					break;
				case HeaderId.MessageId:
					messageId = MimeUtils.ParseMessageId(rawValue, 0, rawValue.Length);
					break;
				case HeaderId.ResentSender:
					MailboxAddress.TryParse(Headers.Options, rawValue, ref index, rawValue.Length, throwOnError: false, out resentSender);
					break;
				case HeaderId.Sender:
					MailboxAddress.TryParse(Headers.Options, rawValue, ref index, rawValue.Length, throwOnError: false, out sender);
					break;
				case HeaderId.ResentDate:
					DateUtils.TryParse(rawValue, 0, rawValue.Length, out resentDate);
					break;
				case HeaderId.Importance:
				{
					string text = header.Value.ToLowerInvariant().Trim();
					if (!(text == "high"))
					{
						if (text == "low")
						{
							importance = MessageImportance.Low;
						}
						else
						{
							importance = MessageImportance.Normal;
						}
					}
					else
					{
						importance = MessageImportance.High;
					}
					break;
				}
				case HeaderId.Priority:
				{
					string text = header.Value.ToLowerInvariant().Trim();
					if (!(text == "non-urgent"))
					{
						if (text == "urgent")
						{
							priority = MessagePriority.Urgent;
						}
						else
						{
							priority = MessagePriority.Normal;
						}
					}
					else
					{
						priority = MessagePriority.NonUrgent;
					}
					break;
				}
				case HeaderId.XPriority:
				{
					ParseUtils.SkipWhiteSpace(rawValue, ref index, rawValue.Length);
					if (ParseUtils.TryParseInt32(rawValue, ref index, rawValue.Length, out var value))
					{
						xpriority = (XMessagePriority)Math.Min(Math.Max(value, 1), 5);
					}
					else
					{
						xpriority = XMessagePriority.Normal;
					}
					break;
				}
				case HeaderId.Date:
					DateUtils.TryParse(rawValue, 0, rawValue.Length, out date);
					break;
				}
			}
		}

		private void HeadersChanged(object o, HeaderListChangedEventArgs e)
		{
			int index = 0;
			InternetAddressList value;
			switch (e.Action)
			{
			case HeaderListChangedAction.Added:
			{
				if (addresses.TryGetValue(e.Header.Field, out value))
				{
					AddAddresses(e.Header, value);
					break;
				}
				byte[] rawValue = e.Header.RawValue;
				switch (e.Header.Id)
				{
				case HeaderId.MimeVersion:
					MimeUtils.TryParse(rawValue, 0, rawValue.Length, out version);
					break;
				case HeaderId.References:
					references.Changed -= ReferencesChanged;
					foreach (string item in MimeUtils.EnumerateReferences(rawValue, 0, rawValue.Length))
					{
						references.Add(item);
					}
					references.Changed += ReferencesChanged;
					break;
				case HeaderId.InReplyTo:
					inreplyto = MimeUtils.EnumerateReferences(rawValue, 0, rawValue.Length).FirstOrDefault();
					break;
				case HeaderId.ResentMessageId:
					resentMessageId = MimeUtils.ParseMessageId(rawValue, 0, rawValue.Length);
					break;
				case HeaderId.MessageId:
					messageId = MimeUtils.ParseMessageId(rawValue, 0, rawValue.Length);
					break;
				case HeaderId.ResentSender:
					MailboxAddress.TryParse(Headers.Options, rawValue, ref index, rawValue.Length, throwOnError: false, out resentSender);
					break;
				case HeaderId.Sender:
					MailboxAddress.TryParse(Headers.Options, rawValue, ref index, rawValue.Length, throwOnError: false, out sender);
					break;
				case HeaderId.ResentDate:
					DateUtils.TryParse(rawValue, 0, rawValue.Length, out resentDate);
					break;
				case HeaderId.Importance:
				{
					string text = e.Header.Value.ToLowerInvariant().Trim();
					if (!(text == "high"))
					{
						if (text == "low")
						{
							importance = MessageImportance.Low;
						}
						else
						{
							importance = MessageImportance.Normal;
						}
					}
					else
					{
						importance = MessageImportance.High;
					}
					break;
				}
				case HeaderId.Priority:
				{
					string text = e.Header.Value.ToLowerInvariant().Trim();
					if (!(text == "non-urgent"))
					{
						if (text == "urgent")
						{
							priority = MessagePriority.Urgent;
						}
						else
						{
							priority = MessagePriority.Normal;
						}
					}
					else
					{
						priority = MessagePriority.NonUrgent;
					}
					break;
				}
				case HeaderId.XPriority:
				{
					ParseUtils.SkipWhiteSpace(rawValue, ref index, rawValue.Length);
					if (ParseUtils.TryParseInt32(rawValue, ref index, rawValue.Length, out var value2))
					{
						xpriority = (XMessagePriority)Math.Min(Math.Max(value2, 1), 5);
					}
					else
					{
						xpriority = XMessagePriority.Normal;
					}
					break;
				}
				case HeaderId.Date:
					DateUtils.TryParse(rawValue, 0, rawValue.Length, out date);
					break;
				}
				break;
			}
			case HeaderListChangedAction.Changed:
			case HeaderListChangedAction.Removed:
				if (addresses.TryGetValue(e.Header.Field, out value))
				{
					ReloadAddressList(e.Header.Id, value);
				}
				else
				{
					ReloadHeader(e.Header.Id);
				}
				break;
			case HeaderListChangedAction.Cleared:
				foreach (KeyValuePair<string, InternetAddressList> address in addresses)
				{
					address.Value.Changed -= InternetAddressListChanged;
					address.Value.Clear();
					address.Value.Changed += InternetAddressListChanged;
				}
				references.Changed -= ReferencesChanged;
				references.Clear();
				references.Changed += ReferencesChanged;
				resentDate = (date = DateTimeOffset.MinValue);
				importance = MessageImportance.Normal;
				xpriority = XMessagePriority.Normal;
				priority = MessagePriority.Normal;
				resentMessageId = null;
				resentSender = null;
				inreplyto = null;
				messageId = null;
				version = null;
				sender = null;
				break;
			default:
				throw new ArgumentOutOfRangeException();
			}
		}

