			if (fileName == null)
			{
				throw new ArgumentNullException("fileName");
			}
			using FileStream stream = File.OpenRead(fileName);
			return await LoadAsync(options, stream, cancellationToken).ConfigureAwait(continueOnCapturedContext: false);
		}

