			: base(ContentType.Parse(contentType))
		{
		}

		public MimePart()
			: this("application", "octet-stream")
		{
		}

		public override void Accept(MimeVisitor visitor)
		{
			if (visitor == null)
			{
				throw new ArgumentNullException("visitor");
			}
			visitor.VisitMimePart(this);
