		public int MaxAddressGroupDepth { get; set; }

		public RfcComplianceMode ParameterComplianceMode { get; set; }

		public RfcComplianceMode Rfc2047ComplianceMode { get; set; }

		public bool RespectContentLength { get; set; }

		public Encoding CharsetEncoding { get; set; }

		public ParserOptions()
		{
			AddressParserComplianceMode = RfcComplianceMode.Loose;
			ParameterComplianceMode = RfcComplianceMode.Loose;
			Rfc2047ComplianceMode = RfcComplianceMode.Loose;
			CharsetEncoding = CharsetUtils.UTF8;
			AllowUnquotedCommasInAddresses = true;
			AllowAddressesWithoutDomain = true;
			RespectContentLength = false;
			MaxAddressGroupDepth = 3;
		}

		public ParserOptions Clone()
		{
			ParserOptions parserOptions = new ParserOptions();
			parserOptions.AddressParserComplianceMode = AddressParserComplianceMode;
			parserOptions.AllowUnquotedCommasInAddresses = AllowUnquotedCommasInAddresses;
			parserOptions.AllowAddressesWithoutDomain = AllowAddressesWithoutDomain;
			parserOptions.ParameterComplianceMode = ParameterComplianceMode;
			parserOptions.Rfc2047ComplianceMode = Rfc2047ComplianceMode;
			parserOptions.MaxAddressGroupDepth = MaxAddressGroupDepth;
			parserOptions.RespectContentLength = RespectContentLength;
			parserOptions.CharsetEncoding = CharsetEncoding;
			foreach (KeyValuePair<string, ConstructorInfo> mimeType in mimeTypes)
			{
				parserOptions.mimeTypes.Add(mimeType.Key, mimeType.Value);
			}
			return parserOptions;
		}

		public void RegisterMimeType(string mimeType, Type type)
		{
			if (mimeType == null)
			{
				throw new ArgumentNullException("mimeType");
			}
			if (type == null)
			{
				throw new ArgumentNullException("type");
			}
			mimeType = mimeType.ToLowerInvariant();
			if (!type.IsSubclassOf(typeof(MessagePart)) && !type.IsSubclassOf(typeof(Multipart)) && !type.IsSubclassOf(typeof(MimePart)))
			{
				throw new ArgumentException("The specified type must be a subclass of MessagePart, Multipart, or MimePart.", "type");
			}
			ConstructorInfo constructor = type.GetConstructor(ConstructorArgTypes);
			if (constructor == null)
			{
				throw new ArgumentException("The specified type must have a constructor that takes a MimeEntityConstructorArgs argument.", "type");
			}
			mimeTypes[mimeType] = constructor;
		}

		private static bool IsEncoded(IList<Header> headers)
		{
			for (int i = 0; i < headers.Count; i++)
			{
				if (headers[i].Id == HeaderId.ContentTransferEncoding)
				{
					MimeUtils.TryParse(headers[i].Value, out ContentEncoding encoding);
					if ((uint)(encoding - 1) <= 2u)
					{
						return false;
					}
					return true;
				}
			}
			return false;
		}

		internal MimeEntity CreateEntity(ContentType contentType, IList<Header> headers, bool toplevel)
		{
			MimeEntityConstructorArgs mimeEntityConstructorArgs = new MimeEntityConstructorArgs(this, contentType, headers, toplevel);
			string text = contentType.MediaSubtype.ToLowerInvariant();
			string text2 = contentType.MediaType.ToLowerInvariant();
			if (mimeTypes.Count > 0)
			{
				string key = $"{text2}/{text}";
				if (mimeTypes.TryGetValue(key, out var value))
				{
					return (MimeEntity)value.Invoke(new object[1] { mimeEntityConstructorArgs });
				}
			}
			if (text2 == "message")
			{
				switch (text)
				{
				case "disposition-notification":
					return new MessageDispositionNotification(mimeEntityConstructorArgs);
				case "delivery-status":
					return new MessageDeliveryStatus(mimeEntityConstructorArgs);
				case "partial":
					if (!IsEncoded(headers))
					{
						return new MessagePartial(mimeEntityConstructorArgs);
					}
					break;
				case "external-body":
				case "rfc2822":
				case "rfc822":
				case "global":
				case "news":
					if (!IsEncoded(headers))
					{
						return new MessagePart(mimeEntityConstructorArgs);
					}
					break;
				}
			}
			if (text2 == "multipart")
			{
				return text switch
				{
					"alternative" => new MultipartAlternative(mimeEntityConstructorArgs), 
					"related" => new MultipartRelated(mimeEntityConstructorArgs), 
					"report" => new MultipartReport(mimeEntityConstructorArgs), 
					"encrypted" => new MultipartEncrypted(mimeEntityConstructorArgs), 
					"signed" => new MultipartSigned(mimeEntityConstructorArgs), 
					_ => new Multipart(mimeEntityConstructorArgs), 
				};
			}
			if (text2 == "application")
			{
				switch (text)
				{
				case "x-pkcs7-signature":
				case "pkcs7-signature":
					return new ApplicationPkcs7Signature(mimeEntityConstructorArgs);
				case "x-pgp-encrypted":
				case "pgp-encrypted":
					return new ApplicationPgpEncrypted(mimeEntityConstructorArgs);
				case "x-pgp-signature":
				case "pgp-signature":
					return new ApplicationPgpSignature(mimeEntityConstructorArgs);
				case "x-pkcs7-mime":
				case "pkcs7-mime":
					return new ApplicationPkcs7Mime(mimeEntityConstructorArgs);
				case "vnd.ms-tnef":
				case "ms-tnef":
					return new TnefPart(mimeEntityConstructorArgs);
				case "rtf":
					return new TextPart(mimeEntityConstructorArgs);
				}
			}
			if (text2 == "text")
			{
				if (text == "rfc822-headers" && !IsEncoded(headers))
				{
					return new TextRfc822Headers(mimeEntityConstructorArgs);
				}
				return new TextPart(mimeEntityConstructorArgs);
			}
			return new MimePart(mimeEntityConstructorArgs);
		}
	}
	public enum RfcComplianceMode
	{
		Loose,
		Strict
	}
	public class TextPart : MimePart
	{
		public bool IsEnriched
		{
			get
			{
				if (!base.ContentType.IsMimeType("text", "enriched"))
				{
					return base.ContentType.IsMimeType("text", "richtext");
				}
				return true;
			}
		}

		public bool IsFlowed
		{
			get
			{
				if (!IsPlain || !base.ContentType.Parameters.TryGetValue("format", out string value))
				{
					return false;
				}
				value = value.Trim();
				return value.ToLowerInvariant() == "flowed";
			}
		}

		public bool IsHtml => base.ContentType.IsMimeType("text", "html");

		public bool IsPlain => base.ContentType.IsMimeType("text", "plain");

		public bool IsRichText
		{
			get
			{
				if (!base.ContentType.IsMimeType("text", "rtf"))
				{
					return base.ContentType.IsMimeType("application", "rtf");
				}
				return true;
			}
		}

		public string Text
		{
			get
			{
				if (base.Content == null)
				{
					return string.Empty;
				}
				string text = base.ContentType.Parameters["charset"];
				Encoding encoding = null;
				if (text != null)
				{
					try
					{
						encoding = CharsetUtils.GetEncoding(text);
					}
					catch (NotSupportedException)
					{
					}
				}
				if (encoding == null)
				{
					try
					{
						byte[] array = new byte[2];
						using (Stream stream = base.Content.Open())
						{
							stream.Read(array, 0, array.Length);
						}
						encoding = ((array.Length >= 2 && array[0] == 255 && array[1] == 254) ? Encoding.Unicode : ((array.Length < 2 || array[0] != 254 || array[1] != 255) ? CharsetUtils.UTF8 : Encoding.BigEndianUnicode));
						return GetText(encoding);
					}
					catch (DecoderFallbackException)
					{
						encoding = CharsetUtils.Latin1;
					}
				}
				return GetText(encoding);
			}
			set
			{
				SetText(Encoding.UTF8, value);
			}
		}

		public TextPart(MimeEntityConstructorArgs args)
			: base(args)
		{
		}

		public TextPart(string subtype, params object[] args)
			: this(subtype)
		{
			if (args == null)
			{
				throw new ArgumentNullException("args");
			}
			Encoding encoding = null;
			string text = null;
			foreach (object obj in args)
			{
				if (obj == null || TryInit(obj))
				{
					continue;
				}
				if (obj is Encoding encoding2)
				{
					if (encoding != null)
					{
						throw new ArgumentException("An encoding should not be specified more than once.");
					}
					encoding = encoding2;
					continue;
				}
				if (obj is string text2)
				{
					if (text != null)
					{
						throw new ArgumentException("The text should not be specified more than once.");
					}
					text = text2;
					continue;
				}
				throw new ArgumentException("Unknown initialization parameter: " + obj.GetType());
			}
			if (text != null)
			{
				encoding = encoding ?? Encoding.UTF8;
				SetText(encoding, text);
			}
		}

		internal TextPart(ContentType contentType)
			: base(contentType)
		{
		}

		public TextPart(string subtype)
			: base("text", subtype)
		{
		}

		private static string GetMediaSubtype(TextFormat format)
		{
			switch (format)
			{
			case TextFormat.CompressedRichText:
			case TextFormat.RichText:
				return "rtf";
			case TextFormat.Enriched:
				return "enriched";
			case TextFormat.Plain:
			case TextFormat.Flowed:
				return "plain";
			case TextFormat.Html:
				return "html";
			default:
				throw new ArgumentOutOfRangeException("format");
			}
		}

		public TextPart(TextFormat format)
			: base("text", GetMediaSubtype(format))
		{
			if (format == TextFormat.Flowed)
			{
				base.ContentType.Format = "flowed";
			}
		}

		public TextPart()
			: base("text", "plain")
		{
		}

		public override void Accept(MimeVisitor visitor)
		{
			if (visitor == null)
			{
				throw new ArgumentNullException("visitor");
			}
			visitor.VisitTextPart(this);
		}

		internal bool IsFormat(TextFormat format)
		{
			return format switch
			{
				TextFormat.Plain => IsPlain, 
				TextFormat.Flowed => IsFlowed, 
				TextFormat.Html => IsHtml, 
				TextFormat.Enriched => IsEnriched, 
				TextFormat.RichText => IsRichText, 
				_ => false, 
			};
		}

		public string GetText(Encoding encoding)
		{
			if (encoding == null)
			{
				throw new ArgumentNullException("encoding");
			}
			if (base.Content == null)
			{
				return string.Empty;
			}
			using MemoryStream memoryStream = new MemoryStream();
			using (FilteredStream filteredStream = new FilteredStream(memoryStream))
			{
				filteredStream.Add(new CharsetFilter(encoding, CharsetUtils.UTF8));
				filteredStream.Add(FormatOptions.Default.CreateNewLineFilter());
				base.Content.DecodeTo(filteredStream);
				filteredStream.Flush();
			}
			byte[] buffer = memoryStream.GetBuffer();
			return CharsetUtils.UTF8.GetString(buffer, 0, (int)memoryStream.Length);
		}

		public string GetText(string charset)
		{
			if (charset == null)
			{
				throw new ArgumentNullException("charset");
			}
			return GetText(CharsetUtils.GetEncoding(charset));
		}

		public void SetText(Encoding encoding, string text)
		{
			if (encoding == null)
			{
				throw new ArgumentNullException("encoding");
			}
			if (text == null)
			{
				throw new ArgumentNullException("text");
			}
			base.ContentType.Parameters["charset"] = CharsetUtils.GetMimeCharset(encoding);
			MemoryStream stream = new MemoryStream(encoding.GetBytes(text));
			base.Content = new MimeContent(stream);
		}

		public void SetText(string charset, string text)
		{
			if (charset == null)
			{
				throw new ArgumentNullException("charset");
			}
			if (text == null)
			{
				throw new ArgumentNullException("text");
			}
			SetText(CharsetUtils.GetEncoding(charset), text);
		}
	}
	public class TextRfc822Headers : MessagePart
	{
		public TextRfc822Headers(MimeEntityConstructorArgs args)
			: base(args)
		{
		}

		public TextRfc822Headers(params object[] args)
			: this()
		{
			MimeMessage mimeMessage = null;
			foreach (object obj in args)
			{
				if (obj != null && !TryInit(obj))
				{
					if (!(obj is MimeMessage mimeMessage2))
					{
						throw new ArgumentException("Unknown initialization parameter: " + obj.GetType());
					}
					if (mimeMessage != null)
					{
						throw new ArgumentException("MimeMessage should not be specified more than once.");
					}
					mimeMessage = mimeMessage2;
				}
			}
			if (mimeMessage != null)
			{
				base.Message = mimeMessage;
			}
		}

		public TextRfc822Headers()
			: base("text", "rfc822-headers")
		{
		}

		public override void Accept(MimeVisitor visitor)
		{
			if (visitor == null)
			{
				throw new ArgumentNullException("visitor");
			}
			visitor.VisitTextRfc822Headers(this);
		}
	}
	public enum XMessagePriority
	{
		Highest = 1,
		High,
		Normal,
		Low,
		Lowest
	}
