				return false;
			}
		}

		private static IList<Word> Merge(FormatOptions options, Encoding charset, IList<Word> words)
		{
			if (words.Count < 2)
			{
				return words;
			}
			List<Word> list = new List<Word>();
			Word word = words[0];
			list.Add(word);
			for (int i = 1; i < words.Count; i++)
			{
				Word word2 = words[i];
				if (word.Type != WordType.Atom && word.Type == word2.Type)
				{
					int num = word2.StartIndex - (word.StartIndex + word.CharCount);
					int num2 = word.ByteCount + num + word2.ByteCount;
					int num3 = Math.Max(word.Encoding, word2.Encoding);
					int encodeCount = word.EncodeCount + word2.EncodeCount;
					int num4 = word.QuotedPairs + word2.QuotedPairs;
					int num5 = ((word.Type != WordType.EncodedWord) ? (num2 + num4 + 2) : (num3 switch
					{
						1 => EstimateEncodedWordLength("iso-8859-1", num2, encodeCount), 
						0 => EstimateEncodedWordLength("us-ascii", num2, encodeCount), 
						_ => EstimateEncodedWordLength(charset, num2, encodeCount), 
					}));
					if (num5 + 1 < options.MaxLineLength)
					{
						word.CharCount = word2.StartIndex + word2.CharCount - word.StartIndex;
						word.ByteCount = num2;
						word.EncodeCount = encodeCount;
						word.QuotedPairs = num4;
						word.Encoding = num3;
						continue;
					}
				}
				list.Add(word2);
				word = word2;
			}
			words = list;
			list = new List<Word>();
			word = words[0];
			list.Add(word);
			for (int j = 1; j < words.Count; j++)
			{
				Word word2 = words[j];
				if (ShouldMergeWords(options, charset, words, word, j))
				{
					int num = word2.StartIndex - (word.StartIndex + word.CharCount);
					word.Type = (WordType)Math.Max((int)word.Type, (int)word2.Type);
					word.CharCount = word2.StartIndex + word2.CharCount - word.StartIndex;
					word.ByteCount = word.ByteCount + num + word2.ByteCount;
					word.Encoding = Math.Max(word.Encoding, word2.Encoding);
					word.EncodeCount += word2.EncodeCount;
					word.QuotedPairs += word2.QuotedPairs;
				}
				else
				{
					list.Add(word2);
					word = word2;
				}
			}
			return list;
		}

		private static byte[] Encode(FormatOptions options, Encoding charset, string text, bool phrase)
		{
			QEncodeMode mode = ((!phrase) ? QEncodeMode.Text : QEncodeMode.Phrase);
			IList<Word> list = Merge(options, charset, GetRfc822Words(options, charset, text, phrase));
			StringBuilder stringBuilder = new StringBuilder();
			Word word = null;
			if (!options.AllowMixedHeaderCharsets)
			{
				int num = 0;
				for (int i = 0; i < list.Count; i++)
				{
					if (list[i].Type != WordType.EncodedWord || list[i].Encoding == num)
					{
						continue;
					}
					if (list[i].Encoding > num)
					{
						num = list[i].Encoding;
						for (int j = 0; j < i; j++)
						{
							if (list[j].Type == WordType.EncodedWord)
							{
								list[j].Encoding = num;
							}
						}
					}
					else
					{
						list[i].Encoding = num;
					}
				}
			}
			foreach (Word item in list)
			{
				if (word != null && (word.Type != WordType.EncodedWord || item.Type != WordType.EncodedWord))
				{
					int num2 = word.StartIndex + word.CharCount;
					int count = item.StartIndex - num2;
					stringBuilder.Append(text, num2, count);
				}
				switch (item.Type)
				{
				case WordType.Atom:
					stringBuilder.Append(text, item.StartIndex, item.CharCount);
					break;
				case WordType.QuotedString:
					AppendQuoted(stringBuilder, text, item.StartIndex, item.CharCount);
					break;
				case WordType.EncodedWord:
				{
					int num2;
					int count;
					if (word != null && word.Type == WordType.EncodedWord)
					{
						num2 = word.StartIndex + word.CharCount;
						count = item.StartIndex + item.CharCount - num2;
						stringBuilder.Append(phrase ? '\t' : ' ');
					}
					else
					{
						num2 = item.StartIndex;
						count = item.CharCount;
					}
					switch (item.Encoding)
					{
					case 0:
						AppendEncodedWord(stringBuilder, Encoding.ASCII, text, num2, count, mode);
						break;
					case 1:
						AppendEncodedWord(stringBuilder, CharsetUtils.Latin1, text, num2, count, mode);
						break;
					default:
						AppendEncodedWord(stringBuilder, charset, text, num2, count, mode);
						break;
					}
					break;
				}
				}
				word = item;
			}
			byte[] array = new byte[stringBuilder.Length];
			for (int k = 0; k < stringBuilder.Length; k++)
			{
				array[k] = (byte)stringBuilder[k];
			}
			return array;
		}

		public static byte[] EncodePhrase(FormatOptions options, Encoding charset, string phrase)
		{
			if (options == null)
			{
				throw new ArgumentNullException("options");
			}
			if (charset == null)
			{
				throw new ArgumentNullException("charset");
			}
			if (phrase == null)
			{
				throw new ArgumentNullException("phrase");
			}
			return Encode(options, charset, phrase, phrase: true);
		}

		public static byte[] EncodePhrase(Encoding charset, string phrase)
		{
			return EncodePhrase(FormatOptions.Default, charset, phrase);
		}

		public static byte[] EncodeText(FormatOptions options, Encoding charset, string text)
		{
			if (options == null)
			{
				throw new ArgumentNullException("options");
			}
			if (charset == null)
			{
				throw new ArgumentNullException("charset");
			}
			if (text == null)
			{
				throw new ArgumentNullException("text");
			}
			return Encode(options, charset, text, phrase: false);
		}

		public static byte[] EncodeText(Encoding charset, string text)
		{
			return EncodeText(FormatOptions.Default, charset, text);
		}
	}
	internal static class StringBuilderExtensions
	{
		public static StringBuilder LineWrap(this StringBuilder text, FormatOptions options)
		{
			if (text.Length == 0)
			{
				return text;
			}
			if (char.IsWhiteSpace(text[text.Length - 1]))
			{
				text.Insert(text.Length - 1, options.NewLine);
			}
			else
			{
				text.Append(options.NewLine);
				text.Append('\t');
			}
			return text;
		}

		public static StringBuilder AppendFolded(this StringBuilder text, FormatOptions options, bool firstToken, string value, ref int lineLength)
		{
			int i = 0;
			while (i < value.Length)
			{
				int j = i;
				if (value[i] == '"')
				{
					j++;
					while (j < value.Length && value[j] != '"')
					{
						if (value[j] == '\\')
						{
							j++;
							if (j < value.Length)
							{
								j++;
							}
						}
						else
						{
							j++;
						}
					}
					if (j < value.Length)
					{
						j++;
					}
				}
				else
				{
					for (; j < value.Length && !char.IsWhiteSpace(value[j]); j++)
					{
					}
				}
				int num = j - i;
				if (!firstToken && lineLength > 1 && lineLength + num > options.MaxLineLength)
				{
					text.LineWrap(options);
					lineLength = 1;
				}
				text.Append(value, i, num);
				lineLength += num;
				firstToken = false;
				for (i = j; i < value.Length && char.IsWhiteSpace(value[i]); i++)
				{
				}
				if (i < value.Length && i > j)
				{
					text.Append(' ');
					lineLength++;
				}
			}
			return text;
		}
	}
