			{
				string text = ((!string.IsNullOrEmpty(Addr) || !CanUseSearchKey) ? Addr : SearchKey.Substring(AddrType.Length + 1));
				if (!string.IsNullOrEmpty(text))
				{
					mailbox = new MailboxAddress(Name, text);
				}
				else
				{
					mailbox = null;
				}
				return mailbox != null;
			}
		}

