		private string GetNamedEntityValue()
		{
			int num = index;
			string text = null;
			while (num > 0 && (text = GetNamedEntityValue(states[num - 1])) == null)
			{
				num--;
			}
			if (text == null)
			{
				text = string.Empty;
			}
			if (num < index)
			{
				text += new string(pushed, num, index - num);
			}
			return text;
		}
