		XmlNS
	}
	internal static class HtmlNamespaceExtensions
	{
		private static readonly int NamespacePrefixLength = "http://www.w3.org/".Length;

		private static readonly string[] NamespaceValues = new string[6] { "http://www.w3.org/1999/xhtml", "http://www.w3.org/1998/Math/MathML", "http://www.w3.org/2000/svg", "http://www.w3.org/1999/xlink", "http://www.w3.org/XML/1998/namespace", "http://www.w3.org/2000/xmlns/" };

		public static string ToNamespaceUrl(this HtmlNamespace value)
		{
			if (value < HtmlNamespace.Html || (int)value >= NamespaceValues.Length)
			{
				throw new ArgumentOutOfRangeException("value");
			}
			return NamespaceValues[(int)value];
		}

		public static HtmlNamespace ToHtmlNamespace(this string ns)
		{
			if (ns == null)
			{
				throw new ArgumentNullException("ns");
			}
			if (!ns.StartsWith("http://www.w3.org/", StringComparison.OrdinalIgnoreCase))
			{
				return HtmlNamespace.Html;
			}
			for (int i = 0; i < NamespaceValues.Length; i++)
			{
				if (ns.Length == NamespaceValues[i].Length && string.Compare(ns, NamespacePrefixLength, NamespaceValues[i], NamespacePrefixLength, ns.Length - NamespacePrefixLength, StringComparison.OrdinalIgnoreCase) == 0)
				{
					return (HtmlNamespace)i;
				}
			}
			return HtmlNamespace.Html;
		}
	}
	public delegate void HtmlTagCallback(HtmlTagContext tagContext, HtmlWriter htmlWriter);
	public abstract class HtmlTagContext
	{
		public abstract HtmlAttributeCollection Attributes { get; }

		public bool DeleteEndTag { get; set; }

		public bool DeleteTag { get; set; }

		public bool InvokeCallbackForEndTag { get; set; }

		public abstract bool IsEmptyElementTag { get; }

		public abstract bool IsEndTag { get; }

		public bool SuppressInnerContent { get; set; }

		public HtmlTagId TagId { get; private set; }

		public abstract string TagName { get; }

		protected HtmlTagContext(HtmlTagId tagId)
		{
			TagId = tagId;
		}

		public void WriteTag(HtmlWriter htmlWriter)
		{
			WriteTag(htmlWriter, writeAttributes: false);
		}

		public void WriteTag(HtmlWriter htmlWriter, bool writeAttributes)
		{
			if (htmlWriter == null)
			{
				throw new ArgumentNullException("htmlWriter");
			}
			if (IsEndTag)
			{
				htmlWriter.WriteEndTag(TagName);
				return;
			}
			if (IsEmptyElementTag)
			{
				htmlWriter.WriteEmptyElementTag(TagName);
			}
			else
			{
				htmlWriter.WriteStartTag(TagName);
			}
			if (writeAttributes)
			{
				for (int i = 0; i < Attributes.Count; i++)
				{
					htmlWriter.WriteAttribute(Attributes[i]);
				}
			}
		}
	}
