	public static class HtmlTagIdExtensions
	{
		private static readonly Dictionary<string, HtmlTagId> TagNameToId;

		static HtmlTagIdExtensions()
		{
			HtmlTagId[] array = (HtmlTagId[])Enum.GetValues(typeof(HtmlTagId));
			TagNameToId = new Dictionary<string, HtmlTagId>(array.Length - 1, MimeUtils.OrdinalIgnoreCase);
			for (int i = 0; i < array.Length - 1; i++)
			{
				TagNameToId.Add(array[i].ToHtmlTagName(), array[i]);
			}
		}

		public static string ToHtmlTagName(this HtmlTagId value)
		{
			if (value == HtmlTagId.Comment)
			{
				return "!";
			}
			string text = value.ToString();
			object[] customAttributes = typeof(HtmlTagId).GetField(text).GetCustomAttributes(typeof(HtmlTagNameAttribute), inherit: false);
			if (customAttributes != null && customAttributes.Length == 1)
			{
				return ((HtmlTagNameAttribute)customAttributes[0]).Name;
			}
			return text.ToLowerInvariant();
		}

		internal static HtmlTagId ToHtmlTagId(this string name)
		{
			if (string.IsNullOrEmpty(name))
			{
				return HtmlTagId.Unknown;
			}
			if (name[0] == '!')
			{
				return HtmlTagId.Comment;
			}
			if (!TagNameToId.TryGetValue(name, out var value))
			{
				return HtmlTagId.Unknown;
			}
			return value;
		}

		public static bool IsEmptyElement(this HtmlTagId id)
		{
			switch (id)
			{
			case HtmlTagId.Area:
			case HtmlTagId.Base:
			case HtmlTagId.Br:
			case HtmlTagId.Col:
			case HtmlTagId.Command:
			case HtmlTagId.Embed:
			case HtmlTagId.HR:
			case HtmlTagId.Image:
			case HtmlTagId.Input:
			case HtmlTagId.Keygen:
			case HtmlTagId.Link:
			case HtmlTagId.Meta:
			case HtmlTagId.Param:
			case HtmlTagId.Source:
			case HtmlTagId.Track:
			case HtmlTagId.Wbr:
				return true;
			default:
				return false;
			}
		}

		public static bool IsFormattingElement(this HtmlTagId id)
		{
			switch (id)
			{
			case HtmlTagId.A:
			case HtmlTagId.B:
			case HtmlTagId.Big:
			case HtmlTagId.Code:
			case HtmlTagId.EM:
			case HtmlTagId.Font:
			case HtmlTagId.I:
			case HtmlTagId.NoBR:
			case HtmlTagId.S:
			case HtmlTagId.Small:
			case HtmlTagId.Strike:
			case HtmlTagId.Strong:
			case HtmlTagId.TT:
			case HtmlTagId.U:
				return true;
			default:
				return false;
			}
		}
	}
	public class HtmlToHtml : TextConverter
	{
		private class HtmlToHtmlTagContext : HtmlTagContext
		{
			private readonly HtmlTagToken tag;

			public override string TagName => tag.Name;

			public override HtmlAttributeCollection Attributes => tag.Attributes;

			public override bool IsEmptyElementTag
			{
				get
				{
					if (!tag.IsEmptyElement)
					{
						return tag.Id.IsEmptyElement();
					}
					return true;
				}
			}

			public override bool IsEndTag => tag.IsEndTag;

			public HtmlToHtmlTagContext(HtmlTagToken htmlTag)
				: base(htmlTag.Id)
			{
				tag = htmlTag;
			}
		}

		public override TextFormat InputFormat => TextFormat.Html;

		public override TextFormat OutputFormat => TextFormat.Html;

		public bool FilterComments { get; set; }

		public bool FilterHtml { get; set; }

		public string Footer { get; set; }

		public HeaderFooterFormat FooterFormat { get; set; }

		public string Header { get; set; }

		public HeaderFooterFormat HeaderFormat { get; set; }

		public HtmlTagCallback HtmlTagCallback { get; set; }

		private static void DefaultHtmlTagCallback(HtmlTagContext tagContext, HtmlWriter htmlWriter)
		{
			tagContext.WriteTag(htmlWriter, writeAttributes: true);
		}

		private static bool SuppressContent(IList<HtmlToHtmlTagContext> stack)
		{
			for (int num = stack.Count; num > 0; num--)
			{
				if (stack[num - 1].SuppressInnerContent)
				{
					return true;
				}
			}
			return false;
		}

		private static HtmlToHtmlTagContext Pop(IList<HtmlToHtmlTagContext> stack, string name)
		{
			for (int num = stack.Count; num > 0; num--)
			{
				if (stack[num - 1].TagName.Equals(name, StringComparison.OrdinalIgnoreCase))
				{
					HtmlToHtmlTagContext result = stack[num - 1];
					stack.RemoveAt(num - 1);
					return result;
				}
			}
			return null;
		}

		public override void Convert(TextReader reader, TextWriter writer)
		{
			if (reader == null)
			{
				throw new ArgumentNullException("reader");
			}
			if (writer == null)
			{
				throw new ArgumentNullException("writer");
			}
			if (!string.IsNullOrEmpty(Header))
			{
				if (HeaderFormat == HeaderFooterFormat.Text)
				{
					TextToHtml textToHtml = new TextToHtml();
					using StringReader reader2 = new StringReader(Header);
					textToHtml.Convert(reader2, writer);
				}
				else
				{
					writer.Write(Header);
				}
			}
			using (HtmlWriter htmlWriter = new HtmlWriter(writer))
			{
				HtmlTagCallback htmlTagCallback = HtmlTagCallback ?? new HtmlTagCallback(DefaultHtmlTagCallback);
				List<HtmlToHtmlTagContext> list = new List<HtmlToHtmlTagContext>();
				HtmlTokenizer htmlTokenizer = new HtmlTokenizer(reader);
				HtmlToken token;
				while (htmlTokenizer.ReadNextToken(out token))
				{
					switch (token.Kind)
					{
					default:
						if (!SuppressContent(list))
						{
							htmlWriter.WriteToken(token);
						}
						break;
					case HtmlTokenKind.Comment:
						if (!FilterComments && !SuppressContent(list))
						{
							htmlWriter.WriteToken(token);
						}
						break;
					case HtmlTokenKind.Tag:
					{
						HtmlTagToken htmlTagToken = (HtmlTagToken)token;
						HtmlToHtmlTagContext htmlToHtmlTagContext;
						if (!htmlTagToken.IsEndTag)
						{
							if (!htmlTagToken.IsEmptyElement)
							{
								htmlToHtmlTagContext = new HtmlToHtmlTagContext(htmlTagToken);
								if (FilterHtml && htmlToHtmlTagContext.TagId == HtmlTagId.Script)
								{
									htmlToHtmlTagContext.SuppressInnerContent = true;
									htmlToHtmlTagContext.DeleteEndTag = true;
									htmlToHtmlTagContext.DeleteTag = true;
								}
								else if (!SuppressContent(list))
								{
									htmlTagCallback(htmlToHtmlTagContext, htmlWriter);
								}
								list.Add(htmlToHtmlTagContext);
							}
							else if (!SuppressContent(list))
							{
								htmlToHtmlTagContext = new HtmlToHtmlTagContext(htmlTagToken);
								if (!FilterHtml || htmlToHtmlTagContext.TagId != HtmlTagId.Script)
								{
									htmlTagCallback(htmlToHtmlTagContext, htmlWriter);
								}
							}
						}
						else if ((htmlToHtmlTagContext = Pop(list, htmlTagToken.Name)) != null)
						{
							if (!SuppressContent(list))
							{
								if (htmlToHtmlTagContext.InvokeCallbackForEndTag)
								{
									htmlToHtmlTagContext = new HtmlToHtmlTagContext(htmlTagToken)
									{
										InvokeCallbackForEndTag = htmlToHtmlTagContext.InvokeCallbackForEndTag,
										SuppressInnerContent = htmlToHtmlTagContext.SuppressInnerContent,
										DeleteEndTag = htmlToHtmlTagContext.DeleteEndTag,
										DeleteTag = htmlToHtmlTagContext.DeleteTag
									};
									htmlTagCallback(htmlToHtmlTagContext, htmlWriter);
								}
								else if (!htmlToHtmlTagContext.DeleteEndTag)
								{
									htmlWriter.WriteEndTag(htmlTagToken.Name);
								}
							}
						}
						else if (!SuppressContent(list))
						{
							htmlToHtmlTagContext = new HtmlToHtmlTagContext(htmlTagToken);
							htmlTagCallback(htmlToHtmlTagContext, htmlWriter);
						}
						break;
					}
					}
				}
				htmlWriter.Flush();
			}
			if (string.IsNullOrEmpty(Footer))
			{
				return;
			}
			if (FooterFormat == HeaderFooterFormat.Text)
			{
				TextToHtml textToHtml2 = new TextToHtml();
				using StringReader reader3 = new StringReader(Footer);
				textToHtml2.Convert(reader3, writer);
				return;
			}
			writer.Write(Footer);
		}
	}
	public abstract class HtmlToken
	{
		public HtmlTokenKind Kind { get; private set; }

		protected HtmlToken(HtmlTokenKind kind)
		{
			Kind = kind;
		}

		public abstract void WriteTo(TextWriter output);

		public override string ToString()
		{
			using StringWriter stringWriter = new StringWriter();
			WriteTo(stringWriter);
			return stringWriter.ToString();
		}
	}
	public class HtmlCommentToken : HtmlToken
	{
		public string Comment { get; private set; }

		public bool IsBogusComment { get; private set; }

		internal bool IsBangComment { get; set; }

		public HtmlCommentToken(string comment, bool bogus = false)
			: base(HtmlTokenKind.Comment)
		{
			if (comment == null)
			{
				throw new ArgumentNullException("comment");
			}
			IsBogusComment = bogus;
			Comment = comment;
		}

		public override void WriteTo(TextWriter output)
		{
			if (output == null)
			{
				throw new ArgumentNullException("output");
			}
			if (!IsBogusComment)
			{
				output.Write("<!--");
				output.Write(Comment);
				output.Write("-->");
				return;
			}
			output.Write('<');
			if (IsBangComment)
			{
				output.Write('!');
			}
			output.Write(Comment);
			output.Write('>');
		}
	}
	public class HtmlDataToken : HtmlToken
	{
		internal bool EncodeEntities { get; set; }

		public string Data { get; private set; }

		protected HtmlDataToken(HtmlTokenKind kind, string data)
			: base(kind)
		{
			switch (kind)
			{
			default:
				throw new ArgumentOutOfRangeException("kind");
			case HtmlTokenKind.CData:
			case HtmlTokenKind.Data:
			case HtmlTokenKind.ScriptData:
				if (data == null)
				{
					throw new ArgumentNullException("data");
				}
				Data = data;
				break;
			}
		}

		public HtmlDataToken(string data)
			: base(HtmlTokenKind.Data)
		{
			if (data == null)
			{
				throw new ArgumentNullException("data");
			}
			Data = data;
		}

		public override void WriteTo(TextWriter output)
		{
			if (output == null)
			{
				throw new ArgumentNullException("output");
			}
			if (!EncodeEntities)
			{
				output.Write(Data);
			}
			else
			{
				HtmlUtils.HtmlEncode(output, Data);
			}
		}
	}
	public class HtmlCDataToken : HtmlDataToken
	{
		public HtmlCDataToken(string data)
			: base(HtmlTokenKind.CData, data)
		{
		}

		public override void WriteTo(TextWriter output)
		{
			if (output == null)
			{
				throw new ArgumentNullException("output");
			}
			output.Write("<![CDATA[");
			output.Write(base.Data);
			output.Write("]]>");
		}
	}
	public class HtmlScriptDataToken : HtmlDataToken
	{
		public HtmlScriptDataToken(string data)
			: base(HtmlTokenKind.ScriptData, data)
		{
		}

		public override void WriteTo(TextWriter output)
		{
			if (output == null)
			{
				throw new ArgumentNullException("output");
			}
			output.Write(base.Data);
		}
	}
	public class HtmlTagToken : HtmlToken
	{
		public HtmlAttributeCollection Attributes { get; private set; }

		public HtmlTagId Id { get; private set; }

		public bool IsEmptyElement { get; internal set; }

		public bool IsEndTag { get; private set; }

		public string Name { get; private set; }

		public HtmlTagToken(string name, IEnumerable<HtmlAttribute> attributes, bool isEmptyElement)
			: base(HtmlTokenKind.Tag)
		{
			if (name == null)
			{
				throw new ArgumentNullException("name");
			}
			if (attributes == null)
			{
				throw new ArgumentNullException("attributes");
			}
			Attributes = new HtmlAttributeCollection(attributes);
			IsEmptyElement = isEmptyElement;
			Id = name.ToHtmlTagId();
			Name = name;
		}

		public HtmlTagToken(string name, bool isEndTag)
			: base(HtmlTokenKind.Tag)
		{
			if (name == null)
			{
				throw new ArgumentNullException("name");
			}
			Attributes = new HtmlAttributeCollection();
			Id = name.ToHtmlTagId();
			IsEndTag = isEndTag;
			Name = name;
		}

		public override void WriteTo(TextWriter output)
		{
			if (output == null)
			{
				throw new ArgumentNullException("output");
			}
			output.Write('<');
			if (IsEndTag)
			{
				output.Write('/');
			}
			output.Write(Name);
			for (int i = 0; i < Attributes.Count; i++)
			{
				output.Write(' ');
				output.Write(Attributes[i].Name);
				if (Attributes[i].Value != null)
				{
					output.Write('=');
					HtmlUtils.HtmlAttributeEncode(output, Attributes[i].Value);
				}
			}
			if (IsEmptyElement)
			{
				output.Write('/');
			}
			output.Write('>');
		}
	}
	public class HtmlDocTypeToken : HtmlToken
	{
		private string publicIdentifier;

		private string systemIdentifier;

		internal string RawTagName { get; set; }

		public bool ForceQuirksMode { get; set; }

		public string Name { get; set; }

		public string PublicIdentifier
		{
			get
			{
				return publicIdentifier;
			}
			set
			{
				publicIdentifier = value;
				if (value != null)
				{
					if (PublicKeyword == null)
					{
						PublicKeyword = "PUBLIC";
					}
				}
				else if (systemIdentifier != null)
				{
					SystemKeyword = "SYSTEM";
				}
			}
		}

		public string PublicKeyword { get; internal set; }

		public string SystemIdentifier
		{
			get
			{
				return systemIdentifier;
			}
			set
			{
				systemIdentifier = value;
				if (value != null)
				{
					if (publicIdentifier == null && SystemKeyword == null)
					{
						SystemKeyword = "SYSTEM";
					}
				}
				else
				{
					SystemKeyword = null;
				}
			}
		}

		public string SystemKeyword { get; internal set; }

		public HtmlDocTypeToken()
			: base(HtmlTokenKind.DocType)
		{
			RawTagName = "DOCTYPE";
		}

		public override void WriteTo(TextWriter output)
		{
			if (output == null)
			{
				throw new ArgumentNullException("output");
			}
			output.Write("<!");
			output.Write(RawTagName);
			if (Name != null)
			{
				output.Write(' ');
				output.Write(Name);
			}
			if (PublicIdentifier != null)
			{
				output.Write(' ');
				output.Write(PublicKeyword);
				output.Write(" \"");
				output.Write(PublicIdentifier);
				output.Write('"');
				if (SystemIdentifier != null)
				{
					output.Write(" \"");
					output.Write(SystemIdentifier);
					output.Write('"');
				}
			}
			else if (SystemIdentifier != null)
			{
				output.Write(' ');
				output.Write(SystemKeyword);
				output.Write(" \"");
				output.Write(SystemIdentifier);
				output.Write('"');
			}
			output.Write('>');
		}
	}
	public class HtmlTokenizer
	{
		private const string DocType = "doctype";

		private const string CData = "[CDATA[";

		private readonly HtmlEntityDecoder entity = new HtmlEntityDecoder();

		private readonly StringBuilder data = new StringBuilder();

		private readonly StringBuilder name = new StringBuilder();

		private readonly char[] cdata = new char[3];

		private HtmlDocTypeToken doctype;

		private HtmlAttribute attribute;

		private string activeTagName;

		private HtmlTagToken tag;

		private int cdataIndex;

		private bool isEndTag;

		private bool bang;

		private char quote;

		private TextReader text;

		public bool DecodeCharacterReferences { get; set; }

		public HtmlNamespace HtmlNamespace { get; private set; }

		public int LineNumber { get; private set; }

		public int LinePosition { get; private set; }

		public HtmlTokenizerState TokenizerState { get; private set; }

		public HtmlTokenizer(TextReader reader)
		{
			DecodeCharacterReferences = true;
			LinePosition = 1;
			LineNumber = 1;
			text = reader;
		}

		protected virtual HtmlDocTypeToken CreateDocType()
		{
			return new HtmlDocTypeToken();
		}

		private HtmlDocTypeToken CreateDocTypeToken(string rawTagName)
		{
			HtmlDocTypeToken htmlDocTypeToken = CreateDocType();
			htmlDocTypeToken.RawTagName = rawTagName;
			return htmlDocTypeToken;
		}

		protected virtual HtmlCommentToken CreateCommentToken(string comment, bool bogus = false)
		{
			return new HtmlCommentToken(comment, bogus);
		}

		protected virtual HtmlDataToken CreateDataToken(string data)
		{
			return new HtmlDataToken(data);
		}

		protected virtual HtmlCDataToken CreateCDataToken(string data)
		{
			return new HtmlCDataToken(data);
		}

		protected virtual HtmlScriptDataToken CreateScriptDataToken(string data)
		{
			return new HtmlScriptDataToken(data);
		}

		protected virtual HtmlTagToken CreateTagToken(string name, bool isEndTag = false)
		{
			return new HtmlTagToken(name, isEndTag);
		}

		protected virtual HtmlAttribute CreateAttribute(string name)
		{
			return new HtmlAttribute(name);
		}

		private static bool IsAlphaNumeric(char c)
		{
			if ((c < 'A' || c > 'Z') && (c < 'a' || c > 'z'))
			{
				if (c >= '0')
				{
					return c <= '9';
				}
				return false;
			}
			return true;
		}

		private static bool IsAsciiLetter(char c)
		{
			if (c < 'A' || c > 'Z')
			{
				if (c >= 'a')
				{
					return c <= 'z';
				}
				return false;
			}
			return true;
		}

		private static char ToLower(char c)
		{
			if (c < 'A' || c > 'Z')
			{
				return c;
			}
			return (char)(c + 32);
		}

		private int Peek()
		{
			return text.Peek();
		}

		private int Read()
		{
			int num;
			if ((num = text.Read()) == -1)
			{
				return -1;
			}
			if (num == 10)
			{
				LinePosition = 1;
				LineNumber++;
			}
			else
			{
				LinePosition++;
			}
			return num;
		}

		private bool NameIs(string value)
		{
			if (name.Length != value.Length)
			{
				return false;
			}
			for (int i = 0; i < name.Length; i++)
			{
				if (ToLower(name[i]) != value[i])
				{
					return false;
				}
			}
			return true;
		}

		private void EmitTagAttribute()
		{
			attribute = CreateAttribute(name.ToString());
			tag.Attributes.Add(attribute);
			name.Length = 0;
		}

		private HtmlToken EmitCommentToken(string comment, bool bogus = false)
		{
			HtmlCommentToken htmlCommentToken = CreateCommentToken(comment, bogus);
			htmlCommentToken.IsBangComment = bang;
			data.Length = 0;
			name.Length = 0;
			bang = false;
			return htmlCommentToken;
		}

		private HtmlToken EmitCommentToken(StringBuilder comment, bool bogus = false)
		{
			return EmitCommentToken(comment.ToString(), bogus);
		}

		private HtmlToken EmitDocType()
		{
			HtmlDocTypeToken result = doctype;
			data.Length = 0;
			doctype = null;
			return result;
		}

		private HtmlToken EmitDataToken(bool encodeEntities)
		{
			if (data.Length == 0)
			{
				return null;
			}
			HtmlDataToken htmlDataToken = CreateDataToken(data.ToString());
			htmlDataToken.EncodeEntities = encodeEntities;
			data.Length = 0;
			return htmlDataToken;
		}

		private HtmlToken EmitCDataToken()
		{
			if (data.Length == 0)
			{
				return null;
			}
			HtmlCDataToken result = CreateCDataToken(data.ToString());
			data.Length = 0;
			return result;
		}

		private HtmlToken EmitScriptDataToken()
		{
			if (data.Length == 0)
			{
				return null;
			}
			HtmlScriptDataToken result = CreateScriptDataToken(data.ToString());
			data.Length = 0;
			return result;
		}

		private HtmlToken EmitTagToken()
		{
			if (!tag.IsEndTag && !tag.IsEmptyElement)
			{
				switch (tag.Id)
				{
				case HtmlTagId.IFrame:
				case HtmlTagId.NoEmbed:
				case HtmlTagId.NoFrames:
				case HtmlTagId.Style:
				case HtmlTagId.Xmp:
					TokenizerState = HtmlTokenizerState.RawText;
					activeTagName = tag.Name.ToLowerInvariant();
					break;
				case HtmlTagId.TextArea:
				case HtmlTagId.Title:
					TokenizerState = HtmlTokenizerState.RcData;
					activeTagName = tag.Name.ToLowerInvariant();
					break;
				case HtmlTagId.PlainText:
					TokenizerState = HtmlTokenizerState.PlainText;
					break;
				case HtmlTagId.Script:
					TokenizerState = HtmlTokenizerState.ScriptData;
					break;
				case HtmlTagId.NoScript:
					TokenizerState = HtmlTokenizerState.RawText;
					activeTagName = tag.Name.ToLowerInvariant();
					break;
				case HtmlTagId.Html:
				{
					TokenizerState = HtmlTokenizerState.Data;
					for (int num = tag.Attributes.Count; num > 0; num--)
					{
						HtmlAttribute htmlAttribute = tag.Attributes[num - 1];
						if (htmlAttribute.Id == HtmlAttributeId.XmlNS && htmlAttribute.Value != null)
						{
							HtmlNamespace = htmlAttribute.Value.ToHtmlNamespace();
							break;
						}
					}
					break;
				}
				default:
					TokenizerState = HtmlTokenizerState.Data;
					break;
				}
			}
			else
			{
				TokenizerState = HtmlTokenizerState.Data;
			}
			HtmlTagToken result = tag;
			data.Length = 0;
			tag = null;
			return result;
		}

		private HtmlToken ReadCharacterReference(HtmlTokenizerState next)
		{
			int num = Peek();
			if (num == -1)
			{
				TokenizerState = HtmlTokenizerState.EndOfFile;
				data.Append('&');
				return EmitDataToken(encodeEntities: true);
			}
			char c = (char)num;
			switch (c)
			{
			case '\t':
			case '\n':
			case '\f':
			case '\r':
			case ' ':
			case '&':
			case '<':
				TokenizerState = next;
				data.Append('&');
				return null;
			default:
				entity.Push('&');
				while (entity.Push(c))
				{
					Read();
					if ((num = Peek()) == -1)
					{
						TokenizerState = HtmlTokenizerState.EndOfFile;
						data.Append(entity.GetPushedInput());
						entity.Reset();
						return EmitDataToken(encodeEntities: true);
					}
					c = (char)num;
				}
				TokenizerState = next;
				data.Append(entity.GetValue());
				entity.Reset();
				if (c == ';')
				{
					Read();
				}
				return null;
			}
		}

		private HtmlToken ReadGenericRawTextLessThan(HtmlTokenizerState rawText, HtmlTokenizerState rawTextEndTagOpen)
		{
			int num = Peek();
			data.Append('<');
			char c = (char)num;
			if (c == '/')
			{
				TokenizerState = rawTextEndTagOpen;
				data.Append('/');
				name.Length = 0;
				Read();
			}
			else
			{
				TokenizerState = rawText;
			}
			return null;
		}

		private HtmlToken ReadGenericRawTextEndTagOpen(bool decoded, HtmlTokenizerState rawText, HtmlTokenizerState rawTextEndTagName)
		{
			int num = Peek();
			if (num == -1)
			{
				TokenizerState = HtmlTokenizerState.EndOfFile;
				return EmitDataToken(decoded);
			}
			char c = (char)num;
			if (IsAsciiLetter(c))
			{
				TokenizerState = rawTextEndTagName;
				name.Append(c);
				data.Append(c);
				Read();
			}
			else
			{
				TokenizerState = rawText;
			}
			return null;
		}

		private HtmlToken ReadGenericRawTextEndTagName(bool decoded, HtmlTokenizerState rawText)
		{
			HtmlTokenizerState tokenizerState = TokenizerState;
			do
			{
				int num = Read();
				if (num == -1)
				{
					TokenizerState = HtmlTokenizerState.EndOfFile;
					name.Length = 0;
					return EmitDataToken(decoded);
				}
				char c = (char)num;
				data.Append(c);
				switch (c)
				{
				case '\t':
				case '\n':
				case '\f':
				case '\r':
				case ' ':
					if (!NameIs(activeTagName))
					{
						break;
					}
					TokenizerState = HtmlTokenizerState.BeforeAttributeName;
					continue;
				case '/':
					if (!NameIs(activeTagName))
					{
						break;
					}
					TokenizerState = HtmlTokenizerState.SelfClosingStartTag;
					continue;
				case '>':
					if (NameIs(activeTagName))
					{
						HtmlTagToken result = CreateTagToken(name.ToString(), isEndTag: true);
						TokenizerState = HtmlTokenizerState.Data;
						data.Length = 0;
						name.Length = 0;
						return result;
					}
					break;
				}
				if (!IsAsciiLetter(c))
				{
					TokenizerState = rawText;
					return null;
				}
				name.Append((c == '\0') ? '\ufffd' : c);
			}
			while (TokenizerState == tokenizerState);
			tag = CreateTagToken(name.ToString(), isEndTag: true);
			name.Length = 0;
			return null;
		}

		private HtmlToken ReadData()
		{
			do
			{
				int num = Read();
				if (num == -1)
				{
					TokenizerState = HtmlTokenizerState.EndOfFile;
					break;
				}
				char c = (char)num;
				switch (c)
				{
				case '&':
					if (DecodeCharacterReferences)
					{
						TokenizerState = HtmlTokenizerState.CharacterReferenceInData;
						return null;
					}
					break;
				case '<':
					TokenizerState = HtmlTokenizerState.TagOpen;
					continue;
				}
				data.Append(c);
			}
			while (TokenizerState == HtmlTokenizerState.Data);
			return EmitDataToken(DecodeCharacterReferences);
		}

		private HtmlToken ReadCharacterReferenceInData()
		{
			return ReadCharacterReference(HtmlTokenizerState.Data);
		}

		private HtmlToken ReadRcData()
		{
			do
			{
				int num = Read();
				if (num == -1)
				{
					TokenizerState = HtmlTokenizerState.EndOfFile;
					break;
				}
				char c = (char)num;
				switch (c)
				{
				case '&':
					if (DecodeCharacterReferences)
					{
						TokenizerState = HtmlTokenizerState.CharacterReferenceInRcData;
						return null;
					}
					break;
				case '<':
					TokenizerState = HtmlTokenizerState.RcDataLessThan;
					return EmitDataToken(DecodeCharacterReferences);
				}
				data.Append((c == '\0') ? '\ufffd' : c);
			}
			while (TokenizerState == HtmlTokenizerState.RcData);
			return EmitDataToken(DecodeCharacterReferences);
		}

		private HtmlToken ReadCharacterReferenceInRcData()
		{
			return ReadCharacterReference(HtmlTokenizerState.RcData);
		}

		private HtmlToken ReadRawText()
		{
			do
			{
				int num = Read();
				if (num == -1)
				{
					TokenizerState = HtmlTokenizerState.EndOfFile;
					break;
				}
				char c = (char)num;
				if (c == '<')
				{
					TokenizerState = HtmlTokenizerState.RawTextLessThan;
					return EmitDataToken(encodeEntities: false);
				}
				data.Append((c == '\0') ? '\ufffd' : c);
			}
			while (TokenizerState == HtmlTokenizerState.RawText);
			return EmitDataToken(encodeEntities: false);
		}

		private HtmlToken ReadScriptData()
		{
			do
			{
				int num = Read();
				if (num == -1)
				{
					TokenizerState = HtmlTokenizerState.EndOfFile;
					break;
				}
				char c = (char)num;
				if (c == '<')
				{
					TokenizerState = HtmlTokenizerState.ScriptDataLessThan;
				}
				else
				{
					data.Append((c == '\0') ? '\ufffd' : c);
				}
			}
			while (TokenizerState == HtmlTokenizerState.ScriptData);
			return EmitScriptDataToken();
		}

		private HtmlToken ReadPlainText()
		{
			for (int num = Read(); num != -1; num = Read())
			{
				char c = (char)num;
				data.Append((c == '\0') ? '\ufffd' : c);
			}
			TokenizerState = HtmlTokenizerState.EndOfFile;
			return EmitDataToken(encodeEntities: false);
		}

		private HtmlToken ReadTagOpen()
		{
			int num = Read();
			if (num == -1)
			{
				TokenizerState = HtmlTokenizerState.EndOfFile;
				return CreateDataToken("<");
			}
			char value = (char)num;
			data.Append('<');
			data.Append(value);
			switch (value = (char)num)
			{
			case '!':
				TokenizerState = HtmlTokenizerState.MarkupDeclarationOpen;
				break;
			case '?':
				TokenizerState = HtmlTokenizerState.BogusComment;
				data.Length = 1;
				data[0] = value;
				break;
			case '/':
				TokenizerState = HtmlTokenizerState.EndTagOpen;
				break;
			default:
				if (IsAsciiLetter(value))
				{
					TokenizerState = HtmlTokenizerState.TagName;
					isEndTag = false;
					name.Append(value);
				}
				else
				{
					TokenizerState = HtmlTokenizerState.Data;
				}
				break;
			}
			return null;
		}

		private HtmlToken ReadEndTagOpen()
		{
			int num = Read();
			if (num == -1)
			{
				TokenizerState = HtmlTokenizerState.EndOfFile;
				return EmitDataToken(encodeEntities: false);
			}
			char c = (char)num;
			data.Append(c);
			if (c == '>')
			{
				TokenizerState = HtmlTokenizerState.Data;
				data.Length = 0;
			}
			else if (IsAsciiLetter(c))
			{
				TokenizerState = HtmlTokenizerState.TagName;
				isEndTag = true;
				name.Append(c);
			}
			else
			{
				TokenizerState = HtmlTokenizerState.BogusComment;
				data.Length = 1;
				data[0] = c;
			}
			return null;
		}

		private HtmlToken ReadTagName()
		{
			do
			{
				int num = Read();
				if (num == -1)
				{
					TokenizerState = HtmlTokenizerState.EndOfFile;
					name.Length = 0;
					return EmitDataToken(encodeEntities: false);
				}
				char c = (char)num;
				data.Append(c);
				switch (c)
				{
				case '\t':
				case '\n':
				case '\f':
				case '\r':
				case ' ':
					TokenizerState = HtmlTokenizerState.BeforeAttributeName;
					break;
				case '/':
					TokenizerState = HtmlTokenizerState.SelfClosingStartTag;
					break;
				case '>':
					tag = CreateTagToken(name.ToString(), isEndTag);
					data.Length = 0;
					name.Length = 0;
					return EmitTagToken();
				default:
					name.Append((c == '\0') ? '\ufffd' : c);
					break;
				}
			}
			while (TokenizerState == HtmlTokenizerState.TagName);
			tag = CreateTagToken(name.ToString(), isEndTag);
			name.Length = 0;
			return null;
		}

		private HtmlToken ReadRcDataLessThan()
		{
			return ReadGenericRawTextLessThan(HtmlTokenizerState.RcData, HtmlTokenizerState.RcDataEndTagOpen);
		}

		private HtmlToken ReadRcDataEndTagOpen()
		{
			return ReadGenericRawTextEndTagOpen(DecodeCharacterReferences, HtmlTokenizerState.RcData, HtmlTokenizerState.RcDataEndTagName);
		}

		private HtmlToken ReadRcDataEndTagName()
		{
			return ReadGenericRawTextEndTagName(DecodeCharacterReferences, HtmlTokenizerState.RcData);
		}

		private HtmlToken ReadRawTextLessThan()
		{
			return ReadGenericRawTextLessThan(HtmlTokenizerState.RawText, HtmlTokenizerState.RawTextEndTagOpen);
		}

		private HtmlToken ReadRawTextEndTagOpen()
		{
			return ReadGenericRawTextEndTagOpen(decoded: false, HtmlTokenizerState.RawText, HtmlTokenizerState.RawTextEndTagName);
		}

		private HtmlToken ReadRawTextEndTagName()
		{
			return ReadGenericRawTextEndTagName(decoded: false, HtmlTokenizerState.RawText);
		}

		private HtmlToken ReadScriptDataLessThan()
		{
			int num = Peek();
			data.Append('<');
			switch ((char)(ushort)num)
			{
			case '/':
				TokenizerState = HtmlTokenizerState.ScriptDataEndTagOpen;
				data.Append('/');
				name.Length = 0;
				Read();
				break;
			case '!':
				TokenizerState = HtmlTokenizerState.ScriptDataEscapeStart;
				data.Append('!');
				Read();
				break;
			default:
				TokenizerState = HtmlTokenizerState.ScriptData;
				break;
			}
			return null;
		}

		private HtmlToken ReadScriptDataEndTagOpen()
		{
			int num = Peek();
			if (num == -1)
			{
				TokenizerState = HtmlTokenizerState.EndOfFile;
				return EmitScriptDataToken();
			}
			char c = (char)num;
			if (c == 'S' || c == 's')
			{
				TokenizerState = HtmlTokenizerState.ScriptDataEndTagName;
				name.Append('s');
				data.Append(c);
				Read();
			}
			else
			{
				TokenizerState = HtmlTokenizerState.ScriptData;
			}
			return null;
		}

		private HtmlToken ReadScriptDataEndTagName()
		{
			do
			{
				int num = Read();
				if (num == -1)
				{
					TokenizerState = HtmlTokenizerState.EndOfFile;
					name.Length = 0;
					return EmitScriptDataToken();
				}
				char c = (char)num;
				data.Append(c);
				switch (c)
				{
				case '\t':
				case '\n':
				case '\f':
				case '\r':
				case ' ':
					if (!NameIs("script"))
					{
						break;
					}
					TokenizerState = HtmlTokenizerState.BeforeAttributeName;
					continue;
				case '/':
					if (!NameIs("script"))
					{
						break;
					}
					TokenizerState = HtmlTokenizerState.SelfClosingStartTag;
					continue;
				case '>':
					if (NameIs("script"))
					{
						HtmlTagToken result = CreateTagToken(name.ToString(), isEndTag: true);
						TokenizerState = HtmlTokenizerState.Data;
						data.Length = 0;
						name.Length = 0;
						return result;
					}
					break;
				}
				if (!IsAsciiLetter(c))
				{
					TokenizerState = HtmlTokenizerState.ScriptData;
					name.Length = 0;
					return null;
				}
				name.Append((c == '\0') ? '\ufffd' : c);
			}
			while (TokenizerState == HtmlTokenizerState.ScriptDataEndTagName);
			tag = CreateTagToken(name.ToString(), isEndTag: true);
			name.Length = 0;
			return null;
		}

		private HtmlToken ReadScriptDataEscapeStart()
		{
			if (Peek() == 45)
			{
				TokenizerState = HtmlTokenizerState.ScriptDataEscapeStartDash;
				data.Append('-');
				Read();
			}
			else
			{
				TokenizerState = HtmlTokenizerState.ScriptData;
			}
			return null;
		}

		private HtmlToken ReadScriptDataEscapeStartDash()
		{
			if (Peek() == 45)
			{
				TokenizerState = HtmlTokenizerState.ScriptDataEscapedDashDash;
				data.Append('-');
				Read();
			}
			else
			{
				TokenizerState = HtmlTokenizerState.ScriptData;
			}
			return null;
		}

		private HtmlToken ReadScriptDataEscaped()
		{
			HtmlToken result = null;
			do
			{
				int num = Read();
				if (num == -1)
				{
					TokenizerState = HtmlTokenizerState.EndOfFile;
					return EmitScriptDataToken();
				}
				char c = (char)num;
				switch (c)
				{
				case '-':
					TokenizerState = HtmlTokenizerState.ScriptDataEscapedDash;
