		private HtmlToken ReadCharacterReferenceInAttributeValue()
		{
			char c = ((quote == '\0') ? '>' : quote);
			int num = Peek();
			if (num == -1)
			{
				TokenizerState = HtmlTokenizerState.EndOfFile;
				name.Length = 0;
				return EmitDataToken(encodeEntities: false);
			}
			char c2 = (char)num;
			bool flag;
			switch (c2)
			{
			case '\t':
			case '\n':
			case '\f':
			case '\r':
			case ' ':
			case '&':
			case '<':
				name.Append('&');
				flag = false;
				break;
			default:
			{
				if (c2 == c)
				{
					name.Append('&');
					flag = false;
					break;
				}
				entity.Push('&');
				while (entity.Push(c2))
				{
					Read();
					if ((num = Peek()) == -1)
					{
						TokenizerState = HtmlTokenizerState.EndOfFile;
						data.Length--;
						data.Append(entity.GetPushedInput());
						entity.Reset();
						return EmitDataToken(encodeEntities: false);
					}
					c2 = (char)num;
				}
				string pushedInput = entity.GetPushedInput();
				string value = ((c2 != '=' && !IsAlphaNumeric(c2)) ? entity.GetValue() : pushedInput);
				data.Length--;
				data.Append(pushedInput);
				name.Append(value);
				flag = c2 == ';';
				entity.Reset();
				break;
			}
			}
			if (quote == '\0')
			{
				TokenizerState = HtmlTokenizerState.AttributeValueUnquoted;
			}
			else
			{
				TokenizerState = HtmlTokenizerState.AttributeValueQuoted;
			}
			if (flag)
			{
				Read();
			}
			return null;
		}

		private HtmlToken ReadAfterAttributeValueQuoted()
		{
			HtmlToken result = null;
			int num = Peek();
			if (num == -1)
			{
				TokenizerState = HtmlTokenizerState.EndOfFile;
				return EmitDataToken(encodeEntities: false);
			}
			char c = (char)num;
			bool flag;
			switch (c)
			{
			case '\t':
			case '\n':
			case '\f':
			case '\r':
			case ' ':
				TokenizerState = HtmlTokenizerState.BeforeAttributeName;
				data.Append(c);
				flag = true;
				break;
			case '/':
				TokenizerState = HtmlTokenizerState.SelfClosingStartTag;
				data.Append(c);
				flag = true;
				break;
			case '>':
				result = EmitTagToken();
				flag = true;
				break;
			default:
				TokenizerState = HtmlTokenizerState.BeforeAttributeName;
				flag = false;
				break;
			}
			if (flag)
			{
				Read();
			}
			return result;
		}

		private HtmlToken ReadSelfClosingStartTag()
		{
			int num = Read();
			if (num == -1)
			{
				TokenizerState = HtmlTokenizerState.EndOfFile;
				return EmitDataToken(encodeEntities: false);
			}
			char c = (char)num;
			if (c == '>')
			{
				tag.IsEmptyElement = true;
				return EmitTagToken();
			}
			TokenizerState = HtmlTokenizerState.BeforeAttributeName;
			data.Append(c);
			return null;
		}

		private HtmlToken ReadBogusComment()
		{
			while (true)
			{
				int num;
				if ((num = Read()) == -1)
				{
					TokenizerState = HtmlTokenizerState.EndOfFile;
					break;
				}
				char c;
				if ((c = (char)num) == '>')
				{
					break;
				}
				data.Append((c == '\0') ? '\ufffd' : c);
			}
			TokenizerState = HtmlTokenizerState.Data;
			return EmitCommentToken(data, bogus: true);
		}

		private HtmlToken ReadMarkupDeclarationOpen()
		{
			int i = 0;
			char c = '\0';
			for (; i < 2; i++)
			{
				int num;
				if ((num = Peek()) == -1)
				{
					TokenizerState = HtmlTokenizerState.EndOfFile;
					return EmitDataToken(encodeEntities: false);
				}
				if ((c = (char)num) != '-')
				{
					break;
				}
				data.Append(c);
				Read();
			}
			switch (i)
			{
			case 2:
				TokenizerState = HtmlTokenizerState.CommentStart;
				name.Length = 0;
				return null;
			case 0:
				switch (c)
				{
				case 'D':
				case 'd':
					data.Append(c);
					name.Append(c);
					i = 1;
					Read();
					for (; i < 7; i++)
					{
						int num;
						if ((num = Read()) == -1)
						{
							TokenizerState = HtmlTokenizerState.EndOfFile;
							return EmitDataToken(encodeEntities: false);
						}
						c = (char)num;
						data.Append(c);
						name.Append(c);
						if (ToLower(c) != "doctype"[i])
						{
							break;
						}
					}
					if (i == 7)
					{
						doctype = CreateDocTypeToken(name.ToString());
						TokenizerState = HtmlTokenizerState.DocType;
						name.Length = 0;
						return null;
					}
					name.Length = 0;
					break;
				case '[':
					data.Append(c);
					i = 1;
					Read();
					for (; i < 7; i++)
					{
						int num;
						if ((num = Read()) == -1)
						{
							TokenizerState = HtmlTokenizerState.EndOfFile;
							return EmitDataToken(encodeEntities: false);
						}
						c = (char)num;
						data.Append(c);
						if (c != "[CDATA["[i])
						{
							break;
						}
					}
					if (i == 7)
					{
						TokenizerState = HtmlTokenizerState.CDataSection;
						data.Length = 0;
						return null;
					}
					break;
				}
				break;
			}
			TokenizerState = HtmlTokenizerState.BogusComment;
			for (int j = 0; j < data.Length - 2; j++)
			{
				data[j] = data[j + 2];
			}
			data.Length -= 2;
			bang = true;
			return null;
		}

		private HtmlToken ReadCommentStart()
		{
			int num = Read();
			if (num == -1)
			{
				TokenizerState = HtmlTokenizerState.Data;
				return EmitCommentToken(string.Empty);
