			char c = (char)num;
			data.Append(c);
			switch (c)
			{
			case '-':
				TokenizerState = HtmlTokenizerState.CommentStartDash;
				break;
			case '>':
				TokenizerState = HtmlTokenizerState.Data;
				return EmitCommentToken(string.Empty);
			default:
				TokenizerState = HtmlTokenizerState.Comment;
				name.Append((c == '\0') ? '\ufffd' : c);
				break;
			}
			return null;
		}

