				return EmitCommentToken(name);
			}
			char c = (char)num;
			data.Append(c);
			switch (c)
			{
			case '-':
				TokenizerState = HtmlTokenizerState.CommentEnd;
				break;
			case '>':
				TokenizerState = HtmlTokenizerState.Data;
				return EmitCommentToken(name);
			default:
				TokenizerState = HtmlTokenizerState.Comment;
				name.Append('-');
				name.Append((c == '\0') ? '\ufffd' : c);
				break;
			}
			return null;
		}

		private HtmlToken ReadComment()
		{
			while (true)
			{
				int num = Read();
				if (num == -1)
				{
					TokenizerState = HtmlTokenizerState.EndOfFile;
					return EmitCommentToken(name);
				}
				char c = (char)num;
				data.Append(c);
				if (c == '-')
				{
					break;
				}
				name.Append((c == '\0') ? '\ufffd' : c);
			}
			TokenizerState = HtmlTokenizerState.CommentEndDash;
			return null;
		}

		private HtmlToken ReadCommentEndDash()
		{
			int num = Read();
			if (num == -1)
			{
				TokenizerState = HtmlTokenizerState.Data;
				return EmitCommentToken(name);
			}
			char c = (char)num;
			data.Append(c);
			if (c == '-')
			{
				TokenizerState = HtmlTokenizerState.CommentEnd;
			}
			else
			{
				TokenizerState = HtmlTokenizerState.Comment;
				name.Append('-');
				name.Append((c == '\0') ? '\ufffd' : c);
			}
			return null;
		}

		private HtmlToken ReadCommentEnd()
		{
			while (true)
			{
				int num = Read();
				if (num == -1)
				{
					break;
				}
				char c = (char)num;
				data.Append(c);
				switch (c)
				{
				case '>':
					TokenizerState = HtmlTokenizerState.Data;
					return EmitCommentToken(name);
				case '!':
					TokenizerState = HtmlTokenizerState.CommentEndBang;
					return null;
				case '-':
					break;
				default:
					TokenizerState = HtmlTokenizerState.Comment;
					name.Append("--");
					name.Append((c == '\0') ? '\ufffd' : c);
					return null;
				}
				name.Append('-');
			}
			TokenizerState = HtmlTokenizerState.EndOfFile;
			return EmitCommentToken(name);
		}

