		private HtmlToken ReadDocType()
		{
			int num = Peek();
			if (num == -1)
			{
				TokenizerState = HtmlTokenizerState.EndOfFile;
				doctype.ForceQuirksMode = true;
				name.Length = 0;
				return EmitDocType();
			}
			TokenizerState = HtmlTokenizerState.BeforeDocTypeName;
			char c = (char)num;
			switch (c)
			{
			case '\t':
			case '\n':
			case '\f':
			case '\r':
			case ' ':
				data.Append(c);
				Read();
				break;
			}
			return null;
		}

