				case '>':
					return i;
				case '\t':
				case '\n':
				case '\f':
				case '\r':
					continue;
				}
				if (c < ' ' || c >= '\u007f')
				{
					return i;
				}
			}
			return endIndex;
		}

		private static void HtmlEncode(TextWriter output, ICharArray data, int startIndex, int count)
		{
			int num = startIndex + count;
