	public abstract class TextConverter
	{
		internal static readonly List<UrlPattern> UrlPatterns;

		private Encoding outputEncoding = Encoding.UTF8;

		private Encoding inputEncoding = Encoding.UTF8;

		private int outputStreamBufferSize = 4096;

		private int inputStreamBufferSize = 4096;

		public bool DetectEncodingFromByteOrderMark { get; set; }

		public Encoding InputEncoding
		{
			get
			{
				return inputEncoding;
			}
			set
			{
				if (value == null)
				{
					throw new ArgumentNullException("value");
				}
				inputEncoding = value;
			}
		}

		public abstract TextFormat InputFormat { get; }

		public Encoding OutputEncoding
		{
			get
			{
				return outputEncoding;
			}
			set
			{
				if (value == null)
				{
					throw new ArgumentNullException("value");
				}
				outputEncoding = value;
			}
		}

		public abstract TextFormat OutputFormat { get; }

		public int InputStreamBufferSize
		{
			get
			{
				return inputStreamBufferSize;
			}
			set
			{
				if (value <= 0)
				{
					throw new ArgumentOutOfRangeException("value");
				}
				inputStreamBufferSize = value;
			}
		}

		public int OutputStreamBufferSize
		{
			get
			{
				return outputStreamBufferSize;
			}
			set
			{
				if (value <= 0)
				{
					throw new ArgumentOutOfRangeException("value");
				}
				outputStreamBufferSize = value;
			}
		}

		static TextConverter()
		{
			UrlPatterns = new List<UrlPattern>(new UrlPattern[16]
			{
				new UrlPattern(UrlPatternType.Addrspec, "@", "mailto:"),
				new UrlPattern(UrlPatternType.MailTo, "mailto:", ""),
				new UrlPattern(UrlPatternType.Web, "www.", "http://"),
				new UrlPattern(UrlPatternType.Web, "ftp.", "ftp://"),
				new UrlPattern(UrlPatternType.File, "file://", ""),
				new UrlPattern(UrlPatternType.Web, "ftp://", ""),
				new UrlPattern(UrlPatternType.Web, "sftp://", ""),
				new UrlPattern(UrlPatternType.Web, "http://", ""),
				new UrlPattern(UrlPatternType.Web, "https://", ""),
				new UrlPattern(UrlPatternType.Web, "news://", ""),
				new UrlPattern(UrlPatternType.Web, "nntp://", ""),
				new UrlPattern(UrlPatternType.Web, "telnet://", ""),
				new UrlPattern(UrlPatternType.Web, "webcal://", ""),
				new UrlPattern(UrlPatternType.Web, "callto:", ""),
				new UrlPattern(UrlPatternType.Web, "h323:", ""),
				new UrlPattern(UrlPatternType.Web, "sip:", "")
			});
		}

		private TextReader CreateReader(Stream stream)
		{
			return new StreamReader(stream, InputEncoding, DetectEncodingFromByteOrderMark, InputStreamBufferSize);
		}

		private TextWriter CreateWriter(Stream stream)
		{
			return new StreamWriter(stream, OutputEncoding, OutputStreamBufferSize);
		}

		public virtual void Convert(Stream source, Stream destination)
		{
			if (source == null)
			{
				throw new ArgumentNullException("source");
			}
			if (destination == null)
			{
				throw new ArgumentNullException("destination");
			}
			Convert(CreateReader(source), CreateWriter(destination));
		}

		public virtual void Convert(Stream source, TextWriter writer)
		{
			if (source == null)
			{
				throw new ArgumentNullException("source");
			}
			if (writer == null)
			{
				throw new ArgumentNullException("writer");
			}
			Convert(CreateReader(source), writer);
		}

		public virtual void Convert(TextReader reader, Stream destination)
		{
			if (reader == null)
			{
				throw new ArgumentNullException("reader");
			}
			if (destination == null)
			{
				throw new ArgumentNullException("destination");
			}
			Convert(reader, CreateWriter(destination));
		}

		public abstract void Convert(TextReader reader, TextWriter writer);

		public virtual string Convert(string text)
		{
			if (text == null)
			{
				throw new ArgumentNullException("text");
			}
			using StringReader reader = new StringReader(text);
			StringBuilder stringBuilder = new StringBuilder();
			using (StringWriter writer = new StringWriter(stringBuilder))
			{
				Convert(reader, writer);
			}
			return stringBuilder.ToString();
		}
	}
	public enum TextFormat
	{
		Plain = 0,
		Text = 0,
		Flowed = 1,
		Html = 2,
		Enriched = 3,
		CompressedRichText = 4,
		RichText = 5
	}
	public class TextToFlowed : TextConverter
	{
		private const int OptimalLineLength = 66;

		private const int MaxLineLength = 78;

		public override TextFormat InputFormat => TextFormat.Plain;

		public override TextFormat OutputFormat => TextFormat.Flowed;

		public string Footer { get; set; }

		public string Header { get; set; }

		private static string Unquote(string line, out int quoteDepth)
		{
			int num = 0;
			quoteDepth = 0;
			if (line.Length == 0 || line[0] != '>')
			{
				return line;
			}
			do
			{
				quoteDepth++;
				num++;
				if (num < line.Length && line[num] == ' ')
				{
					num++;
				}
			}
			while (num < line.Length && line[num] == '>');
			return line.Substring(num);
		}

		private static bool StartsWith(string text, int startIndex, string value)
		{
			if (startIndex + value.Length > text.Length)
			{
				return false;
			}
			for (int i = 0; i < value.Length; i++)
			{
				if (text[startIndex + i] != value[i])
				{
					return false;
				}
			}
			return true;
		}

		private static string GetFlowedLine(StringBuilder flowed, string line, ref int index, int quoteDepth)
		{
			flowed.Length = 0;
			if (quoteDepth > 0)
			{
				flowed.Append('>', quoteDepth);
			}
			if (quoteDepth > 0 || StartsWith(line, index, "From "))
			{
				flowed.Append(' ');
			}
			if (flowed.Length + (line.Length - index) <= 78)
			{
				flowed.Append(line.Substring(index));
				index = line.Length;
				return flowed.ToString();
			}
			while (true)
			{
				flowed.Append(line[index++]);
				if (flowed.Length + 1 >= 78 || index >= line.Length || line[index] == ' ')
				{
					if (flowed.Length >= 66)
					{
						flowed.Append(' ');
						break;
					}
					while (flowed.Length + 1 < 78 && index < line.Length && line[index] == ' ')
					{
						flowed.Append(line[index++]);
					}
					if (index >= line.Length || flowed.Length >= 66)
					{
						break;
					}
				}
			}
			return flowed.ToString();
		}

		public override void Convert(TextReader reader, TextWriter writer)
		{
			if (reader == null)
			{
				throw new ArgumentNullException("reader");
			}
			if (writer == null)
			{
				throw new ArgumentNullException("writer");
			}
			if (!string.IsNullOrEmpty(Header))
			{
				writer.Write(Header);
			}
			StringBuilder flowed = new StringBuilder(78);
			string text;
			while ((text = reader.ReadLine()) != null)
			{
				int index = 0;
				text = text.TrimEnd(' ');
				text = Unquote(text, out var quoteDepth);
				do
				{
					string flowedLine = GetFlowedLine(flowed, text, ref index, quoteDepth);
					writer.WriteLine(flowedLine);
				}
				while (index < text.Length);
			}
			if (!string.IsNullOrEmpty(Footer))
			{
				writer.Write(Footer);
			}
		}
	}
	public class TextToHtml : TextConverter
	{
		private class TextToHtmlTagContext : HtmlTagContext
		{
			private HtmlAttributeCollection attributes;

			private bool isEndTag;

			public override string TagName => base.TagId.ToHtmlTagName();

			public override HtmlAttributeCollection Attributes => attributes;

			public override bool IsEmptyElementTag => base.TagId == HtmlTagId.Br;

			public override bool IsEndTag => isEndTag;

			public TextToHtmlTagContext(HtmlTagId tag, HtmlAttribute attr)
				: base(tag)
			{
				attributes = new HtmlAttributeCollection(new HtmlAttribute[1] { attr });
			}

			public TextToHtmlTagContext(HtmlTagId tag)
				: base(tag)
			{
				attributes = HtmlAttributeCollection.Empty;
			}

			public void SetIsEndTag(bool value)
			{
				isEndTag = value;
			}
		}

		private readonly UrlScanner scanner;

		public override TextFormat InputFormat => TextFormat.Plain;

		public override TextFormat OutputFormat => TextFormat.Html;

		public string Footer { get; set; }

		public HeaderFooterFormat FooterFormat { get; set; }

		public string Header { get; set; }

		public HeaderFooterFormat HeaderFormat { get; set; }

		public HtmlTagCallback HtmlTagCallback { get; set; }

		public bool OutputHtmlFragment { get; set; }

		public TextToHtml()
		{
			scanner = new UrlScanner();
			for (int i = 0; i < TextConverter.UrlPatterns.Count; i++)
			{
				scanner.Add(TextConverter.UrlPatterns[i]);
			}
		}

		private static void DefaultHtmlTagCallback(HtmlTagContext tagContext, HtmlWriter htmlWriter)
		{
			tagContext.WriteTag(htmlWriter, writeAttributes: true);
		}

		private static string Unquote(string line, out int quoteDepth)
		{
			int num = 0;
			quoteDepth = 0;
			if (line.Length == 0 || line[0] != '>')
			{
				return line;
			}
			do
			{
				quoteDepth++;
				num++;
				if (num < line.Length && line[num] == ' ')
				{
					num++;
				}
			}
			while (num < line.Length && line[num] == '>');
			return line.Substring(num);
		}

		private static bool SuppressContent(IList<TextToHtmlTagContext> stack)
		{
			for (int num = stack.Count; num > 0; num--)
			{
				if (stack[num - 1].SuppressInnerContent)
				{
					return true;
				}
			}
			return false;
		}

		private void WriteText(HtmlWriter htmlWriter, string text)
		{
			HtmlTagCallback htmlTagCallback = HtmlTagCallback ?? new HtmlTagCallback(DefaultHtmlTagCallback);
			char[] array = text.ToCharArray();
			int num = array.Length;
			int num2 = 0;
			do
			{
				int count = num - num2;
				if (scanner.Scan(array, num2, count, out var match))
				{
					count = match.EndIndex - match.StartIndex;
					if (match.StartIndex > num2)
					{
						htmlWriter.WriteText(array, num2, match.StartIndex - num2);
					}
					string value = match.Prefix + new string(array, match.StartIndex, count);
					TextToHtmlTagContext textToHtmlTagContext = new TextToHtmlTagContext(HtmlTagId.A, new HtmlAttribute(HtmlAttributeId.Href, value));
					htmlTagCallback(textToHtmlTagContext, htmlWriter);
					if (!textToHtmlTagContext.SuppressInnerContent)
					{
						htmlWriter.WriteText(array, match.StartIndex, count);
					}
					if (!textToHtmlTagContext.DeleteEndTag)
					{
						textToHtmlTagContext.SetIsEndTag(value: true);
						if (textToHtmlTagContext.InvokeCallbackForEndTag)
						{
							htmlTagCallback(textToHtmlTagContext, htmlWriter);
						}
						else
						{
							textToHtmlTagContext.WriteTag(htmlWriter);
						}
					}
					num2 = match.EndIndex;
					continue;
				}
				htmlWriter.WriteText(array, num2, count);
				break;
			}
			while (num2 < num);
		}

		public override void Convert(TextReader reader, TextWriter writer)
		{
			if (reader == null)
			{
				throw new ArgumentNullException("reader");
			}
			if (writer == null)
			{
				throw new ArgumentNullException("writer");
			}
			if (!OutputHtmlFragment)
			{
				writer.Write("<html><body>");
			}
			if (!string.IsNullOrEmpty(Header))
			{
				if (HeaderFormat == HeaderFooterFormat.Text)
				{
					TextToHtml textToHtml = new TextToHtml
					{
						OutputHtmlFragment = true
					};
					using StringReader reader2 = new StringReader(Header);
					textToHtml.Convert(reader2, writer);
				}
				else
				{
					writer.Write(Header);
				}
			}
			using (HtmlWriter htmlWriter = new HtmlWriter(writer))
			{
				HtmlTagCallback htmlTagCallback = HtmlTagCallback ?? new HtmlTagCallback(DefaultHtmlTagCallback);
				List<TextToHtmlTagContext> list = new List<TextToHtmlTagContext>();
				int num = 0;
				string line;
				while ((line = reader.ReadLine()) != null)
				{
					line = Unquote(line, out var quoteDepth);
					while (num < quoteDepth)
					{
						TextToHtmlTagContext textToHtmlTagContext = new TextToHtmlTagContext(HtmlTagId.BlockQuote);
						htmlTagCallback(textToHtmlTagContext, htmlWriter);
						num++;
						list.Add(textToHtmlTagContext);
					}
					while (quoteDepth < num)
					{
						TextToHtmlTagContext textToHtmlTagContext = list[list.Count - 1];
						list.RemoveAt(list.Count - 1);
						if (!SuppressContent(list) && !textToHtmlTagContext.DeleteEndTag)
						{
							textToHtmlTagContext.SetIsEndTag(value: true);
							if (textToHtmlTagContext.InvokeCallbackForEndTag)
							{
								htmlTagCallback(textToHtmlTagContext, htmlWriter);
							}
							else
							{
								textToHtmlTagContext.WriteTag(htmlWriter);
							}
						}
						if (textToHtmlTagContext.TagId == HtmlTagId.BlockQuote)
						{
							num--;
						}
					}
					if (!SuppressContent(list))
					{
						WriteText(htmlWriter, line);
						TextToHtmlTagContext textToHtmlTagContext = new TextToHtmlTagContext(HtmlTagId.Br);
						htmlTagCallback(textToHtmlTagContext, htmlWriter);
					}
				}
				for (int num2 = list.Count; num2 > 0; num2--)
				{
					TextToHtmlTagContext textToHtmlTagContext = list[num2 - 1];
					textToHtmlTagContext.SetIsEndTag(value: true);
					if (textToHtmlTagContext.InvokeCallbackForEndTag)
					{
						htmlTagCallback(textToHtmlTagContext, htmlWriter);
					}
					else
					{
						textToHtmlTagContext.WriteTag(htmlWriter);
					}
				}
				htmlWriter.Flush();
			}
			if (!string.IsNullOrEmpty(Footer))
			{
				if (FooterFormat == HeaderFooterFormat.Text)
				{
					TextToHtml textToHtml2 = new TextToHtml
					{
						OutputHtmlFragment = true
					};
					using StringReader reader3 = new StringReader(Footer);
					textToHtml2.Convert(reader3, writer);
				}
				else
				{
					writer.Write(Footer);
				}
			}
			if (!OutputHtmlFragment)
			{
				writer.Write("</body></html>");
			}
		}
	}
	public class TextToText : TextConverter
	{
		public override TextFormat InputFormat => TextFormat.Plain;

		public override TextFormat OutputFormat => TextFormat.Plain;

		public string Footer { get; set; }

		public HeaderFooterFormat FooterFormat { get; set; }

		public string Header { get; set; }

		public override void Convert(TextReader reader, TextWriter writer)
		{
			if (reader == null)
			{
				throw new ArgumentNullException("reader");
			}
			if (writer == null)
			{
				throw new ArgumentNullException("writer");
			}
			if (!string.IsNullOrEmpty(Header))
			{
				writer.Write(Header);
			}
			char[] array = new char[4096];
			int count;
			while ((count = reader.Read(array, 0, array.Length)) > 0)
			{
				writer.Write(array, 0, count);
			}
			if (!string.IsNullOrEmpty(Footer))
			{
				writer.Write(Footer);
			}
		}
	}
	internal class Trie
	{
		private class TrieState
		{
			public TrieState Next;

			public TrieState Fail;

			public TrieMatch Match;

