			public TrieState(TrieState fail)
			{
				Fail = fail;
			}
		}

		private class TrieMatch
		{
			public TrieMatch Next;

			public TrieState State;

			public char Value { get; private set; }

			public TrieMatch(char value)
			{
				Value = value;
			}
		}

		private List<TrieState> failStates;

		private TrieState root;

		private bool icase;

		public Trie(bool ignoreCase)
		{
			failStates = new List<TrieState>();
			root = new TrieState(null);
			icase = ignoreCase;
		}

		public Trie()
			: this(ignoreCase: false)
		{
		}

		private static void ValidateArguments(char[] text, int startIndex, int count)
		{
			if (text == null)
			{
				throw new ArgumentNullException("text");
			}
			if (startIndex < 0 || startIndex > text.Length)
			{
				throw new ArgumentOutOfRangeException("startIndex");
			}
			if (count < 0 || count > text.Length - startIndex)
			{
				throw new ArgumentOutOfRangeException("count");
			}
		}

		private static TrieMatch FindMatch(TrieState state, char value)
		{
			TrieMatch trieMatch = state.Match;
			while (trieMatch != null && trieMatch.Value != value)
			{
				trieMatch = trieMatch.Next;
			}
			return trieMatch;
		}

		private TrieState Insert(TrieState state, int depth, char value)
		{
			TrieState trieState = new TrieState(root);
			TrieMatch trieMatch = new TrieMatch(value);
			trieMatch.Next = state.Match;
			trieMatch.State = trieState;
			state.Match = trieMatch;
			if (failStates.Count < depth + 1)
			{
				failStates.Add(null);
			}
			trieState.Next = failStates[depth];
			failStates[depth] = trieState;
			return trieState;
		}

		public void Add(string pattern)
		{
			TrieState trieState = root;
			int num = 0;
			if (pattern == null)
			{
				throw new ArgumentNullException("pattern");
			}
			if (pattern.Length == 0)
			{
				throw new ArgumentException("The pattern cannot be empty.", "pattern");
			}
			for (int i = 0; i < pattern.Length; i++)
			{
				char value = (icase ? char.ToLower(pattern[i]) : pattern[i]);
				TrieMatch trieMatch = FindMatch(trieState, value);
				trieState = ((trieMatch != null) ? trieMatch.State : Insert(trieState, num, value));
				num++;
			}
			trieState.Pattern = pattern;
			trieState.Depth = num;
			for (int j = 0; j < failStates.Count; j++)
			{
				for (trieState = failStates[j]; trieState != null; trieState = trieState.Next)
				{
					for (TrieMatch trieMatch = trieState.Match; trieMatch != null; trieMatch = trieMatch.Next)
					{
						TrieState state = trieMatch.State;
						TrieState fail = trieState.Fail;
						TrieMatch trieMatch2 = null;
						char value = trieMatch.Value;
						while (fail != null && (trieMatch2 = FindMatch(fail, value)) == null)
						{
							fail = fail.Fail;
						}
						if (fail != null)
						{
							state.Fail = trieMatch2.State;
							if (state.Fail.Depth > state.Depth)
							{
								state.Depth = state.Fail.Depth;
							}
						}
						else if ((trieMatch2 = FindMatch(root, value)) != null)
						{
							state.Fail = trieMatch2.State;
						}
						else
						{
							state.Fail = root;
						}
					}
				}
			}
		}

		public int Search(char[] text, int startIndex, int count, out string pattern)
		{
			ValidateArguments(text, startIndex, count);
			int num = Math.Min(text.Length, startIndex + count);
			TrieState trieState = root;
			TrieMatch trieMatch = null;
			int num2 = 0;
			int result = -1;
			pattern = null;
			for (int i = startIndex; i < num; i++)
			{
				char value = (icase ? char.ToLower(text[i]) : text[i]);
				while (trieState != null && (trieMatch = FindMatch(trieState, value)) == null && num2 == 0)
				{
					trieState = trieState.Fail;
				}
				if (trieState == root)
				{
					if (num2 > 0)
					{
						return result;
					}
					result = i;
				}
				if (trieState == null)
				{
					if (num2 > 0)
					{
						return result;
					}
					trieState = root;
					result = i;
				}
				else if (trieMatch != null)
				{
					trieState = trieMatch.State;
					if (trieState.Depth > num2)
					{
						pattern = trieState.Pattern;
						num2 = trieState.Depth;
					}
				}
				else if (num2 > 0)
				{
					return result;
				}
			}
			if (num2 <= 0)
			{
				return -1;
			}
			return result;
		}

		public int Search(char[] text, int startIndex, out string pattern)
		{
			return Search(text, startIndex, text.Length - startIndex, out pattern);
		}

		public int Search(char[] text, out string pattern)
		{
			return Search(text, 0, text.Length, out pattern);
		}
	}
	internal class UrlMatch
	{
		public readonly string Pattern;

		public readonly string Prefix;

		public int StartIndex;

		public int EndIndex;

		public UrlMatch(string pattern, string prefix)
		{
			Pattern = pattern;
			Prefix = prefix;
		}
	}
	internal enum UrlPatternType
	{
		Addrspec,
		MailTo,
		File,
		Web
	}
	internal class UrlPattern
	{
		public readonly UrlPatternType Type;

		public readonly string Pattern;

		public readonly string Prefix;

		public UrlPattern(UrlPatternType type, string pattern, string prefix)
		{
			Pattern = pattern;
			Prefix = prefix;
			Type = type;
		}
	}
	internal class UrlScanner
	{
		private delegate bool GetIndexDelegate(UrlMatch match, char[] input, int startIndex, int matchIndex, int endIndex);

		private const string AtomCharacters = "!#$%&'*+-/=?^_`{|}~";

		private const string UrlSafeCharacters = "$-_.+!*'(),{}|\\^~[]`#%\";/?:@&=";

		private readonly Dictionary<string, UrlPattern> patterns = new Dictionary<string, UrlPattern>(StringComparer.Ordinal);

		private readonly Trie trie = new Trie(ignoreCase: true);

		public void Add(UrlPattern pattern)
		{
			patterns.Add(pattern.Pattern, pattern);
			trie.Add(pattern.Pattern);
		}

		public bool Scan(char[] text, int startIndex, int count, out UrlMatch match)
		{
			int endIndex = startIndex + count;
			int matchIndex;
			if ((matchIndex = trie.Search(text, startIndex, count, out var pattern)) == -1)
			{
				match = null;
				return false;
			}
			if (!patterns.TryGetValue(pattern, out var value))
			{
				match = null;
				return false;
			}
			match = new UrlMatch(value.Pattern, value.Prefix);
			GetIndexDelegate getIndexDelegate;
			GetIndexDelegate getIndexDelegate2;
			switch (value.Type)
			{
			case UrlPatternType.Addrspec:
				getIndexDelegate = GetAddrspecStartIndex;
				getIndexDelegate2 = GetAddrspecEndIndex;
				break;
			case UrlPatternType.MailTo:
				getIndexDelegate = GetMailToStartIndex;
				getIndexDelegate2 = GetMailToEndIndex;
				break;
			case UrlPatternType.File:
				getIndexDelegate = GetFileStartIndex;
				getIndexDelegate2 = GetFileEndIndex;
				break;
			default:
				getIndexDelegate = GetWebStartIndex;
				getIndexDelegate2 = GetWebEndIndex;
				break;
			}
			if (!getIndexDelegate(match, text, startIndex, matchIndex, endIndex))
			{
				match = null;
				return false;
			}
			if (!getIndexDelegate2(match, text, startIndex, matchIndex, endIndex))
			{
				match = null;
				return false;
			}
			return true;
		}

		private static char GetClosingBrace(UrlMatch match, char[] text, int startIndex)
		{
			if (match.StartIndex == startIndex)
			{
				return '\0';
			}
			return text[match.StartIndex - 1] switch
			{
				'(' => ')', 
				'{' => '}', 
				'[' => ']', 
				'<' => '>', 
				'|' => '|', 
				_ => '\0', 
			};
		}

		private static bool IsDigit(char c)
		{
			if (c >= '0')
			{
				return c <= '9';
			}
			return false;
		}

		private static bool IsLetterOrDigit(char c)
		{
			if ((c < 'A' || c > 'Z') && (c < 'a' || c > 'z'))
			{
				return IsDigit(c);
			}
			return true;
		}

		private static bool IsUrlSafe(char c)
		{
			if (c < '\u0080' && !IsLetterOrDigit(c))
			{
				return "$-_.+!*'(),{}|\\^~[]`#%\";/?:@&=".IndexOf(c) != -1;
			}
			return true;
		}

		private static bool IsAtom(char c)
		{
			if (c < '\u0080' && !IsLetterOrDigit(c))
			{
				return "!#$%&'*+-/=?^_`{|}~".IndexOf(c) != -1;
			}
			return true;
		}

		private static bool IsDomain(char c)
		{
			if (c < '\u0080' && !IsLetterOrDigit(c))
			{
				return c == '-';
			}
			return true;
		}

		private static bool SkipAtom(char[] text, int endIndex, ref int index)
		{
			int num = index;
			while (index < endIndex && IsAtom(text[index]))
			{
				index++;
			}
			return index > num;
		}

		private static bool SkipAtomBackwards(char[] text, int startIndex, ref int index)
		{
			if (!IsAtom(text[index]))
			{
				return false;
			}
			while (index > startIndex && IsAtom(text[index - 1]))
			{
				index--;
			}
			return true;
		}

		private static bool SkipSubDomain(char[] text, int endIndex, ref int index)
		{
			if (!IsDomain(text[index]) || text[index] == '-')
			{
				return false;
			}
			index++;
			while (index < endIndex && IsDomain(text[index]))
			{
				index++;
			}
			return true;
		}

		private static bool SkipDomain(char[] text, int endIndex, ref int index)
		{
			if (!SkipSubDomain(text, endIndex, ref index))
			{
				return false;
			}
			while (index < endIndex && text[index] == '.')
			{
				int num = index++;
				if (index == endIndex || !SkipSubDomain(text, endIndex, ref index))
				{
					index = num;
					break;
				}
			}
			return true;
		}

		private static bool SkipQuoted(char[] text, int endIndex, ref int index)
		{
			bool flag = false;
			index++;
			while (index < endIndex)
			{
				if (text[index] == '\\')
				{
					flag = !flag;
				}
				else if (!flag)
				{
					if (text[index] == '"')
					{
						break;
					}
				}
				else
				{
					flag = false;
				}
				index++;
			}
			if (index >= endIndex || text[index] != '"')
			{
				return false;
			}
			index++;
			return true;
		}

		private static bool SkipQuotedBackwards(char[] text, int startIndex, ref int index)
		{
			index--;
			while (index >= startIndex && (text[index] != '"' || (index != startIndex && text[index - 1] == '\\')))
			{
				index--;
			}
			if (index < startIndex || text[index] != '"')
			{
				return false;
			}
			return true;
		}

		private static bool SkipWord(char[] text, int endIndex, ref int index)
		{
			if (text[index] == '"')
			{
				return SkipQuoted(text, endIndex, ref index);
			}
			return SkipAtom(text, endIndex, ref index);
		}

		private static bool SkipWordBackwards(char[] text, int startIndex, ref int index)
		{
			if (text[index] == '"')
			{
				return SkipQuotedBackwards(text, startIndex, ref index);
			}
			return SkipAtomBackwards(text, startIndex, ref index);
		}

		private static bool SkipIPv4Literal(char[] text, int endIndex, ref int index)
		{
			int num = 0;
			while (index < endIndex && num < 4)
			{
				int num2 = index;
				int num3 = 0;
				while (index < endIndex && text[index] >= '0' && text[index] <= '9')
				{
					num3 = num3 * 10 + (text[index] - 48);
					index++;
				}
				if (index == num2 || index - num2 > 3 || num3 > 255)
				{
					return false;
				}
				num++;
				if (num < 4 && index < endIndex && text[index] == '.')
				{
					index++;
				}
			}
			return num == 4;
		}

		private static bool IsHexDigit(char c)
		{
			if ((c < 'A' || c > 'F') && (c < 'a' || c > 'f'))
			{
				if (c >= '0')
				{
					return c <= '9';
				}
				return false;
			}
			return true;
		}

		private static bool IsIPv6(char[] text, int startIndex)
		{
			int num = startIndex;
			if (text[num] != 'I' && text[num] != 'i')
			{
				return false;
			}
			num++;
			if (text[num] != 'P' && text[num] != 'p')
			{
				return false;
			}
			num++;
			if (text[num] != 'V' && text[num] != 'v')
			{
				return false;
			}
			num++;
			if (text[num] == '6')
			{
				return text[num + 1] == ':';
