				num3 = index - num2;
				if (num3 > 2)
				{
					return false;
				}
				if (num3 == 2)
				{
					if (flag)
					{
						return false;
					}
					flag = true;
					num += 2;
				}
				else
				{
					num++;
				}
			}
			if (num < 2)
			{
				return false;
			}
			if (!flag)
			{
				return num == 7;
			}
			return num < 7;
		}

		private static bool GetAddrspecStartIndex(UrlMatch match, char[] text, int startIndex, int matchIndex, int endIndex)
		{
