			{
				throw new ArgumentOutOfRangeException("maxLineLength");
			}
			switch (constraint)
			{
			case EncodingConstraint.SevenBit:
				if (count0 > 0)
				{
					return ContentEncoding.Base64;
				}
				if (count8 > 0)
				{
