						*(ptr2++) = 13;
						*(ptr2++) = b;
					}
					break;
				}
				case QpDecoderState.DecodeByte:
				{
					byte b = *(ptr3++);
					if (b.IsXDigit())
					{
						saved = saved.ToXDigit();
						b = b.ToXDigit();
						*(ptr2++) = (byte)((saved << 4) | b);
					}
					else
					{
						*(ptr2++) = 61;
						*(ptr2++) = saved;
						*(ptr2++) = b;
					}
					state = QpDecoderState.PassThrough;
					break;
				}
				}
