	public static class AsymmetricAlgorithmExtensions
	{
		private static void GetAsymmetricKeyParameters(DSACryptoServiceProvider dsa, bool publicOnly, out AsymmetricKeyParameter pub, out AsymmetricKeyParameter key)
		{
			DSAParameters dSAParameters = dsa.ExportParameters(!publicOnly);
			DsaValidationParameters parameters = ((dSAParameters.Seed != null) ? new DsaValidationParameters(dSAParameters.Seed, dSAParameters.Counter) : null);
			DsaParameters parameters2 = new DsaParameters(new BigInteger(1, dSAParameters.P), new BigInteger(1, dSAParameters.Q), new BigInteger(1, dSAParameters.G), parameters);
			pub = new DsaPublicKeyParameters(new BigInteger(1, dSAParameters.Y), parameters2);
			key = (publicOnly ? null : new DsaPrivateKeyParameters(new BigInteger(1, dSAParameters.X), parameters2));
		}

		private static AsymmetricKeyParameter GetAsymmetricKeyParameter(DSACryptoServiceProvider dsa)
		{
			GetAsymmetricKeyParameters(dsa, dsa.PublicOnly, out var pub, out var key);
			if (!dsa.PublicOnly)
			{
				return key;
			}
			return pub;
		}

		private static AsymmetricCipherKeyPair GetAsymmetricCipherKeyPair(DSACryptoServiceProvider dsa)
		{
			if (dsa.PublicOnly)
			{
				throw new ArgumentException("DSA key is not a private key.", "key");
			}
			GetAsymmetricKeyParameters(dsa, dsa.PublicOnly, out var pub, out var key);
			return new AsymmetricCipherKeyPair(pub, key);
		}

		private static void GetAsymmetricKeyParameters(RSACryptoServiceProvider rsa, bool publicOnly, out AsymmetricKeyParameter pub, out AsymmetricKeyParameter key)
		{
			RSAParameters rSAParameters = rsa.ExportParameters(!publicOnly);
			BigInteger modulus = new BigInteger(1, rSAParameters.Modulus);
			BigInteger bigInteger = new BigInteger(1, rSAParameters.Exponent);
			pub = new RsaKeyParameters(isPrivate: false, modulus, bigInteger);
			key = (publicOnly ? null : new RsaPrivateCrtKeyParameters(modulus, bigInteger, new BigInteger(1, rSAParameters.D), new BigInteger(1, rSAParameters.P), new BigInteger(1, rSAParameters.Q), new BigInteger(1, rSAParameters.DP), new BigInteger(1, rSAParameters.DQ), new BigInteger(1, rSAParameters.InverseQ)));
		}

		private static AsymmetricKeyParameter GetAsymmetricKeyParameter(RSACryptoServiceProvider rsa)
		{
			GetAsymmetricKeyParameters(rsa, rsa.PublicOnly, out var pub, out var key);
			if (!rsa.PublicOnly)
			{
				return key;
			}
			return pub;
		}

		private static AsymmetricCipherKeyPair GetAsymmetricCipherKeyPair(RSACryptoServiceProvider rsa)
		{
			if (rsa.PublicOnly)
			{
				throw new ArgumentException("RSA key is not a private key.", "key");
			}
			GetAsymmetricKeyParameters(rsa, rsa.PublicOnly, out var pub, out var key);
			return new AsymmetricCipherKeyPair(pub, key);
		}

		public static AsymmetricKeyParameter AsAsymmetricKeyParameter(this AsymmetricAlgorithm key)
		{
			if (key == null)
			{
				throw new ArgumentNullException("key");
			}
			if (key is DSACryptoServiceProvider)
			{
				return GetAsymmetricKeyParameter((DSACryptoServiceProvider)key);
			}
			if (key is RSACryptoServiceProvider)
			{
				return GetAsymmetricKeyParameter((RSACryptoServiceProvider)key);
			}
			throw new NotSupportedException($"'{key.GetType().Name}' is currently not supported.");
		}

		public static AsymmetricCipherKeyPair AsAsymmetricCipherKeyPair(this AsymmetricAlgorithm key)
		{
			if (key == null)
			{
				throw new ArgumentNullException("key");
			}
			if (key is DSACryptoServiceProvider)
			{
				return GetAsymmetricCipherKeyPair((DSACryptoServiceProvider)key);
			}
			if (key is RSACryptoServiceProvider)
			{
				return GetAsymmetricCipherKeyPair((RSACryptoServiceProvider)key);
			}
			throw new NotSupportedException($"'{key.GetType().Name}' is currently not supported.");
		}

		private static byte[] GetPaddedByteArray(BigInteger big, int length)
		{
			byte[] array = big.ToByteArrayUnsigned();
			if (array.Length >= length)
			{
				return array;
			}
			byte[] array2 = new byte[length];
			Buffer.BlockCopy(array, 0, array2, length - array.Length, array.Length);
			return array2;
		}

		private static DSAParameters GetDSAParameters(DsaKeyParameters key)
		{
			DSAParameters result = default(DSAParameters);
			if (key.Parameters.ValidationParameters != null)
			{
				result.Counter = key.Parameters.ValidationParameters.Counter;
				result.Seed = key.Parameters.ValidationParameters.GetSeed();
			}
			result.G = key.Parameters.G.ToByteArrayUnsigned();
			result.P = key.Parameters.P.ToByteArrayUnsigned();
			result.Q = key.Parameters.Q.ToByteArrayUnsigned();
			return result;
		}

		private static AsymmetricAlgorithm GetAsymmetricAlgorithm(DsaPrivateKeyParameters key, DsaPublicKeyParameters pub)
		{
			DSAParameters dSAParameters = GetDSAParameters(key);
			dSAParameters.X = key.X.ToByteArrayUnsigned();
			if (pub != null)
			{
				dSAParameters.Y = pub.Y.ToByteArrayUnsigned();
			}
			DSACryptoServiceProvider dSACryptoServiceProvider = new DSACryptoServiceProvider();
			dSACryptoServiceProvider.ImportParameters(dSAParameters);
			return dSACryptoServiceProvider;
		}

		private static AsymmetricAlgorithm GetAsymmetricAlgorithm(DsaPublicKeyParameters key)
		{
			DSAParameters dSAParameters = GetDSAParameters(key);
			dSAParameters.Y = key.Y.ToByteArrayUnsigned();
			DSACryptoServiceProvider dSACryptoServiceProvider = new DSACryptoServiceProvider();
			dSACryptoServiceProvider.ImportParameters(dSAParameters);
			return dSACryptoServiceProvider;
		}

		private static AsymmetricAlgorithm GetAsymmetricAlgorithm(RsaPrivateCrtKeyParameters key)
		{
			RSAParameters parameters = default(RSAParameters);
			parameters.Exponent = key.PublicExponent.ToByteArrayUnsigned();
			parameters.Modulus = key.Modulus.ToByteArrayUnsigned();
			parameters.P = key.P.ToByteArrayUnsigned();
			parameters.Q = key.Q.ToByteArrayUnsigned();
			parameters.InverseQ = GetPaddedByteArray(key.QInv, parameters.Q.Length);
			parameters.D = GetPaddedByteArray(key.Exponent, parameters.Modulus.Length);
			parameters.DP = GetPaddedByteArray(key.DP, parameters.P.Length);
			parameters.DQ = GetPaddedByteArray(key.DQ, parameters.Q.Length);
			RSACryptoServiceProvider rSACryptoServiceProvider = new RSACryptoServiceProvider();
			rSACryptoServiceProvider.ImportParameters(parameters);
			return rSACryptoServiceProvider;
		}

		private static AsymmetricAlgorithm GetAsymmetricAlgorithm(RsaKeyParameters key)
		{
			RSAParameters parameters = new RSAParameters
			{
				Exponent = key.Exponent.ToByteArrayUnsigned(),
				Modulus = key.Modulus.ToByteArrayUnsigned()
			};
			RSACryptoServiceProvider rSACryptoServiceProvider = new RSACryptoServiceProvider();
			rSACryptoServiceProvider.ImportParameters(parameters);
			return rSACryptoServiceProvider;
		}

		public static AsymmetricAlgorithm AsAsymmetricAlgorithm(this AsymmetricKeyParameter key)
		{
			if (key == null)
			{
				throw new ArgumentNullException("key");
			}
			if (key.IsPrivate)
			{
				if (key is DsaPrivateKeyParameters)
				{
					return GetAsymmetricAlgorithm((DsaPrivateKeyParameters)key, null);
				}
				if (key is RsaPrivateCrtKeyParameters)
				{
					return GetAsymmetricAlgorithm((RsaPrivateCrtKeyParameters)key);
				}
			}
			else
			{
				if (key is DsaPublicKeyParameters)
				{
					return GetAsymmetricAlgorithm((DsaPublicKeyParameters)key);
				}
				if (key is RsaKeyParameters)
				{
					return GetAsymmetricAlgorithm((RsaKeyParameters)key);
				}
			}
			throw new NotSupportedException($"{key.GetType().Name} is currently not supported.");
		}

		public static AsymmetricAlgorithm AsAsymmetricAlgorithm(this AsymmetricCipherKeyPair key)
		{
			if (key == null)
			{
				throw new ArgumentNullException("key");
			}
			if (key.Private is DsaPrivateKeyParameters)
			{
				return GetAsymmetricAlgorithm((DsaPrivateKeyParameters)key.Private, (DsaPublicKeyParameters)key.Public);
			}
			if (key.Private is RsaPrivateCrtKeyParameters)
			{
				return GetAsymmetricAlgorithm((RsaPrivateCrtKeyParameters)key.Private);
			}
			throw new NotSupportedException($"{key.GetType().Name} is currently not supported.");
		}
	}
	public static class BouncyCastleCertificateExtensions
	{
		public static X509Certificate2 AsX509Certificate2(this Org.BouncyCastle.X509.X509Certificate certificate)
		{
			if (certificate == null)
			{
				throw new ArgumentNullException("certificate");
			}
			return new X509Certificate2(certificate.GetEncoded());
		}

		public static string GetIssuerNameInfo(this Org.BouncyCastle.X509.X509Certificate certificate, DerObjectIdentifier identifier)
		{
			if (certificate == null)
			{
				throw new ArgumentNullException("certificate");
			}
			IList valueList = certificate.IssuerDN.GetValueList(identifier);
			if (valueList.Count == 0)
			{
				return string.Empty;
			}
			return (string)valueList[0];
		}

		public static string GetSubjectNameInfo(this Org.BouncyCastle.X509.X509Certificate certificate, DerObjectIdentifier identifier)
		{
			if (certificate == null)
			{
				throw new ArgumentNullException("certificate");
			}
			IList valueList = certificate.SubjectDN.GetValueList(identifier);
			if (valueList.Count == 0)
			{
				return string.Empty;
			}
			return (string)valueList[0];
		}

		public static string GetCommonName(this Org.BouncyCastle.X509.X509Certificate certificate)
		{
			return certificate.GetSubjectNameInfo(X509Name.CN);
		}

		public static string GetSubjectName(this Org.BouncyCastle.X509.X509Certificate certificate)
		{
			return certificate.GetSubjectNameInfo(X509Name.Name);
		}

		public static string GetSubjectEmailAddress(this Org.BouncyCastle.X509.X509Certificate certificate)
		{
			string subjectNameInfo = certificate.GetSubjectNameInfo(X509Name.EmailAddress);
			if (!string.IsNullOrEmpty(subjectNameInfo))
			{
				return subjectNameInfo;
			}
			Asn1OctetString extensionValue = certificate.GetExtensionValue(X509Extensions.SubjectAlternativeName);
			if (extensionValue == null)
			{
				return string.Empty;
			}
			foreach (Asn1Encodable item in Asn1Sequence.GetInstance(Asn1Object.FromByteArray(extensionValue.GetOctets())))
			{
				GeneralName instance = GeneralName.GetInstance(item);
				if (instance.TagNo == 1)
				{
					return ((IAsn1String)instance.Name).GetString();
				}
			}
			return null;
		}

		public static string GetFingerprint(this Org.BouncyCastle.X509.X509Certificate certificate)
		{
			if (certificate == null)
			{
				throw new ArgumentNullException("certificate");
			}
			byte[] encoded = certificate.GetEncoded();
			StringBuilder stringBuilder = new StringBuilder();
			Sha1Digest sha1Digest = new Sha1Digest();
			byte[] array = new byte[20];
			sha1Digest.BlockUpdate(encoded, 0, encoded.Length);
			sha1Digest.DoFinal(array, 0);
			for (int i = 0; i < array.Length; i++)
			{
				stringBuilder.Append(array[i].ToString("x2"));
			}
			return stringBuilder.ToString();
		}

		public static PublicKeyAlgorithm GetPublicKeyAlgorithm(this Org.BouncyCastle.X509.X509Certificate certificate)
		{
			if (certificate == null)
			{
				throw new ArgumentNullException("certificate");
			}
			AsymmetricKeyParameter publicKey = certificate.GetPublicKey();
			if (publicKey is DsaKeyParameters)
			{
				return PublicKeyAlgorithm.Dsa;
			}
			if (publicKey is RsaKeyParameters)
			{
				return PublicKeyAlgorithm.RsaGeneral;
			}
			if (publicKey is ElGamalKeyParameters)
			{
				return PublicKeyAlgorithm.ElGamalGeneral;
			}
			if (publicKey is ECKeyParameters)
			{
				return PublicKeyAlgorithm.EllipticCurve;
			}
			if (publicKey is DHKeyParameters)
			{
				return PublicKeyAlgorithm.DiffieHellman;
			}
			return PublicKeyAlgorithm.None;
		}

		internal static X509KeyUsageFlags GetKeyUsageFlags(bool[] usage)
		{
			X509KeyUsageFlags x509KeyUsageFlags = X509KeyUsageFlags.None;
			if (usage == null || usage[0])
			{
				x509KeyUsageFlags |= X509KeyUsageFlags.DigitalSignature;
			}
			if (usage == null || usage[1])
			{
				x509KeyUsageFlags |= X509KeyUsageFlags.NonRepudiation;
			}
			if (usage == null || usage[2])
			{
				x509KeyUsageFlags |= X509KeyUsageFlags.KeyEncipherment;
			}
			if (usage == null || usage[3])
			{
				x509KeyUsageFlags |= X509KeyUsageFlags.DataEncipherment;
			}
			if (usage == null || usage[4])
			{
				x509KeyUsageFlags |= X509KeyUsageFlags.KeyAgreement;
			}
			if (usage == null || usage[5])
			{
				x509KeyUsageFlags |= X509KeyUsageFlags.KeyCertSign;
			}
			if (usage == null || usage[6])
			{
				x509KeyUsageFlags |= X509KeyUsageFlags.CrlSign;
			}
			if (usage == null || usage[7])
			{
				x509KeyUsageFlags |= X509KeyUsageFlags.EncipherOnly;
			}
			if (usage == null || usage[8])
			{
				x509KeyUsageFlags |= X509KeyUsageFlags.DecipherOnly;
			}
			return x509KeyUsageFlags;
		}

		public static X509KeyUsageFlags GetKeyUsageFlags(this Org.BouncyCastle.X509.X509Certificate certificate)
		{
			if (certificate == null)
			{
				throw new ArgumentNullException("certificate");
			}
			return GetKeyUsageFlags(certificate.GetKeyUsage());
		}

		private static EncryptionAlgorithm[] DecodeEncryptionAlgorithms(byte[] rawData)
		{
			using MemoryStream inputStream = new MemoryStream(rawData, writable: false);
			using Asn1InputStream asn1InputStream = new Asn1InputStream(inputStream);
			List<EncryptionAlgorithm> list = new List<EncryptionAlgorithm>();
			if (!(asn1InputStream.ReadObject() is Asn1Sequence asn1Sequence))
			{
				return null;
			}
			for (int i = 0; i < asn1Sequence.Count; i++)
			{
				if (BouncyCastleSecureMimeContext.TryGetEncryptionAlgorithm(AlgorithmIdentifier.GetInstance(asn1Sequence[i]), out var algorithm))
				{
					list.Add(algorithm);
				}
			}
			return list.ToArray();
		}

		public static EncryptionAlgorithm[] GetEncryptionAlgorithms(this Org.BouncyCastle.X509.X509Certificate certificate)
		{
			if (certificate == null)
			{
				throw new ArgumentNullException("certificate");
			}
			Asn1OctetString extensionValue = certificate.GetExtensionValue(SmimeAttributes.SmimeCapabilities);
			if (extensionValue != null)
			{
				return DecodeEncryptionAlgorithms(extensionValue.GetOctets());
			}
			return new EncryptionAlgorithm[1] { EncryptionAlgorithm.TripleDes };
		}

		internal static bool IsDelta(this X509Crl crl)
		{
			return crl.GetCriticalExtensionOids().Contains(X509Extensions.DeltaCrlIndicator.Id);
		}
	}
	public abstract class BouncyCastleSecureMimeContext : SecureMimeContext
	{
		private HttpClient client;

		public bool CheckCertificateRevocation { get; set; }

		protected BouncyCastleSecureMimeContext()
		{
			client = new HttpClient();
		}

		protected abstract Org.BouncyCastle.X509.X509Certificate GetCertificate(IX509Selector selector);

		protected abstract AsymmetricKeyParameter GetPrivateKey(IX509Selector selector);

		protected abstract HashSet GetTrustedAnchors();

		protected abstract IX509Store GetIntermediateCertificates();

		protected abstract IX509Store GetCertificateRevocationLists();

		protected abstract DateTime GetNextCertificateRevocationListUpdate(X509Name issuer);

		protected abstract CmsRecipient GetCmsRecipient(MailboxAddress mailbox);

		protected CmsRecipientCollection GetCmsRecipients(IEnumerable<MailboxAddress> mailboxes)
		{
			if (mailboxes == null)
			{
				throw new ArgumentNullException("mailboxes");
			}
			CmsRecipientCollection cmsRecipientCollection = new CmsRecipientCollection();
			foreach (MailboxAddress mailbox in mailboxes)
			{
				cmsRecipientCollection.Add(GetCmsRecipient(mailbox));
			}
			return cmsRecipientCollection;
		}

		protected abstract CmsSigner GetCmsSigner(MailboxAddress mailbox, DigestAlgorithm digestAlgo);

		protected abstract void UpdateSecureMimeCapabilities(Org.BouncyCastle.X509.X509Certificate certificate, EncryptionAlgorithm[] algorithms, DateTime timestamp);

		private Org.BouncyCastle.Asn1.Cms.AttributeTable AddSecureMimeCapabilities(Org.BouncyCastle.Asn1.Cms.AttributeTable signedAttributes)
		{
			SmimeCapabilitiesAttribute secureMimeCapabilitiesAttribute = GetSecureMimeCapabilitiesAttribute();
			return signedAttributes.Add(secureMimeCapabilitiesAttribute.AttrType, secureMimeCapabilitiesAttribute.AttrValues[0]);
		}

		private Stream Sign(CmsSigner signer, Stream content, bool encapsulate)
		{
			CmsSignedDataStreamGenerator cmsSignedDataStreamGenerator = new CmsSignedDataStreamGenerator();
			cmsSignedDataStreamGenerator.AddSigner(signer.PrivateKey, signer.Certificate, SecureMimeContext.GetDigestOid(signer.DigestAlgorithm), AddSecureMimeCapabilities(signer.SignedAttributes), signer.UnsignedAttributes);
			cmsSignedDataStreamGenerator.AddCertificates(signer.CertificateChain);
			MemoryBlockStream memoryBlockStream = new MemoryBlockStream();
			using (Stream destination = cmsSignedDataStreamGenerator.Open(memoryBlockStream, encapsulate))
			{
				content.CopyTo(destination, 4096);
			}
			memoryBlockStream.Position = 0L;
			return memoryBlockStream;
		}

		public override ApplicationPkcs7Mime EncapsulatedSign(CmsSigner signer, Stream content)
		{
			if (signer == null)
			{
				throw new ArgumentNullException("signer");
			}
			if (content == null)
			{
				throw new ArgumentNullException("content");
			}
			return new ApplicationPkcs7Mime(SecureMimeType.SignedData, Sign(signer, content, encapsulate: true));
		}

		public override ApplicationPkcs7Mime EncapsulatedSign(MailboxAddress signer, DigestAlgorithm digestAlgo, Stream content)
		{
			if (signer == null)
			{
				throw new ArgumentNullException("signer");
			}
			if (content == null)
			{
				throw new ArgumentNullException("content");
			}
			CmsSigner cmsSigner = GetCmsSigner(signer, digestAlgo);
			return EncapsulatedSign(cmsSigner, content);
		}

		public override ApplicationPkcs7Signature Sign(CmsSigner signer, Stream content)
		{
			if (signer == null)
			{
				throw new ArgumentNullException("signer");
			}
			if (content == null)
			{
				throw new ArgumentNullException("content");
			}
			return new ApplicationPkcs7Signature(Sign(signer, content, encapsulate: false));
		}

		public override MimePart Sign(MailboxAddress signer, DigestAlgorithm digestAlgo, Stream content)
		{
			if (signer == null)
			{
				throw new ArgumentNullException("signer");
			}
			if (content == null)
			{
				throw new ArgumentNullException("content");
			}
			CmsSigner cmsSigner = GetCmsSigner(signer, digestAlgo);
			return Sign(cmsSigner, content);
		}

		private Org.BouncyCastle.X509.X509Certificate GetCertificate(IX509Store store, SignerID signer)
		{
			IEnumerator enumerator = store.GetMatches(signer).GetEnumerator();
			try
			{
				if (enumerator.MoveNext())
				{
					return (Org.BouncyCastle.X509.X509Certificate)enumerator.Current;
				}
			}
			finally
			{
				IDisposable disposable = enumerator as IDisposable;
				if (disposable != null)
				{
					disposable.Dispose();
				}
			}
			return GetCertificate(signer);
		}

		private PkixCertPath BuildCertPath(HashSet anchors, IX509Store certificates, IX509Store crls, Org.BouncyCastle.X509.X509Certificate certificate, DateTime signingTime)
		{
			X509CertificateStore x509CertificateStore = new X509CertificateStore();
			foreach (Org.BouncyCastle.X509.X509Certificate match in certificates.GetMatches(null))
			{
				x509CertificateStore.Add(match);
			}
			X509CertStoreSelector x509CertStoreSelector = new X509CertStoreSelector();
			x509CertStoreSelector.Certificate = certificate;
			PkixBuilderParameters pkixBuilderParameters = new PkixBuilderParameters(anchors, x509CertStoreSelector);
			pkixBuilderParameters.AddStore(GetIntermediateCertificates());
			pkixBuilderParameters.AddStore(x509CertificateStore);
			IX509Store certificateRevocationLists = GetCertificateRevocationLists();
			pkixBuilderParameters.AddStore(certificateRevocationLists);
			pkixBuilderParameters.AddStore(crls);
			pkixBuilderParameters.ValidityModel = 0;
			pkixBuilderParameters.IsRevocationEnabled = false;
			if (signingTime != default(DateTime))
			{
				pkixBuilderParameters.Date = new DateTimeObject(signingTime);
			}
			return new PkixCertPathBuilder().Build(pkixBuilderParameters).CertPath;
		}

		protected internal static bool TryGetDigestAlgorithm(AlgorithmIdentifier identifier, out DigestAlgorithm algorithm)
		{
			if (identifier == null)
			{
				throw new ArgumentNullException("identifier");
			}
			return SecureMimeContext.TryGetDigestAlgorithm(identifier.Algorithm.Id, out algorithm);
		}

		protected internal static bool TryGetEncryptionAlgorithm(AlgorithmIdentifier identifier, out EncryptionAlgorithm algorithm)
		{
			if (identifier == null)
			{
				throw new ArgumentNullException("identifier");
			}
			if (identifier.Algorithm.Id == CmsEnvelopedGenerator.Aes256Cbc)
			{
				algorithm = EncryptionAlgorithm.Aes256;
				return true;
			}
			if (identifier.Algorithm.Id == CmsEnvelopedGenerator.Aes192Cbc)
			{
				algorithm = EncryptionAlgorithm.Aes192;
				return true;
			}
			if (identifier.Algorithm.Id == CmsEnvelopedGenerator.Aes128Cbc)
			{
				algorithm = EncryptionAlgorithm.Aes128;
				return true;
			}
			if (identifier.Algorithm.Id == CmsEnvelopedGenerator.Camellia256Cbc)
			{
				algorithm = EncryptionAlgorithm.Camellia256;
				return true;
			}
			if (identifier.Algorithm.Id == CmsEnvelopedGenerator.Camellia192Cbc)
			{
				algorithm = EncryptionAlgorithm.Camellia192;
				return true;
			}
			if (identifier.Algorithm.Id == CmsEnvelopedGenerator.Camellia128Cbc)
			{
				algorithm = EncryptionAlgorithm.Camellia128;
				return true;
			}
			if (identifier.Algorithm.Id == "1.2.840.113533.7.66.10")
			{
				algorithm = EncryptionAlgorithm.Cast5;
				return true;
			}
			if (identifier.Algorithm.Id == CmsEnvelopedGenerator.DesEde3Cbc)
			{
				algorithm = EncryptionAlgorithm.TripleDes;
				return true;
			}
			if (identifier.Algorithm.Id == SecureMimeContext.Blowfish.Id)
			{
				algorithm = EncryptionAlgorithm.Blowfish;
				return true;
			}
			if (identifier.Algorithm.Id == SecureMimeContext.Twofish.Id)
			{
				algorithm = EncryptionAlgorithm.Twofish;
				return true;
			}
			if (identifier.Algorithm.Id == CmsEnvelopedGenerator.SeedCbc)
			{
				algorithm = EncryptionAlgorithm.Seed;
				return true;
			}
			if (identifier.Algorithm.Id == SmimeCapability.DesCbc.Id)
			{
				algorithm = EncryptionAlgorithm.Des;
				return true;
			}
			if (identifier.Algorithm.Id == "1.3.6.1.4.1.188.7.1.1.2")
			{
				algorithm = EncryptionAlgorithm.Idea;
				return true;
			}
			if (identifier.Algorithm.Id == CmsEnvelopedGenerator.RC2Cbc)
			{
				if (identifier.Parameters is DerSequence)
				{
					switch (((DerInteger)((DerSequence)identifier.Parameters)[0]).Value.IntValue)
					{
					case 58:
						algorithm = EncryptionAlgorithm.RC2128;
						return true;
					case 120:
						algorithm = EncryptionAlgorithm.RC264;
						return true;
					case 160:
						algorithm = EncryptionAlgorithm.RC240;
						return true;
					}
				}
				else
				{
					switch (((DerInteger)identifier.Parameters).Value.IntValue)
					{
					case 128:
						algorithm = EncryptionAlgorithm.RC2128;
						return true;
					case 64:
						algorithm = EncryptionAlgorithm.RC264;
						return true;
					case 40:
						algorithm = EncryptionAlgorithm.RC240;
						return true;
					}
				}
			}
			algorithm = EncryptionAlgorithm.RC240;
			return false;
		}

		private async Task<bool> DownloadCrlsOverHttpAsync(string location, Stream stream, bool doAsync, CancellationToken cancellationToken)
		{
			_ = 1;
			try
			{
				if (doAsync)
				{
					using HttpResponseMessage response = await client.GetAsync(location, cancellationToken).ConfigureAwait(continueOnCapturedContext: false);
					await response.Content.CopyToAsync(stream).ConfigureAwait(continueOnCapturedContext: false);
				}
				else
				{
					cancellationToken.ThrowIfCancellationRequested();
					using WebResponse webResponse = ((HttpWebRequest)WebRequest.Create(location)).GetResponse();
					webResponse.GetResponseStream().CopyTo(stream, 4096);
				}
				return true;
			}
			catch
			{
				return false;
			}
		}

		private async Task DownloadCrlsAsync(Org.BouncyCastle.X509.X509Certificate certificate, bool doAsync, CancellationToken cancellationToken)
		{
			DateTime nextCertificateRevocationListUpdate = GetNextCertificateRevocationListUpdate(certificate.IssuerDN);
			DateTime utcNow = DateTime.UtcNow;
			Asn1OctetString extensionValue;
			if (nextCertificateRevocationListUpdate > utcNow || (extensionValue = certificate.GetExtensionValue(X509Extensions.CrlDistributionPoints)) == null)
			{
				return;
			}
			CrlDistPoint instance = CrlDistPoint.GetInstance(Asn1Object.FromByteArray(extensionValue.GetOctets()));
			DistributionPoint[] points = instance.GetDistributionPoints();
			using MemoryBlockStream stream = new MemoryBlockStream();
			bool flag = false;
			for (int i = 0; i < points.Length; i++)
			{
				GeneralName[] generalNames = GeneralNames.GetInstance(points[i].DistributionPointName.Name).GetNames();
				for (int j = 0; j < generalNames.Length; j++)
				{
					if (flag)
					{
						break;
					}
					if (generalNames[j].TagNo != 6)
					{
						continue;
					}
					string text = DerIA5String.GetInstance(generalNames[j].Name).GetString();
					int num = text.IndexOf(':');
					if (num != -1)
					{
						string text2 = text.Substring(0, num).ToLowerInvariant();
						if (text2 == "https" || text2 == "http")
						{
							flag = await DownloadCrlsOverHttpAsync(text, stream, doAsync, cancellationToken).ConfigureAwait(continueOnCapturedContext: false);
						}
					}
				}
			}
			if (!flag)
			{
				return;
			}
			stream.Position = 0L;
			foreach (X509Crl item in new X509CrlParser().ReadCrls(stream))
			{
				Import(item);
			}
		}

		private async Task<DigitalSignatureCollection> GetDigitalSignaturesAsync(CmsSignedDataParser parser, bool doAsync, CancellationToken cancellationToken)
		{
			IX509Store certificates = parser.GetCertificates("Collection");
			List<IDigitalSignature> signatures = new List<IDigitalSignature>();
			IX509Store crls = parser.GetCrls("Collection");
			SignerInformationStore signerInfos = parser.GetSignerInfos();
			foreach (SignerInformation signer in signerInfos.GetSigners())
			{
				Org.BouncyCastle.X509.X509Certificate certificate = GetCertificate(certificates, signer.SignerID);
				SecureMimeDigitalSignature signature = new SecureMimeDigitalSignature(signer, certificate);
				if (CheckCertificateRevocation && certificate != null)
				{
					await DownloadCrlsAsync(certificate, doAsync, cancellationToken).ConfigureAwait(continueOnCapturedContext: false);
				}
				if (certificate != null)
				{
					Import(certificate);
					if (signature.EncryptionAlgorithms.Length != 0 && signature.CreationDate != default(DateTime))
					{
						UpdateSecureMimeCapabilities(certificate, signature.EncryptionAlgorithms, signature.CreationDate);
					}
				}
				HashSet trustedAnchors = GetTrustedAnchors();
				try
				{
					signature.Chain = BuildCertPath(trustedAnchors, certificates, crls, certificate, signature.CreationDate);
				}
				catch (Exception chainException)
				{
					signature.ChainException = chainException;
				}
				signatures.Add(signature);
			}
			return new DigitalSignatureCollection(signatures);
		}

		public override DigitalSignatureCollection Verify(Stream content, Stream signatureData, CancellationToken cancellationToken = default(CancellationToken))
		{
			if (content == null)
			{
				throw new ArgumentNullException("content");
			}
			if (signatureData == null)
			{
				throw new ArgumentNullException("signatureData");
			}
			CmsSignedDataParser cmsSignedDataParser = new CmsSignedDataParser(new CmsTypedStream(content), signatureData);
			cmsSignedDataParser.GetSignedContent().Drain();
			return GetDigitalSignaturesAsync(cmsSignedDataParser, doAsync: false, cancellationToken).GetAwaiter().GetResult();
		}

		public override Task<DigitalSignatureCollection> VerifyAsync(Stream content, Stream signatureData, CancellationToken cancellationToken = default(CancellationToken))
		{
			if (content == null)
			{
				throw new ArgumentNullException("content");
			}
			if (signatureData == null)
			{
				throw new ArgumentNullException("signatureData");
			}
			CmsSignedDataParser cmsSignedDataParser = new CmsSignedDataParser(new CmsTypedStream(content), signatureData);
			cmsSignedDataParser.GetSignedContent().Drain();
			return GetDigitalSignaturesAsync(cmsSignedDataParser, doAsync: true, cancellationToken);
		}

		public override DigitalSignatureCollection Verify(Stream signedData, out MimeEntity entity, CancellationToken cancellationToken = default(CancellationToken))
		{
			if (signedData == null)
			{
				throw new ArgumentNullException("signedData");
			}
			CmsSignedDataParser cmsSignedDataParser = new CmsSignedDataParser(signedData);
			CmsTypedStream signedContent = cmsSignedDataParser.GetSignedContent();
			entity = MimeEntity.Load(signedContent.ContentStream, cancellationToken);
			signedContent.Drain();
			return GetDigitalSignaturesAsync(cmsSignedDataParser, doAsync: false, cancellationToken).GetAwaiter().GetResult();
		}

		public override Stream Verify(Stream signedData, out DigitalSignatureCollection signatures, CancellationToken cancellationToken = default(CancellationToken))
		{
			if (signedData == null)
			{
				throw new ArgumentNullException("signedData");
			}
			CmsSignedDataParser cmsSignedDataParser = new CmsSignedDataParser(signedData);
			CmsTypedStream signedContent = cmsSignedDataParser.GetSignedContent();
			MemoryBlockStream memoryBlockStream = new MemoryBlockStream();
			signedContent.ContentStream.CopyTo(memoryBlockStream, 4096);
			memoryBlockStream.Position = 0L;
			signedContent.Drain();
			signatures = GetDigitalSignaturesAsync(cmsSignedDataParser, doAsync: false, cancellationToken).GetAwaiter().GetResult();
			return memoryBlockStream;
		}

		private Stream Envelope(CmsRecipientCollection recipients, Stream content)
		{
			HashSet<Org.BouncyCastle.X509.X509Certificate> hashSet = new HashSet<Org.BouncyCastle.X509.X509Certificate>();
			CmsEnvelopedDataGenerator cmsEnvelopedDataGenerator = new CmsEnvelopedDataGenerator();
			int num = 0;
			foreach (CmsRecipient recipient in recipients)
			{
				if (hashSet.Add(recipient.Certificate))
				{
					cmsEnvelopedDataGenerator.AddKeyTransRecipient(recipient.Certificate);
					num++;
				}
			}
			if (num == 0)
			{
				throw new ArgumentException("No recipients specified.", "recipients");
			}
			EncryptionAlgorithm preferredEncryptionAlgorithm = GetPreferredEncryptionAlgorithm(recipients);
			CmsProcessableInputStream content2 = new CmsProcessableInputStream(content);
			return new MemoryStream((preferredEncryptionAlgorithm switch
			{
				EncryptionAlgorithm.Aes128 => cmsEnvelopedDataGenerator.Generate(content2, CmsEnvelopedGenerator.Aes128Cbc), 
				EncryptionAlgorithm.Aes192 => cmsEnvelopedDataGenerator.Generate(content2, CmsEnvelopedGenerator.Aes192Cbc), 
				EncryptionAlgorithm.Aes256 => cmsEnvelopedDataGenerator.Generate(content2, CmsEnvelopedGenerator.Aes256Cbc), 
				EncryptionAlgorithm.Blowfish => cmsEnvelopedDataGenerator.Generate(content2, SecureMimeContext.Blowfish.Id), 
				EncryptionAlgorithm.Camellia128 => cmsEnvelopedDataGenerator.Generate(content2, CmsEnvelopedGenerator.Camellia128Cbc), 
				EncryptionAlgorithm.Camellia192 => cmsEnvelopedDataGenerator.Generate(content2, CmsEnvelopedGenerator.Camellia192Cbc), 
				EncryptionAlgorithm.Camellia256 => cmsEnvelopedDataGenerator.Generate(content2, CmsEnvelopedGenerator.Camellia256Cbc), 
				EncryptionAlgorithm.Cast5 => cmsEnvelopedDataGenerator.Generate(content2, "1.2.840.113533.7.66.10"), 
				EncryptionAlgorithm.Des => cmsEnvelopedDataGenerator.Generate(content2, SmimeCapability.DesCbc.Id), 
				EncryptionAlgorithm.Idea => cmsEnvelopedDataGenerator.Generate(content2, "1.3.6.1.4.1.188.7.1.1.2"), 
				EncryptionAlgorithm.RC240 => cmsEnvelopedDataGenerator.Generate(content2, CmsEnvelopedGenerator.RC2Cbc, 40), 
				EncryptionAlgorithm.RC264 => cmsEnvelopedDataGenerator.Generate(content2, CmsEnvelopedGenerator.RC2Cbc, 64), 
				EncryptionAlgorithm.RC2128 => cmsEnvelopedDataGenerator.Generate(content2, CmsEnvelopedGenerator.RC2Cbc, 128), 
				EncryptionAlgorithm.Seed => cmsEnvelopedDataGenerator.Generate(content2, CmsEnvelopedGenerator.SeedCbc), 
				EncryptionAlgorithm.TripleDes => cmsEnvelopedDataGenerator.Generate(content2, CmsEnvelopedGenerator.DesEde3Cbc), 
				_ => throw new NotSupportedException($"The {preferredEncryptionAlgorithm} encryption algorithm is not supported by the {GetType().Name}."), 
			}).GetEncoded(), writable: false);
		}

		public override ApplicationPkcs7Mime Encrypt(CmsRecipientCollection recipients, Stream content)
		{
			if (recipients == null)
			{
				throw new ArgumentNullException("recipients");
			}
			if (content == null)
			{
				throw new ArgumentNullException("content");
			}
			return new ApplicationPkcs7Mime(SecureMimeType.EnvelopedData, Envelope(recipients, content));
		}

		public override MimePart Encrypt(IEnumerable<MailboxAddress> recipients, Stream content)
		{
			if (recipients == null)
			{
				throw new ArgumentNullException("recipients");
			}
			if (content == null)
			{
				throw new ArgumentNullException("content");
			}
			return Encrypt(GetCmsRecipients(recipients), content);
		}

		public override MimeEntity Decrypt(Stream encryptedData, CancellationToken cancellationToken = default(CancellationToken))
		{
			if (encryptedData == null)
			{
				throw new ArgumentNullException("encryptedData");
			}
			CmsEnvelopedDataParser cmsEnvelopedDataParser = new CmsEnvelopedDataParser(encryptedData);
			RecipientInformationStore recipientInfos = cmsEnvelopedDataParser.GetRecipientInfos();
			_ = cmsEnvelopedDataParser.EncryptionAlgorithmID;
			foreach (RecipientInformation recipient in recipientInfos.GetRecipients())
			{
				AsymmetricKeyParameter privateKey;
				if ((privateKey = GetPrivateKey(recipient.RecipientID)) != null)
				{
					return MimeEntity.Load(new MemoryStream(recipient.GetContent(privateKey), writable: false), persistent: true, cancellationToken);
				}
			}
			throw new CmsException("A suitable private key could not be found for decrypting.");
		}

		public override void DecryptTo(Stream encryptedData, Stream decryptedData)
		{
			if (encryptedData == null)
			{
				throw new ArgumentNullException("encryptedData");
			}
			if (decryptedData == null)
			{
				throw new ArgumentNullException("decryptedData");
			}
			CmsEnvelopedDataParser cmsEnvelopedDataParser = new CmsEnvelopedDataParser(encryptedData);
			RecipientInformationStore recipientInfos = cmsEnvelopedDataParser.GetRecipientInfos();
			_ = cmsEnvelopedDataParser.EncryptionAlgorithmID;
			foreach (RecipientInformation recipient in recipientInfos.GetRecipients())
			{
				AsymmetricKeyParameter privateKey;
				if ((privateKey = GetPrivateKey(recipient.RecipientID)) != null)
				{
					recipient.GetContentStream(privateKey).ContentStream.CopyTo(decryptedData, 4096);
					return;
				}
			}
			throw new CmsException("A suitable private key could not be found for decrypting.");
		}

		public override MimePart Export(IEnumerable<MailboxAddress> mailboxes)
		{
			if (mailboxes == null)
			{
				throw new ArgumentNullException("mailboxes");
			}
			X509CertificateStore x509CertificateStore = new X509CertificateStore();
			int num = 0;
			foreach (MailboxAddress mailbox in mailboxes)
			{
				CmsRecipient cmsRecipient = GetCmsRecipient(mailbox);
				x509CertificateStore.Add(cmsRecipient.Certificate);
				num++;
			}
			if (num == 0)
			{
				throw new ArgumentException("No mailboxes specified.", "mailboxes");
			}
			CmsSignedDataStreamGenerator cmsSignedDataStreamGenerator = new CmsSignedDataStreamGenerator();
			MemoryBlockStream memoryBlockStream = new MemoryBlockStream();
			cmsSignedDataStreamGenerator.AddCertificates(x509CertificateStore);
			cmsSignedDataStreamGenerator.Open(memoryBlockStream).Dispose();
			memoryBlockStream.Position = 0L;
			return new ApplicationPkcs7Mime(SecureMimeType.CertsOnly, memoryBlockStream);
		}

		protected override void Dispose(bool disposing)
		{
			if (disposing && client != null)
			{
				client.Dispose();
				client = null;
			}
			base.Dispose(disposing);
		}
	}
	[Serializable]
	public class CertificateNotFoundException : Exception
	{
		public MailboxAddress Mailbox { get; private set; }

		protected CertificateNotFoundException(SerializationInfo info, StreamingContext context)
			: base(info, context)
		{
			if (MailboxAddress.TryParse(info.GetString("Mailbox"), out var mailbox))
			{
				Mailbox = mailbox;
			}
		}

		public CertificateNotFoundException(MailboxAddress mailbox, string message)
			: base(message)
		{
			Mailbox = mailbox;
		}

		[SecurityCritical]
		public override void GetObjectData(SerializationInfo info, StreamingContext context)
		{
			base.GetObjectData(info, context);
			info.AddValue("Mailbox", Mailbox.ToString(encode: true));
		}
	}
	public class CmsRecipient
	{
		public Org.BouncyCastle.X509.X509Certificate Certificate { get; private set; }

		public SubjectIdentifierType RecipientIdentifierType { get; private set; }

		public EncryptionAlgorithm[] EncryptionAlgorithms { get; set; }

		public CmsRecipient(Org.BouncyCastle.X509.X509Certificate certificate, SubjectIdentifierType recipientIdentifierType = SubjectIdentifierType.IssuerAndSerialNumber)
		{
			if (certificate == null)
			{
				throw new ArgumentNullException("certificate");
			}
			if (recipientIdentifierType == SubjectIdentifierType.IssuerAndSerialNumber)
			{
				RecipientIdentifierType = SubjectIdentifierType.IssuerAndSerialNumber;
			}
			else
			{
				RecipientIdentifierType = SubjectIdentifierType.SubjectKeyIdentifier;
			}
			EncryptionAlgorithms = certificate.GetEncryptionAlgorithms();
			Certificate = certificate;
		}

		public CmsRecipient(Stream stream, SubjectIdentifierType recipientIdentifierType = SubjectIdentifierType.IssuerAndSerialNumber)
		{
			if (stream == null)
			{
				throw new ArgumentNullException("stream");
			}
			if (recipientIdentifierType == SubjectIdentifierType.IssuerAndSerialNumber)
			{
				RecipientIdentifierType = SubjectIdentifierType.IssuerAndSerialNumber;
			}
			else
			{
				RecipientIdentifierType = SubjectIdentifierType.SubjectKeyIdentifier;
			}
			X509CertificateParser x509CertificateParser = new X509CertificateParser();
			RecipientIdentifierType = SubjectIdentifierType.IssuerAndSerialNumber;
			Certificate = x509CertificateParser.ReadCertificate(stream);
			if (Certificate == null)
			{
				throw new FormatException();
			}
			EncryptionAlgorithms = Certificate.GetEncryptionAlgorithms();
		}

		public CmsRecipient(string fileName, SubjectIdentifierType recipientIdentifierType = SubjectIdentifierType.IssuerAndSerialNumber)
		{
			if (fileName == null)
			{
				throw new ArgumentNullException("fileName");
			}
			X509CertificateParser x509CertificateParser = new X509CertificateParser();
			if (recipientIdentifierType == SubjectIdentifierType.IssuerAndSerialNumber)
			{
				RecipientIdentifierType = SubjectIdentifierType.IssuerAndSerialNumber;
			}
			else
			{
				RecipientIdentifierType = SubjectIdentifierType.SubjectKeyIdentifier;
			}
			using (FileStream inStream = File.OpenRead(fileName))
			{
				Certificate = x509CertificateParser.ReadCertificate(inStream);
			}
			if (Certificate == null)
			{
				throw new FormatException();
			}
			EncryptionAlgorithms = Certificate.GetEncryptionAlgorithms();
		}

		public CmsRecipient(X509Certificate2 certificate, SubjectIdentifierType recipientIdentifierType = SubjectIdentifierType.IssuerAndSerialNumber)
		{
			if (certificate == null)
			{
				throw new ArgumentNullException("certificate");
			}
			if (recipientIdentifierType == SubjectIdentifierType.IssuerAndSerialNumber)
			{
				RecipientIdentifierType = SubjectIdentifierType.IssuerAndSerialNumber;
			}
			else
			{
				RecipientIdentifierType = SubjectIdentifierType.SubjectKeyIdentifier;
			}
			EncryptionAlgorithms = certificate.GetEncryptionAlgorithms();
			Certificate = certificate.AsBouncyCastleCertificate();
		}
	}
	public class CmsRecipientCollection : ICollection<CmsRecipient>, IEnumerable<CmsRecipient>, IEnumerable
	{
		private readonly IList<CmsRecipient> recipients;

		public int Count => recipients.Count;

		public bool IsReadOnly => false;

		public CmsRecipientCollection()
		{
			recipients = new List<CmsRecipient>();
		}

		public void Add(CmsRecipient recipient)
		{
			if (recipient == null)
			{
				throw new ArgumentNullException("recipient");
			}
			recipients.Add(recipient);
		}

		public void Clear()
		{
			recipients.Clear();
		}

		public bool Contains(CmsRecipient recipient)
		{
			if (recipient == null)
			{
				throw new ArgumentNullException("recipient");
			}
			return recipients.Contains(recipient);
		}

		public void CopyTo(CmsRecipient[] array, int arrayIndex)
		{
			if (array == null)
			{
				throw new ArgumentNullException("array");
			}
			if (arrayIndex < 0 || arrayIndex + Count > array.Length)
			{
				throw new ArgumentOutOfRangeException("arrayIndex");
			}
			recipients.CopyTo(array, arrayIndex);
		}

		public bool Remove(CmsRecipient recipient)
		{
			if (recipient == null)
			{
				throw new ArgumentNullException("recipient");
			}
			return recipients.Remove(recipient);
		}

		public IEnumerator<CmsRecipient> GetEnumerator()
		{
			return recipients.GetEnumerator();
		}

		IEnumerator IEnumerable.GetEnumerator()
		{
			return recipients.GetEnumerator();
		}
	}
	public class CmsSigner
	{
		public Org.BouncyCastle.X509.X509Certificate Certificate { get; private set; }

		public X509CertificateChain CertificateChain { get; private set; }

		public DigestAlgorithm DigestAlgorithm { get; set; }

		public AsymmetricKeyParameter PrivateKey { get; private set; }

		public Org.BouncyCastle.Asn1.Cms.AttributeTable SignedAttributes { get; set; }

		public Org.BouncyCastle.Asn1.Cms.AttributeTable UnsignedAttributes { get; set; }

		private CmsSigner()
		{
			UnsignedAttributes = new Org.BouncyCastle.Asn1.Cms.AttributeTable(new Dictionary<DerObjectIdentifier, Asn1Encodable>());
			SignedAttributes = new Org.BouncyCastle.Asn1.Cms.AttributeTable(new Dictionary<DerObjectIdentifier, Asn1Encodable>());
			DigestAlgorithm = DigestAlgorithm.Sha1;
		}

		private static bool CanSign(Org.BouncyCastle.X509.X509Certificate certificate)
		{
			X509KeyUsageFlags keyUsageFlags = certificate.GetKeyUsageFlags();
			if (keyUsageFlags != X509KeyUsageFlags.None && (keyUsageFlags & (X509KeyUsageFlags.NonRepudiation | X509KeyUsageFlags.DigitalSignature)) == 0)
			{
				return false;
			}
			return true;
		}

		private static void CheckCertificateCanBeUsedForSigning(Org.BouncyCastle.X509.X509Certificate certificate)
		{
			if (!CanSign(certificate))
			{
				throw new ArgumentException("The certificate cannot be used for signing.", "certificate");
			}
		}

		public CmsSigner(IEnumerable<Org.BouncyCastle.X509.X509Certificate> chain, AsymmetricKeyParameter key)
			: this()
		{
			if (chain == null)
			{
				throw new ArgumentNullException("chain");
			}
			if (key == null)
			{
				throw new ArgumentNullException("key");
			}
			CertificateChain = new X509CertificateChain(chain);
			if (CertificateChain.Count == 0)
			{
				throw new ArgumentException("The certificate chain was empty.", "chain");
			}
			CheckCertificateCanBeUsedForSigning(CertificateChain[0]);
			if (!key.IsPrivate)
			{
				throw new ArgumentException("The key must be a private key.", "key");
			}
			Certificate = CertificateChain[0];
			PrivateKey = key;
		}

		public CmsSigner(Org.BouncyCastle.X509.X509Certificate certificate, AsymmetricKeyParameter key)
			: this()
		{
			if (certificate == null)
			{
				throw new ArgumentNullException("certificate");
			}
			CheckCertificateCanBeUsedForSigning(certificate);
			if (key == null)
			{
				throw new ArgumentNullException("key");
			}
			if (!key.IsPrivate)
			{
				throw new ArgumentException("The key must be a private key.", "key");
			}
			CertificateChain = new X509CertificateChain();
			CertificateChain.Add(certificate);
			Certificate = certificate;
			PrivateKey = key;
		}

		private void LoadPkcs12(Stream stream, string password)
		{
			Pkcs12Store pkcs12Store = new Pkcs12Store(stream, password.ToCharArray());
			bool flag = false;
			foreach (string alias in pkcs12Store.Aliases)
			{
				if (!pkcs12Store.IsKeyEntry(alias))
				{
					continue;
				}
				X509CertificateEntry[] certificateChain = pkcs12Store.GetCertificateChain(alias);
				AsymmetricKeyEntry key = pkcs12Store.GetKey(alias);
				if (!key.Key.IsPrivate)
				{
					continue;
				}
				flag = true;
				if (certificateChain.Length != 0 && CanSign(certificateChain[0].Certificate))
				{
					CertificateChain = new X509CertificateChain();
					Certificate = certificateChain[0].Certificate;
					PrivateKey = key.Key;
					X509CertificateEntry[] array = certificateChain;
					foreach (X509CertificateEntry x509CertificateEntry in array)
					{
						CertificateChain.Add(x509CertificateEntry.Certificate);
					}
					return;
				}
			}
			if (!flag)
			{
				throw new ArgumentException("The stream did not contain a private key.", "stream");
			}
			throw new ArgumentException("The stream did not contain a certificate that could be used to create digital signatures.", "stream");
		}

		public CmsSigner(Stream stream, string password)
			: this()
		{
			if (stream == null)
			{
				throw new ArgumentNullException("stream");
			}
			if (password == null)
			{
				throw new ArgumentNullException("password");
			}
			LoadPkcs12(stream, password);
		}

		public CmsSigner(string fileName, string password)
			: this()
		{
			if (fileName == null)
			{
				throw new ArgumentNullException("fileName");
			}
			if (password == null)
			{
				throw new ArgumentNullException("password");
			}
			using FileStream stream = File.OpenRead(fileName);
			LoadPkcs12(stream, password);
		}

		public CmsSigner(X509Certificate2 certificate)
			: this()
		{
			if (certificate == null)
			{
				throw new ArgumentNullException("certificate");
			}
			if (!certificate.HasPrivateKey)
			{
				throw new ArgumentException("The certificate does not contain a private key.", "certificate");
			}
			Org.BouncyCastle.X509.X509Certificate certificate2 = certificate.AsBouncyCastleCertificate();
			AsymmetricKeyParameter privateKey = certificate.PrivateKey.AsAsymmetricKeyParameter();
			CheckCertificateCanBeUsedForSigning(certificate2);
			CertificateChain = new X509CertificateChain();
			CertificateChain.Add(certificate2);
			Certificate = certificate2;
			PrivateKey = privateKey;
		}
	}
	public abstract class CryptographyContext : IDisposable
	{
		private const string SubclassAndRegisterFormat = "You need to subclass {0} and then register it with MimeKit.Cryptography.CryptographyContext.Register().";

		private static Func<SecureMimeContext> SecureMimeContextFactory;

		private static Func<OpenPgpContext> OpenPgpContextFactory;

		private static readonly object mutex = new object();

		private EncryptionAlgorithm[] encryptionAlgorithmRank;

		private DigestAlgorithm[] digestAlgorithmRank;

		private int enabledEncryptionAlgorithms;

		private int enabledDigestAlgorithms;

		public abstract string SignatureProtocol { get; }

		public abstract string EncryptionProtocol { get; }

		public abstract string KeyExchangeProtocol { get; }

		protected EncryptionAlgorithm[] EncryptionAlgorithmRank
		{
			get
			{
				return encryptionAlgorithmRank;
			}
			set
			{
				if (value == null)
				{
					throw new ArgumentNullException("value");
				}
				if (value.Length == 0)
				{
					throw new ArgumentException("The array of encryption algorithms cannot be empty.", "value");
				}
				encryptionAlgorithmRank = value;
			}
		}

		public EncryptionAlgorithm[] EnabledEncryptionAlgorithms
		{
			get
			{
				List<EncryptionAlgorithm> list = new List<EncryptionAlgorithm>();
				EncryptionAlgorithm[] array = EncryptionAlgorithmRank;
				foreach (EncryptionAlgorithm encryptionAlgorithm in array)
				{
					if (IsEnabled(encryptionAlgorithm))
					{
						list.Add(encryptionAlgorithm);
					}
				}
				return list.ToArray();
			}
		}

		protected DigestAlgorithm[] DigestAlgorithmRank
		{
			get
			{
				return digestAlgorithmRank;
			}
			set
			{
				if (value == null)
				{
					throw new ArgumentNullException("value");
				}
				if (value.Length == 0)
				{
					throw new ArgumentException("The array of digest algorithms cannot be empty.", "value");
				}
				digestAlgorithmRank = value;
			}
		}

		public DigestAlgorithm[] EnabledDigestAlgorithms
		{
			get
			{
				List<DigestAlgorithm> list = new List<DigestAlgorithm>();
				DigestAlgorithm[] array = DigestAlgorithmRank;
				foreach (DigestAlgorithm digestAlgorithm in array)
				{
					if (IsEnabled(digestAlgorithm))
					{
						list.Add(digestAlgorithm);
					}
				}
				return list.ToArray();
			}
		}

		protected CryptographyContext()
		{
			encryptionAlgorithmRank = new EncryptionAlgorithm[1] { EncryptionAlgorithm.TripleDes };
			Enable(EncryptionAlgorithm.TripleDes);
			digestAlgorithmRank = new DigestAlgorithm[1] { DigestAlgorithm.Sha1 };
			Enable(DigestAlgorithm.Sha1);
		}

		public void Enable(EncryptionAlgorithm algorithm)
		{
			enabledEncryptionAlgorithms |= 1 << (int)algorithm;
		}

		public void Disable(EncryptionAlgorithm algorithm)
		{
			enabledEncryptionAlgorithms &= ~(1 << (int)algorithm);
		}

		public bool IsEnabled(EncryptionAlgorithm algorithm)
		{
			return (enabledEncryptionAlgorithms & (1 << (int)algorithm)) != 0;
		}

		public void Enable(DigestAlgorithm algorithm)
		{
			enabledDigestAlgorithms |= 1 << (int)algorithm;
		}

		public void Disable(DigestAlgorithm algorithm)
		{
			enabledDigestAlgorithms &= ~(1 << (int)algorithm);
		}

		public bool IsEnabled(DigestAlgorithm algorithm)
		{
			return (enabledDigestAlgorithms & (1 << (int)algorithm)) != 0;
		}

		public abstract bool Supports(string protocol);

		public abstract string GetDigestAlgorithmName(DigestAlgorithm micalg);

		public abstract DigestAlgorithm GetDigestAlgorithm(string micalg);

		public abstract bool CanSign(MailboxAddress signer);

		public abstract bool CanEncrypt(MailboxAddress mailbox);

		public abstract MimePart Sign(MailboxAddress signer, DigestAlgorithm digestAlgo, Stream content);

		public abstract DigitalSignatureCollection Verify(Stream content, Stream signatureData, CancellationToken cancellationToken = default(CancellationToken));

		public abstract Task<DigitalSignatureCollection> VerifyAsync(Stream content, Stream signatureData, CancellationToken cancellationToken = default(CancellationToken));

		public abstract MimePart Encrypt(IEnumerable<MailboxAddress> recipients, Stream content);

		public abstract MimeEntity Decrypt(Stream encryptedData, CancellationToken cancellationToken = default(CancellationToken));

		public abstract void Import(Stream stream);

		public abstract MimePart Export(IEnumerable<MailboxAddress> mailboxes);

		protected virtual void Dispose(bool disposing)
		{
		}

		public void Dispose()
		{
			Dispose(disposing: true);
			GC.SuppressFinalize(this);
		}

		public static CryptographyContext Create(string protocol)
		{
			if (protocol == null)
			{
				throw new ArgumentNullException("protocol");
			}
			protocol = protocol.ToLowerInvariant();
			lock (mutex)
			{
				switch (protocol)
				{
				case "application/x-pkcs7-signature":
				case "application/pkcs7-signature":
				case "application/x-pkcs7-mime":
				case "application/pkcs7-mime":
				case "application/x-pkcs7-keys":
				case "application/pkcs7-keys":
					if (SecureMimeContextFactory != null)
					{
						return SecureMimeContextFactory();
					}
					if (!SqliteCertificateDatabase.IsAvailable)
					{
						throw new NotSupportedException(string.Format("SQLite is not available. Either install the {0} nuget or subclass MimeKit.Cryptography.SecureMimeContext and register it with MimeKit.Cryptography.CryptographyContext.Register().", "System.Data.SQLite"));
					}
					return new DefaultSecureMimeContext();
				case "application/x-pgp-signature":
				case "application/pgp-signature":
				case "application/x-pgp-encrypted":
				case "application/pgp-encrypted":
				case "application/x-pgp-keys":
				case "application/pgp-keys":
					if (OpenPgpContextFactory != null)
					{
						return OpenPgpContextFactory();
					}
					throw new NotSupportedException(string.Format("You need to subclass {0} and then register it with MimeKit.Cryptography.CryptographyContext.Register().", "MimeKit.Cryptography.OpenPgpContext or MimeKit.Cryptography.GnuPGContext"));
				default:
					throw new NotSupportedException();
				}
			}
		}

		public static void Register(Type type)
		{
			if (type == null)
			{
				throw new ArgumentNullException("type");
			}
			ConstructorInfo ctor = type.GetConstructor(new Type[0]);
			if (ctor == null)
			{
				throw new ArgumentException("The specified type must have a parameterless constructor.", "type");
			}
			if (type.IsSubclassOf(typeof(SecureMimeContext)))
			{
				lock (mutex)
				{
					SecureMimeContextFactory = () => (SecureMimeContext)ctor.Invoke(new object[0]);
					return;
				}
			}
			if (type.IsSubclassOf(typeof(OpenPgpContext)))
			{
				lock (mutex)
				{
					OpenPgpContextFactory = () => (OpenPgpContext)ctor.Invoke(new object[0]);
					return;
				}
			}
			throw new ArgumentException("The specified type must be a subclass of SecureMimeContext or OpenPgpContext.", "type");
		}

		public static void Register(Func<SecureMimeContext> factory)
		{
			if (factory == null)
			{
				throw new ArgumentNullException("factory");
			}
			lock (mutex)
			{
				SecureMimeContextFactory = factory;
			}
		}

		public static void Register(Func<OpenPgpContext> factory)
		{
			if (factory == null)
			{
				throw new ArgumentNullException("factory");
			}
			lock (mutex)
			{
				OpenPgpContextFactory = factory;
			}
		}
	}
	internal static class DbExtensions
	{
		public static int AddParameterWithValue(this DbCommand command, string name, object value)
		{
			DbParameter dbParameter = command.CreateParameter();
			dbParameter.ParameterName = name;
			dbParameter.Value = value;
			return command.Parameters.Add(dbParameter);
		}
	}
	public class DefaultSecureMimeContext : BouncyCastleSecureMimeContext
	{
		private const X509CertificateRecordFields CmsRecipientFields = X509CertificateRecordFields.Algorithms | X509CertificateRecordFields.Certificate;

		private const X509CertificateRecordFields CmsSignerFields = X509CertificateRecordFields.Certificate | X509CertificateRecordFields.PrivateKey;

		private const X509CertificateRecordFields AlgorithmFields = X509CertificateRecordFields.Id | X509CertificateRecordFields.Algorithms | X509CertificateRecordFields.AlgorithmsUpdated;

		private const X509CertificateRecordFields ImportPkcs12Fields = X509CertificateRecordFields.Id | X509CertificateRecordFields.Trusted | X509CertificateRecordFields.Algorithms | X509CertificateRecordFields.AlgorithmsUpdated | X509CertificateRecordFields.PrivateKey;

		public static readonly string DefaultDatabasePath;

		private readonly IX509CertificateDatabase dbase;

		static DefaultSecureMimeContext()
		{
			string path = ((Path.DirectorySeparatorChar != '\\') ? Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.MyDocuments), ".mimekit") : Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.ApplicationData), "Roaming\\mimekit"));
			DefaultDatabasePath = Path.Combine(path, "smime.db");
		}

		public DefaultSecureMimeContext(string fileName, string password)
		{
			if (fileName == null)
			{
				throw new ArgumentNullException("fileName");
			}
			if (password == null)
			{
				throw new ArgumentNullException("password");
			}
			if (!SqliteCertificateDatabase.IsAvailable)
			{
				throw new NotSupportedException("Mono.Data.Sqlite is not available.");
			}
			string directoryName = Path.GetDirectoryName(fileName);
			File.Exists(fileName);
			if (!string.IsNullOrEmpty(directoryName) && !Directory.Exists(directoryName))
			{
				Directory.CreateDirectory(directoryName);
			}
			dbase = new SqliteCertificateDatabase(fileName, password);
		}

		public DefaultSecureMimeContext(string password)
			: this(DefaultDatabasePath, password)
		{
		}

		public DefaultSecureMimeContext()
			: this(DefaultDatabasePath, "no.secret")
		{
		}

		public DefaultSecureMimeContext(IX509CertificateDatabase database)
		{
			if (database == null)
			{
				throw new ArgumentNullException("database");
			}
			dbase = database;
		}

		public override bool CanSign(MailboxAddress signer)
		{
			if (signer == null)
			{
				throw new ArgumentNullException("signer");
			}
			foreach (X509CertificateRecord item in dbase.Find(signer, DateTime.UtcNow, requirePrivateKey: true, X509CertificateRecordFields.Certificate | X509CertificateRecordFields.PrivateKey))
			{
				if (item.KeyUsage == X509KeyUsageFlags.None || (item.KeyUsage & (X509KeyUsageFlags.NonRepudiation | X509KeyUsageFlags.DigitalSignature)) != X509KeyUsageFlags.None)
				{
					return true;
				}
			}
			return false;
		}

		public override bool CanEncrypt(MailboxAddress mailbox)
		{
			if (mailbox == null)
			{
				throw new ArgumentNullException("mailbox");
			}
			foreach (X509CertificateRecord item in dbase.Find(mailbox, DateTime.UtcNow, requirePrivateKey: false, X509CertificateRecordFields.Algorithms | X509CertificateRecordFields.Certificate))
			{
				if (item.KeyUsage == X509KeyUsageFlags.None || (item.KeyUsage & X509KeyUsageFlags.KeyEncipherment) != X509KeyUsageFlags.None)
				{
					return true;
				}
			}
			return false;
		}

		protected override Org.BouncyCastle.X509.X509Certificate GetCertificate(IX509Selector selector)
		{
			return dbase.FindCertificates(selector).FirstOrDefault();
		}

		protected override AsymmetricKeyParameter GetPrivateKey(IX509Selector selector)
		{
			return dbase.FindPrivateKeys(selector).FirstOrDefault();
		}

		protected override HashSet GetTrustedAnchors()
		{
			HashSet hashSet = new HashSet();
			X509CertStoreSelector x509CertStoreSelector = new X509CertStoreSelector();
			x509CertStoreSelector.KeyUsage = new bool[9] { false, false, false, false, false, true, false, false, false };
			foreach (X509CertificateRecord item in dbase.Find(x509CertStoreSelector, trustedOnly: true, X509CertificateRecordFields.Certificate))
			{
				hashSet.Add(new TrustAnchor(item.Certificate, null));
			}
			return hashSet;
		}

		protected override IX509Store GetIntermediateCertificates()
		{
			return dbase;
		}

		protected override IX509Store GetCertificateRevocationLists()
		{
			return dbase.GetCrlStore();
		}

		protected override DateTime GetNextCertificateRevocationListUpdate(X509Name issuer)
		{
			DateTime minValue = DateTime.MinValue;
			DateTime dateTime = minValue.ToUniversalTime();
			foreach (X509CrlRecord item in dbase.Find(issuer, X509CrlRecordFields.NextUpdate))
			{
				dateTime = ((item.NextUpdate > dateTime) ? item.NextUpdate : dateTime);
			}
			return dateTime;
		}

		protected override CmsRecipient GetCmsRecipient(MailboxAddress mailbox)
		{
			foreach (X509CertificateRecord item in dbase.Find(mailbox, DateTime.UtcNow, requirePrivateKey: false, X509CertificateRecordFields.Algorithms | X509CertificateRecordFields.Certificate))
			{
				if (item.KeyUsage == X509KeyUsageFlags.None || (item.KeyUsage & X509KeyUsageFlags.KeyEncipherment) != X509KeyUsageFlags.None)
				{
					CmsRecipient cmsRecipient = new CmsRecipient(item.Certificate);
					if (item.Algorithms != null)
					{
						cmsRecipient.EncryptionAlgorithms = item.Algorithms;
					}
					return cmsRecipient;
				}
			}
			throw new CertificateNotFoundException(mailbox, "A valid certificate could not be found.");
		}

		protected override CmsSigner GetCmsSigner(MailboxAddress mailbox, DigestAlgorithm digestAlgo)
		{
			foreach (X509CertificateRecord item in dbase.Find(mailbox, DateTime.UtcNow, requirePrivateKey: true, X509CertificateRecordFields.Certificate | X509CertificateRecordFields.PrivateKey))
			{
				if (item.KeyUsage == X509KeyUsageFlags.None || (item.KeyUsage & (X509KeyUsageFlags.NonRepudiation | X509KeyUsageFlags.DigitalSignature)) != X509KeyUsageFlags.None)
				{
					return new CmsSigner(item.Certificate, item.PrivateKey)
					{
						DigestAlgorithm = digestAlgo
					};
				}
			}
			throw new CertificateNotFoundException(mailbox, "A valid signing certificate could not be found.");
		}

		protected override void UpdateSecureMimeCapabilities(Org.BouncyCastle.X509.X509Certificate certificate, EncryptionAlgorithm[] algorithms, DateTime timestamp)
		{
			X509CertificateRecord x509CertificateRecord;
			if ((x509CertificateRecord = dbase.Find(certificate, X509CertificateRecordFields.Id | X509CertificateRecordFields.Algorithms | X509CertificateRecordFields.AlgorithmsUpdated)) == null)
			{
				x509CertificateRecord = new X509CertificateRecord(certificate);
				x509CertificateRecord.AlgorithmsUpdated = timestamp;
				x509CertificateRecord.Algorithms = algorithms;
				dbase.Add(x509CertificateRecord);
			}
			else if (timestamp > x509CertificateRecord.AlgorithmsUpdated)
			{
				x509CertificateRecord.AlgorithmsUpdated = timestamp;
				x509CertificateRecord.Algorithms = algorithms;
				dbase.Update(x509CertificateRecord, X509CertificateRecordFields.Id | X509CertificateRecordFields.Algorithms | X509CertificateRecordFields.AlgorithmsUpdated);
			}
		}

		public override void Import(Org.BouncyCastle.X509.X509Certificate certificate)
		{
			if (certificate == null)
			{
				throw new ArgumentNullException("certificate");
			}
			if (dbase.Find(certificate, X509CertificateRecordFields.Id) == null)
			{
				dbase.Add(new X509CertificateRecord(certificate));
			}
		}

		public override void Import(X509Crl crl)
		{
			if (crl == null)
			{
				throw new ArgumentNullException("crl");
			}
			if (dbase.Find(crl, X509CrlRecordFields.Id) != null)
			{
				return;
			}
			List<X509CrlRecord> list = new List<X509CrlRecord>();
			bool flag = crl.IsDelta();
			foreach (X509CrlRecord item in dbase.Find(crl.IssuerDN, ~X509CrlRecordFields.Crl))
			{
				if (!item.IsDelta && item.ThisUpdate >= crl.ThisUpdate)
				{
					return;
				}
				if (!flag)
				{
					list.Add(item);
				}
			}
			foreach (X509CrlRecord item2 in list)
			{
				dbase.Remove(item2);
			}
			dbase.Add(new X509CrlRecord(crl));
		}

		public override void Import(Stream stream, string password)
		{
			if (stream == null)
			{
				throw new ArgumentNullException("stream");
			}
			if (password == null)
			{
				throw new ArgumentNullException("password");
			}
			Pkcs12Store pkcs12Store = new Pkcs12Store(stream, password.ToCharArray());
			EncryptionAlgorithm[] algorithms = base.EnabledEncryptionAlgorithms;
			foreach (string alias in pkcs12Store.Aliases)
			{
				if (pkcs12Store.IsKeyEntry(alias))
				{
					X509CertificateEntry[] certificateChain = pkcs12Store.GetCertificateChain(alias);
					AsymmetricKeyEntry key = pkcs12Store.GetKey(alias);
					int num = 0;
					if (key.Key.IsPrivate)
					{
						X509CertificateRecord x509CertificateRecord;
						if ((x509CertificateRecord = dbase.Find(certificateChain[0].Certificate, X509CertificateRecordFields.Id | X509CertificateRecordFields.Trusted | X509CertificateRecordFields.Algorithms | X509CertificateRecordFields.AlgorithmsUpdated | X509CertificateRecordFields.PrivateKey)) == null)
						{
							x509CertificateRecord = new X509CertificateRecord(certificateChain[0].Certificate, key.Key);
							x509CertificateRecord.AlgorithmsUpdated = DateTime.UtcNow;
							x509CertificateRecord.Algorithms = algorithms;
							x509CertificateRecord.IsTrusted = true;
							dbase.Add(x509CertificateRecord);
						}
						else
						{
							x509CertificateRecord.AlgorithmsUpdated = DateTime.UtcNow;
							x509CertificateRecord.Algorithms = algorithms;
							if (x509CertificateRecord.PrivateKey == null)
							{
								x509CertificateRecord.PrivateKey = key.Key;
							}
							x509CertificateRecord.IsTrusted = true;
							dbase.Update(x509CertificateRecord, X509CertificateRecordFields.Id | X509CertificateRecordFields.Trusted | X509CertificateRecordFields.Algorithms | X509CertificateRecordFields.AlgorithmsUpdated | X509CertificateRecordFields.PrivateKey);
						}
						num = 1;
					}
					for (int i = num; i < certificateChain.Length; i++)
					{
						X509CertificateRecord x509CertificateRecord;
						if ((x509CertificateRecord = dbase.Find(certificateChain[i].Certificate, X509CertificateRecordFields.Id)) == null)
						{
							dbase.Add(new X509CertificateRecord(certificateChain[i].Certificate)
							{
								IsTrusted = true
							});
						}
					}
				}
				else if (pkcs12Store.IsCertificateEntry(alias))
				{
					X509CertificateEntry certificate = pkcs12Store.GetCertificate(alias);
					X509CertificateRecord x509CertificateRecord;
					if ((x509CertificateRecord = dbase.Find(certificate.Certificate, X509CertificateRecordFields.Id)) == null)
					{
						dbase.Add(new X509CertificateRecord(certificate.Certificate)
						{
							IsTrusted = true
						});
					}
				}
			}
		}

		public void Import(Stream stream, bool trusted)
		{
			if (stream == null)
			{
				throw new ArgumentNullException("stream");
			}
			foreach (Org.BouncyCastle.X509.X509Certificate item in new X509CertificateParser().ReadCertificates(stream))
			{
				X509CertificateRecord x509CertificateRecord;
				if ((x509CertificateRecord = dbase.Find(item, X509CertificateRecordFields.Id | X509CertificateRecordFields.Trusted)) != null)
				{
					if (trusted && !x509CertificateRecord.IsTrusted)
					{
						x509CertificateRecord.IsTrusted = trusted;
						dbase.Update(x509CertificateRecord, X509CertificateRecordFields.Trusted);
					}
				}
				else
				{
					x509CertificateRecord = new X509CertificateRecord(item);
					x509CertificateRecord.IsTrusted = trusted;
					dbase.Add(x509CertificateRecord);
				}
			}
		}

		protected override void Dispose(bool disposing)
		{
			dbase.Dispose();
			base.Dispose(disposing);
		}
	}
