	internal class DkimHashStream : Stream
	{
		private IDigest digest;

		private bool disposed;

		private int length;

		private int max;

		public override bool CanRead => false;

		public override bool CanWrite => true;

		public override bool CanSeek => false;

		public override bool CanTimeout => false;

		public override long Length
		{
			get
			{
				CheckDisposed();
				return length;
			}
		}

		public override long Position
		{
			get
			{
				return length;
			}
			set
			{
				Seek(value, SeekOrigin.Begin);
			}
		}

		public DkimHashStream(DkimSignatureAlgorithm algorithm, int maxLength = -1)
		{
			if (algorithm == DkimSignatureAlgorithm.RsaSha256)
			{
				digest = new Sha256Digest();
			}
			else
			{
				digest = new Sha1Digest();
			}
			max = maxLength;
		}

		public byte[] GenerateHash()
		{
			byte[] array = new byte[digest.GetDigestSize()];
			digest.DoFinal(array, 0);
			return array;
		}

		private void CheckDisposed()
		{
			if (disposed)
			{
				throw new ObjectDisposedException("DkimHashStream");
			}
		}

		private static void ValidateArguments(byte[] buffer, int offset, int count)
		{
			if (buffer == null)
			{
				throw new ArgumentNullException("buffer");
			}
			if (offset < 0 || offset > buffer.Length)
			{
				throw new ArgumentOutOfRangeException("offset");
			}
			if (count < 0 || count > buffer.Length - offset)
			{
				throw new ArgumentOutOfRangeException("count");
			}
		}

		public override int Read(byte[] buffer, int offset, int count)
		{
			CheckDisposed();
			throw new NotSupportedException("The stream does not support reading");
		}

		public override void Write(byte[] buffer, int offset, int count)
		{
			CheckDisposed();
			ValidateArguments(buffer, offset, count);
			int num = ((max >= 0 && length + count > max) ? (max - length) : count);
			digest.BlockUpdate(buffer, offset, num);
			length += num;
		}

		public override long Seek(long offset, SeekOrigin origin)
		{
			CheckDisposed();
			throw new NotSupportedException("The stream does not support seeking.");
		}

		public override void Flush()
		{
			CheckDisposed();
		}

		public override void SetLength(long value)
		{
			CheckDisposed();
			throw new NotSupportedException("The stream does not support setting the length.");
		}

		protected override void Dispose(bool disposing)
		{
			if (disposing && !disposed)
			{
				disposed = true;
			}
			base.Dispose(disposing);
		}
	}
	internal class DkimRelaxedBodyFilter : DkimBodyFilter
	{
		private bool lwsp;

		private bool cr;

		public DkimRelaxedBodyFilter()
		{
			LastWasNewLine = true;
			IsEmptyLine = true;
		}

		private unsafe int Filter(byte* inbuf, int length, byte* outbuf)
		{
			byte* ptr = inbuf + length;
			byte* ptr2 = outbuf;
			byte* ptr3 = inbuf;
			int num = 0;
			for (; ptr3 < ptr; ptr3++)
			{
				if (*ptr3 == 10)
				{
					if (IsEmptyLine)
					{
						EmptyLines++;
					}
					else
					{
						if (cr)
						{
							*(ptr2++) = 13;
							num++;
						}
						*(ptr2++) = 10;
						LastWasNewLine = true;
						IsEmptyLine = true;
						num++;
					}
					lwsp = false;
					cr = false;
					continue;
				}
				if (cr)
				{
					*(ptr2++) = 13;
					cr = false;
					num++;
				}
				if (*ptr3 == 13)
				{
					lwsp = false;
					cr = true;
					continue;
				}
				if ((*ptr3).IsBlank())
				{
					lwsp = true;
					continue;
				}
				if (EmptyLines > 0)
				{
					while (EmptyLines > 0)
					{
						*(ptr2++) = 13;
						*(ptr2++) = 10;
						EmptyLines--;
						num += 2;
					}
				}
				if (lwsp)
				{
					*(ptr2++) = 32;
					lwsp = false;
					num++;
				}
				LastWasNewLine = false;
				IsEmptyLine = false;
				*(ptr2++) = *ptr3;
				num++;
			}
			return num;
		}

		protected unsafe override byte[] Filter(byte[] input, int startIndex, int length, out int outputIndex, out int outputLength, bool flush)
		{
			EnsureOutputSize(length + (lwsp ? 1 : 0) + EmptyLines * 2 + (cr ? 1 : 0) + 1, keep: false);
			fixed (byte* ptr = input)
			{
				fixed (byte* outputBuffer = base.OutputBuffer)
				{
					outputLength = Filter(ptr + startIndex, length, outputBuffer);
				}
			}
			outputIndex = 0;
			return base.OutputBuffer;
		}

		public override void Reset()
		{
			LastWasNewLine = true;
			IsEmptyLine = true;
			EmptyLines = 0;
			lwsp = false;
			cr = false;
			base.Reset();
		}
	}
	public enum DkimSignatureAlgorithm
	{
		RsaSha1,
		RsaSha256
	}
	internal class DkimSignatureStream : Stream
	{
		private bool disposed;

		private long length;

		public ISigner Signer { get; private set; }

		public override bool CanRead => false;

		public override bool CanWrite => true;

		public override bool CanSeek => false;

		public override bool CanTimeout => false;

		public override long Length
		{
			get
			{
				CheckDisposed();
				return length;
			}
		}

		public override long Position
		{
			get
			{
				return length;
			}
			set
			{
				Seek(value, SeekOrigin.Begin);
			}
		}

		public DkimSignatureStream(ISigner signer)
		{
			if (signer == null)
			{
				throw new ArgumentNullException("signer");
			}
			Signer = signer;
		}

		public byte[] GenerateSignature()
		{
			return Signer.GenerateSignature();
		}

		public bool VerifySignature(string signature)
		{
			if (signature == null)
			{
				throw new ArgumentNullException("signature");
			}
			byte[] signature2 = Convert.FromBase64String(signature);
			return Signer.VerifySignature(signature2);
		}

		private void CheckDisposed()
		{
			if (disposed)
			{
				throw new ObjectDisposedException("DkimSignatureStream");
			}
		}

		private static void ValidateArguments(byte[] buffer, int offset, int count)
		{
			if (buffer == null)
			{
				throw new ArgumentNullException("buffer");
			}
			if (offset < 0 || offset > buffer.Length)
			{
				throw new ArgumentOutOfRangeException("offset");
			}
			if (count < 0 || count > buffer.Length - offset)
			{
				throw new ArgumentOutOfRangeException("count");
			}
		}

		public override int Read(byte[] buffer, int offset, int count)
		{
			CheckDisposed();
			throw new NotSupportedException("The stream does not support reading");
		}

		public override void Write(byte[] buffer, int offset, int count)
		{
			CheckDisposed();
			ValidateArguments(buffer, offset, count);
			Signer.BlockUpdate(buffer, offset, count);
			length += count;
		}

		public override long Seek(long offset, SeekOrigin origin)
		{
			CheckDisposed();
			throw new NotSupportedException("The stream does not support seeking.");
		}

		public override void Flush()
		{
			CheckDisposed();
		}

		public override void SetLength(long value)
		{
			CheckDisposed();
			throw new NotSupportedException("The stream does not support setting the length.");
		}

		protected override void Dispose(bool disposing)
		{
			if (disposing && !disposed)
			{
				disposed = true;
			}
			base.Dispose(disposing);
		}
	}
	public class DkimSigner
	{
		protected AsymmetricKeyParameter PrivateKey { get; set; }

		public string Domain { get; private set; }

		public string Selector { get; private set; }

		public string AgentOrUserIdentifier { get; set; }

		public DkimSignatureAlgorithm SignatureAlgorithm { get; set; }

		public string QueryMethod { get; set; }

		public virtual ISigner DigestSigner
		{
			get
			{
				DerObjectIdentifier id = ((SignatureAlgorithm != DkimSignatureAlgorithm.RsaSha256) ? PkcsObjectIdentifiers.Sha1WithRsaEncryption : PkcsObjectIdentifiers.Sha256WithRsaEncryption);
				ISigner signer = SignerUtilities.GetSigner(id);
				signer.Init(forSigning: true, PrivateKey);
				return signer;
			}
		}

		protected DkimSigner(string domain, string selector, DkimSignatureAlgorithm algorithm = DkimSignatureAlgorithm.RsaSha256)
		{
			if (domain == null)
			{
				throw new ArgumentNullException("domain");
			}
			if (selector == null)
			{
				throw new ArgumentNullException("selector");
			}
			SignatureAlgorithm = algorithm;
			Selector = selector;
			Domain = domain;
		}

		public DkimSigner(AsymmetricKeyParameter key, string domain, string selector, DkimSignatureAlgorithm algorithm = DkimSignatureAlgorithm.RsaSha256)
		{
			if (key == null)
			{
				throw new ArgumentNullException("key");
			}
			if (domain == null)
			{
				throw new ArgumentNullException("domain");
			}
			if (selector == null)
			{
				throw new ArgumentNullException("selector");
			}
			if (!key.IsPrivate)
			{
				throw new ArgumentException("The key must be a private key.", "key");
			}
			SignatureAlgorithm = algorithm;
			Selector = selector;
			PrivateKey = key;
			Domain = domain;
		}

		private static AsymmetricKeyParameter LoadPrivateKey(Stream stream)
		{
			AsymmetricKeyParameter asymmetricKeyParameter = null;
			using (StreamReader reader = new StreamReader(stream))
			{
				object obj = new PemReader(reader).ReadObject();
				if (obj != null)
				{
					asymmetricKeyParameter = obj as AsymmetricKeyParameter;
					if (asymmetricKeyParameter == null && obj is AsymmetricCipherKeyPair asymmetricCipherKeyPair)
					{
						asymmetricKeyParameter = asymmetricCipherKeyPair.Private;
					}
				}
			}
			if (asymmetricKeyParameter == null || !asymmetricKeyParameter.IsPrivate)
			{
				throw new FormatException("Private key not found.");
			}
			return asymmetricKeyParameter;
		}

		public DkimSigner(string fileName, string domain, string selector, DkimSignatureAlgorithm algorithm = DkimSignatureAlgorithm.RsaSha256)
		{
			if (fileName == null)
			{
				throw new ArgumentNullException("fileName");
			}
			if (fileName.Length == 0)
			{
				throw new ArgumentException("The file name cannot be empty.", "fileName");
			}
			if (domain == null)
			{
				throw new ArgumentNullException("domain");
			}
			if (selector == null)
			{
				throw new ArgumentNullException("selector");
			}
			using (FileStream stream = File.OpenRead(fileName))
			{
				PrivateKey = LoadPrivateKey(stream);
			}
			SignatureAlgorithm = algorithm;
			Selector = selector;
			Domain = domain;
		}

		public DkimSigner(Stream stream, string domain, string selector, DkimSignatureAlgorithm algorithm = DkimSignatureAlgorithm.RsaSha256)
		{
			if (stream == null)
			{
				throw new ArgumentNullException("stream");
			}
			if (domain == null)
			{
				throw new ArgumentNullException("domain");
			}
			if (selector == null)
			{
				throw new ArgumentNullException("selector");
			}
			PrivateKey = LoadPrivateKey(stream);
			SignatureAlgorithm = algorithm;
			Selector = selector;
			Domain = domain;
		}
	}
	internal class DkimSimpleBodyFilter : DkimBodyFilter
	{
		public DkimSimpleBodyFilter()
		{
			LastWasNewLine = false;
			IsEmptyLine = true;
			EmptyLines = 0;
		}

		private unsafe int Filter(byte* inbuf, int length, byte* outbuf)
		{
			byte* ptr = inbuf + length;
			byte* ptr2 = outbuf;
			byte* ptr3 = inbuf;
			int num = 0;
			for (; ptr3 < ptr; ptr3++)
			{
				if (*ptr3 == 13)
				{
					if (!IsEmptyLine)
					{
						*(ptr2++) = *ptr3;
						num++;
					}
					continue;
				}
				if (*ptr3 == 10)
				{
					if (!IsEmptyLine)
					{
						*(ptr2++) = *ptr3;
						LastWasNewLine = true;
						IsEmptyLine = true;
						EmptyLines = 0;
						num++;
					}
					else
					{
						EmptyLines++;
					}
					continue;
				}
				if (EmptyLines > 0)
				{
					while (EmptyLines > 0)
					{
						*(ptr2++) = 13;
						*(ptr2++) = 10;
						EmptyLines--;
						num += 2;
					}
				}
				LastWasNewLine = false;
				IsEmptyLine = false;
				*(ptr2++) = *ptr3;
				num++;
			}
			return num;
		}

		protected unsafe override byte[] Filter(byte[] input, int startIndex, int length, out int outputIndex, out int outputLength, bool flush)
		{
			EnsureOutputSize(length + EmptyLines * 2 + 1, keep: false);
			fixed (byte* ptr = input)
			{
				fixed (byte* outputBuffer = base.OutputBuffer)
				{
					outputLength = Filter(ptr + startIndex, length, outputBuffer);
				}
			}
			outputIndex = 0;
			return base.OutputBuffer;
		}

		public override void Reset()
		{
			LastWasNewLine = false;
			IsEmptyLine = true;
			EmptyLines = 0;
			base.Reset();
		}
	}
