	internal class OpenPgpBlockFilter : MimeFilterBase
	{
		private readonly byte[] beginMarker;

		private readonly byte[] endMarker;

		private bool seenBeginMarker;

		private bool seenEndMarker;

		private bool midline;

		public OpenPgpBlockFilter(string beginMarker, string endMarker)
		{
			this.beginMarker = CharsetUtils.UTF8.GetBytes(beginMarker);
			this.endMarker = CharsetUtils.UTF8.GetBytes(endMarker);
		}

		private static bool IsMarker(byte[] input, int startIndex, byte[] marker)
		{
			int num = startIndex;
			for (int i = 0; i < marker.Length; i++)
			{
				if (input[num] != marker[i])
				{
					return false;
				}
				num++;
			}
			if (input[num] == 13)
			{
				num++;
			}
			return input[num] == 10;
		}

		private static bool IsPartialMatch(byte[] input, int startIndex, int endIndex, byte[] marker)
		{
			int num = startIndex;
			for (int i = 0; i < marker.Length; i++)
			{
				if (num >= endIndex)
				{
					break;
				}
				if (input[num] != marker[i])
				{
					return false;
				}
				num++;
			}
			if (num < endIndex && input[num] == 13)
			{
				num++;
			}
			return num == endIndex;
		}

		protected override byte[] Filter(byte[] input, int startIndex, int length, out int outputIndex, out int outputLength, bool flush)
		{
			int num = startIndex + length;
			int i = startIndex;
			outputIndex = startIndex;
			outputLength = 0;
			if (seenEndMarker || length == 0)
			{
				return input;
			}
			if (midline)
			{
				for (; i < num && input[i] != 10; i++)
				{
				}
				if (i == num)
				{
					if (seenBeginMarker)
					{
						outputLength = i - startIndex;
					}
					return input;
				}
				midline = false;
			}
			if (!seenBeginMarker)
			{
				do
				{
					int num2 = i;
					for (; i < num && input[i] != 10; i++)
					{
					}
					if (i == num)
					{
						if (IsPartialMatch(input, num2, i, beginMarker))
						{
							SaveRemainingInput(input, num2, i - num2);
						}
						else
						{
							midline = true;
						}
						return input;
					}
					i++;
					if (IsMarker(input, num2, beginMarker))
					{
						outputLength = i - num2;
						outputIndex = num2;
						seenBeginMarker = true;
						break;
					}
				}
				while (i < num);
				if (i == num)
				{
					return input;
				}
			}
			do
			{
				int num3 = i;
				for (; i < num && input[i] != 10; i++)
				{
				}
				if (i == num)
				{
					if (!flush)
					{
						if (IsPartialMatch(input, num3, i, endMarker))
						{
							SaveRemainingInput(input, num3, i - num3);
							outputLength = num3 - outputIndex;
						}
						else
						{
							outputLength = i - outputIndex;
							midline = true;
						}
						return input;
					}
					outputLength = i - outputIndex;
					return input;
				}
				i++;
				if (IsMarker(input, num3, endMarker))
				{
					seenEndMarker = true;
					break;
				}
			}
			while (i < num);
			outputLength = i - outputIndex;
			return input;
		}

		public override void Reset()
		{
			seenBeginMarker = false;
			seenEndMarker = false;
			midline = false;
			base.Reset();
		}
	}
	public abstract class OpenPgpContext : CryptographyContext
	{
		private class KeyRetrievalResults
		{
			public readonly PgpPublicKeyRing KeyRing;

			public readonly PgpPublicKey Key;

			public KeyRetrievalResults(PgpPublicKeyRing keyring, PgpPublicKey pubkey)
			{
				KeyRing = keyring;
				Key = pubkey;
			}
		}

		private static readonly string[] ProtocolSubtypes = new string[6] { "pgp-signature", "pgp-encrypted", "pgp-keys", "x-pgp-signature", "x-pgp-encrypted", "x-pgp-keys" };

		private const string BeginPublicKeyBlock = "-----BEGIN PGP PUBLIC KEY BLOCK-----";

		private const string EndPublicKeyBlock = "-----END PGP PUBLIC KEY BLOCK-----";

		internal static readonly EncryptionAlgorithm[] DefaultEncryptionAlgorithmRank = new EncryptionAlgorithm[11]
		{
			EncryptionAlgorithm.Idea,
			EncryptionAlgorithm.TripleDes,
			EncryptionAlgorithm.Cast5,
			EncryptionAlgorithm.Blowfish,
			EncryptionAlgorithm.Aes128,
			EncryptionAlgorithm.Aes192,
			EncryptionAlgorithm.Aes256,
			EncryptionAlgorithm.Twofish,
			EncryptionAlgorithm.Camellia128,
			EncryptionAlgorithm.Camellia192,
			EncryptionAlgorithm.Camellia256
		};

		internal static readonly DigestAlgorithm[] DefaultDigestAlgorithmRank = new DigestAlgorithm[6]
		{
			DigestAlgorithm.Sha1,
			DigestAlgorithm.RipeMD160,
			DigestAlgorithm.Sha256,
			DigestAlgorithm.Sha384,
			DigestAlgorithm.Sha512,
			DigestAlgorithm.Sha224
		};

		private EncryptionAlgorithm defaultAlgorithm;

		private HttpClient client;

		private Uri keyServer;

		public EncryptionAlgorithm DefaultEncryptionAlgorithm
		{
			get
			{
				return defaultAlgorithm;
			}
			set
			{
				GetSymmetricKeyAlgorithm(value);
				defaultAlgorithm = value;
			}
		}

		private bool IsValidKeyServer
		{
			get
			{
				if (keyServer == null)
				{
					return false;
				}
				switch (keyServer.Scheme.ToLowerInvariant())
				{
				case "https":
				case "http":
				case "hkp":
					return true;
				default:
					return false;
				}
			}
		}

		public Uri KeyServer
		{
			get
			{
				return keyServer;
			}
			set
			{
				if (value != null && !value.IsAbsoluteUri)
				{
					throw new ArgumentException("The key server URI must be absolute.", "value");
				}
				keyServer = value;
			}
		}

		public bool AutoKeyRetrieve { get; set; }

		protected string PublicKeyRingPath { get; set; }

		protected string SecretKeyRingPath { get; set; }

		public PgpPublicKeyRingBundle PublicKeyRingBundle { get; protected set; }

		public PgpSecretKeyRingBundle SecretKeyRingBundle { get; protected set; }

		public override string SignatureProtocol => "application/pgp-signature";

		public override string EncryptionProtocol => "application/pgp-encrypted";

		public override string KeyExchangeProtocol => "application/pgp-keys";

		protected OpenPgpContext()
		{
			base.EncryptionAlgorithmRank = DefaultEncryptionAlgorithmRank;
			base.DigestAlgorithmRank = DefaultDigestAlgorithmRank;
			EncryptionAlgorithm[] array = base.EncryptionAlgorithmRank;
			foreach (EncryptionAlgorithm algorithm in array)
			{
				Enable(algorithm);
			}
			DigestAlgorithm[] array2 = base.DigestAlgorithmRank;
			foreach (DigestAlgorithm algorithm2 in array2)
			{
				Enable(algorithm2);
			}
			defaultAlgorithm = EncryptionAlgorithm.Cast5;
			client = new HttpClient();
		}

		protected OpenPgpContext(string pubring, string secring)
			: this()
		{
			if (pubring == null)
			{
				throw new ArgumentNullException("pubring");
			}
			if (secring == null)
			{
				throw new ArgumentNullException("secring");
			}
			PublicKeyRingPath = pubring;
			SecretKeyRingPath = secring;
			if (File.Exists(pubring))
			{
				using FileStream inputStream = File.OpenRead(pubring);
				PublicKeyRingBundle = new PgpPublicKeyRingBundle(inputStream);
			}
			else
			{
				PublicKeyRingBundle = new PgpPublicKeyRingBundle(new byte[0]);
			}
			if (File.Exists(secring))
			{
				using (FileStream inputStream2 = File.OpenRead(secring))
				{
					SecretKeyRingBundle = new PgpSecretKeyRingBundle(inputStream2);
					return;
				}
			}
			SecretKeyRingBundle = new PgpSecretKeyRingBundle(new byte[0]);
		}

		public override bool Supports(string protocol)
		{
			if (protocol == null)
			{
				throw new ArgumentNullException("protocol");
			}
			if (!protocol.StartsWith("application/", StringComparison.OrdinalIgnoreCase))
			{
				return false;
			}
			int length = "application/".Length;
			int num = protocol.Length - length;
			for (int i = 0; i < ProtocolSubtypes.Length; i++)
			{
				if (num == ProtocolSubtypes[i].Length && string.Compare(protocol, length, ProtocolSubtypes[i], 0, num, StringComparison.OrdinalIgnoreCase) == 0)
				{
					return true;
				}
			}
			return false;
		}

