		private static bool IsExpired(PgpPublicKey pubkey)
		{
			long validSeconds = pubkey.GetValidSeconds();
			if (validSeconds != 0L && pubkey.CreationTime.AddSeconds(validSeconds) <= DateTime.Now)
			{
				return true;
			}
			return false;
		}

		protected virtual PgpPublicKey GetPublicKey(MailboxAddress mailbox)
		{
			foreach (PgpPublicKey item in EnumeratePublicKeys(mailbox))
			{
				if (item.IsEncryptionKey && !item.IsRevoked() && !IsExpired(item))
				{
					return item;
				}
			}
			throw new PublicKeyNotFoundException(mailbox, "The public key could not be found.");
		}

		protected internal virtual IList<PgpPublicKey> GetPublicKeys(IEnumerable<MailboxAddress> mailboxes)
		{
			if (mailboxes == null)
			{
				throw new ArgumentNullException("mailboxes");
			}
			List<PgpPublicKey> list = new List<PgpPublicKey>();
			foreach (MailboxAddress mailbox in mailboxes)
			{
				list.Add(GetPublicKey(mailbox));
			}
			return list;
		}

		private static bool PgpSecretKeyMatches(PgpSecretKey key, MailboxAddress mailbox)
		{
			if (mailbox is SecureMailboxAddress secureMailboxAddress && !string.IsNullOrEmpty(secureMailboxAddress.Fingerprint))
			{
				if (secureMailboxAddress.Fingerprint.Length > 16)
				{
					string value = HexEncode(key.PublicKey.GetFingerprint());
					return secureMailboxAddress.Fingerprint.Equals(value, StringComparison.OrdinalIgnoreCase);
				}
				string value2 = ((int)key.KeyId).ToString("X2");
				return secureMailboxAddress.Fingerprint.EndsWith(value2, StringComparison.OrdinalIgnoreCase);
			}
			foreach (string userId in key.UserIds)
			{
				if (MailboxAddress.TryParse(userId, out var mailbox2) && mailbox.Address.Equals(mailbox2.Address, StringComparison.OrdinalIgnoreCase))
				{
					return true;
				}
			}
			return false;
		}

		protected internal virtual PgpSecretKey GetSigningKey(MailboxAddress mailbox)
		{
			if (mailbox == null)
			{
				throw new ArgumentNullException("mailbox");
			}
			foreach (PgpSecretKeyRing keyRing in SecretKeyRingBundle.GetKeyRings())
			{
				foreach (PgpSecretKey secretKey in keyRing.GetSecretKeys())
				{
					if (PgpSecretKeyMatches(keyRing.GetSecretKey(), mailbox) && secretKey.IsSigningKey)
					{
						PgpPublicKey publicKey = secretKey.PublicKey;
						if (!publicKey.IsRevoked() && !IsExpired(publicKey))
						{
							return secretKey;
						}
					}
				}
			}
			throw new PrivateKeyNotFoundException(mailbox, "The private key could not be found.");
		}

		protected abstract string GetPasswordForKey(PgpSecretKey key);

		protected PgpPrivateKey GetPrivateKey(PgpSecretKey key)
		{
			int num = 0;
			if (key == null)
			{
				throw new ArgumentNullException("key");
			}
			do
			{
				string passwordForKey;
				if ((passwordForKey = GetPasswordForKey(key)) == null)
				{
					throw new OperationCanceledException();
				}
				try
				{
					PgpPrivateKey pgpPrivateKey = key.ExtractPrivateKey(passwordForKey.ToCharArray());
					if (pgpPrivateKey == null)
					{
						break;
					}
					return pgpPrivateKey;
				}
				catch (Exception)
				{
					goto IL_003b;
				}
				IL_003b:
				num++;
			}
			while (num < 3);
			throw new UnauthorizedAccessException();
		}

		private PgpSecretKey GetSecretKey(long keyId)
		{
			foreach (PgpSecretKeyRing keyRing in SecretKeyRingBundle.GetKeyRings())
			{
				foreach (PgpSecretKey secretKey in keyRing.GetSecretKeys())
				{
					if (secretKey.KeyId == keyId)
					{
						return secretKey;
					}
				}
			}
			throw new PrivateKeyNotFoundException(keyId, "The private key could not be found.");
		}

		private void AddEncryptionKeyPair(PgpKeyRingGenerator keyRingGenerator, KeyGenerationParameters parameters, PublicKeyAlgorithmTag algorithm, DateTime now, long expirationTime, int[] encryptionAlgorithms, int[] digestAlgorithms)
		{
			IAsymmetricCipherKeyPairGenerator keyPairGenerator = GeneratorUtilities.GetKeyPairGenerator("RSA");
			keyPairGenerator.Init(parameters);
			PgpKeyPair keyPair = new PgpKeyPair(algorithm, keyPairGenerator.GenerateKeyPair(), now);
			PgpSignatureSubpacketGenerator pgpSignatureSubpacketGenerator = new PgpSignatureSubpacketGenerator();
			pgpSignatureSubpacketGenerator.SetKeyFlags(isCritical: false, 12);
			pgpSignatureSubpacketGenerator.SetPreferredSymmetricAlgorithms(isCritical: false, encryptionAlgorithms);
			pgpSignatureSubpacketGenerator.SetPreferredHashAlgorithms(isCritical: false, digestAlgorithms);
			if (expirationTime > 0)
			{
				pgpSignatureSubpacketGenerator.SetKeyExpirationTime(isCritical: false, expirationTime);
				pgpSignatureSubpacketGenerator.SetSignatureExpirationTime(isCritical: false, expirationTime);
			}
			keyRingGenerator.AddSubKey(keyPair, pgpSignatureSubpacketGenerator.Generate(), null);
		}

		private PgpKeyRingGenerator CreateKeyRingGenerator(MailboxAddress mailbox, EncryptionAlgorithm algorithm, long expirationTime, string password, DateTime now, SecureRandom random)
		{
			EncryptionAlgorithm[] array = base.EnabledEncryptionAlgorithms;
			DigestAlgorithm[] array2 = base.EnabledDigestAlgorithms;
			int[] array3 = new int[array.Length];
			int[] array4 = new int[array2.Length];
			for (int i = 0; i < array.Length; i++)
			{
				array3[i] = (int)array[i];
			}
			for (int j = 0; j < array2.Length; j++)
			{
				array4[j] = (int)array2[j];
			}
			RsaKeyGenerationParameters parameters = new RsaKeyGenerationParameters(BigInteger.ValueOf(65537L), random, 2048, 12);
			IAsymmetricCipherKeyPairGenerator keyPairGenerator = GeneratorUtilities.GetKeyPairGenerator("RSA");
			keyPairGenerator.Init(parameters);
			PgpKeyPair masterKey = new PgpKeyPair(PublicKeyAlgorithmTag.RsaSign, keyPairGenerator.GenerateKeyPair(), now);
			PgpSignatureSubpacketGenerator pgpSignatureSubpacketGenerator = new PgpSignatureSubpacketGenerator();
			pgpSignatureSubpacketGenerator.SetKeyFlags(isCritical: false, 3);
			pgpSignatureSubpacketGenerator.SetPreferredSymmetricAlgorithms(isCritical: false, array3);
			pgpSignatureSubpacketGenerator.SetPreferredHashAlgorithms(isCritical: false, array4);
			if (expirationTime > 0)
			{
				pgpSignatureSubpacketGenerator.SetKeyExpirationTime(isCritical: false, expirationTime);
				pgpSignatureSubpacketGenerator.SetSignatureExpirationTime(isCritical: false, expirationTime);
			}
			pgpSignatureSubpacketGenerator.SetFeature(isCritical: false, Features.FEATURE_MODIFICATION_DETECTION);
			PgpKeyRingGenerator pgpKeyRingGenerator = new PgpKeyRingGenerator(19, masterKey, mailbox.ToString(encode: false), GetSymmetricKeyAlgorithm(algorithm), CharsetUtils.UTF8.GetBytes(password), useSha1: true, pgpSignatureSubpacketGenerator.Generate(), null, random);
			AddEncryptionKeyPair(pgpKeyRingGenerator, parameters, PublicKeyAlgorithmTag.RsaGeneral, now, expirationTime, array3, array4);
			return pgpKeyRingGenerator;
		}

		public void GenerateKeyPair(MailboxAddress mailbox, string password, DateTime? expirationDate = null, EncryptionAlgorithm algorithm = EncryptionAlgorithm.Aes256, SecureRandom random = null)
		{
			DateTime utcNow = DateTime.UtcNow;
			long expirationTime = 0L;
			if (mailbox == null)
			{
				throw new ArgumentNullException("mailbox");
			}
			if (password == null)
			{
				throw new ArgumentNullException("password");
			}
			if (expirationDate.HasValue)
			{
				DateTime dateTime = expirationDate.Value.ToUniversalTime();
				if (dateTime <= utcNow)
				{
					throw new ArgumentException("expirationDate needs to be greater than DateTime.Now", "expirationDate");
				}
				if ((expirationTime = Convert.ToInt64(dateTime.Subtract(utcNow).TotalSeconds)) <= 0)
				{
					throw new ArgumentException("expirationDate needs to be greater than DateTime.Now", "expirationDate");
				}
			}
			if (random == null)
			{
				random = new SecureRandom(new CryptoApiRandomGenerator());
			}
			PgpKeyRingGenerator pgpKeyRingGenerator = CreateKeyRingGenerator(mailbox, algorithm, expirationTime, password, utcNow, random);
			Import(pgpKeyRingGenerator.GenerateSecretKeyRing());
			Import(pgpKeyRingGenerator.GeneratePublicKeyRing());
		}

		public void SignKey(PgpSecretKey secretKey, PgpPublicKey publicKey, DigestAlgorithm digestAlgo = DigestAlgorithm.Sha1, OpenPgpKeyCertification certification = OpenPgpKeyCertification.GenericCertification)
		{
			if (secretKey == null)
			{
				throw new ArgumentNullException("secretKey");
			}
			if (publicKey == null)
			{
				throw new ArgumentNullException("publicKey");
			}
			PgpPrivateKey privateKey = GetPrivateKey(secretKey);
			PgpSignatureGenerator pgpSignatureGenerator = new PgpSignatureGenerator(secretKey.PublicKey.Algorithm, GetHashAlgorithm(digestAlgo));
			pgpSignatureGenerator.InitSign((int)certification, privateKey);
			pgpSignatureGenerator.GenerateOnePassVersion(isNested: false);
			PgpSignatureSubpacketVector hashedSubpackets = new PgpSignatureSubpacketGenerator().Generate();
			pgpSignatureGenerator.SetHashedSubpackets(hashedSubpackets);
			PgpPublicKey pgpPublicKey = PgpPublicKey.AddCertification(publicKey, pgpSignatureGenerator.Generate());
			PgpPublicKeyRing pgpPublicKeyRing = null;
			foreach (PgpPublicKeyRing item in EnumeratePublicKeyRings())
			{
				foreach (PgpPublicKey publicKey2 in item.GetPublicKeys())
				{
					if (publicKey2.KeyId == publicKey.KeyId)
					{
						PublicKeyRingBundle = PgpPublicKeyRingBundle.RemovePublicKeyRing(PublicKeyRingBundle, item);
						pgpPublicKeyRing = PgpPublicKeyRing.InsertPublicKey(item, pgpPublicKey);
						break;
					}
				}
			}
			if (pgpPublicKeyRing == null)
			{
				pgpPublicKeyRing = new PgpPublicKeyRing(pgpPublicKey.GetEncoded());
			}
			PublicKeyRingBundle = PgpPublicKeyRingBundle.AddPublicKeyRing(PublicKeyRingBundle, pgpPublicKeyRing);
			SavePublicKeyRingBundle();
		}

		public static HashAlgorithmTag GetHashAlgorithm(DigestAlgorithm digestAlgo)
		{
			return digestAlgo switch
			{
				DigestAlgorithm.MD5 => HashAlgorithmTag.MD5, 
				DigestAlgorithm.Sha1 => HashAlgorithmTag.Sha1, 
				DigestAlgorithm.RipeMD160 => HashAlgorithmTag.RipeMD160, 
				DigestAlgorithm.DoubleSha => throw new NotSupportedException("The Double SHA digest algorithm is not supported."), 
				DigestAlgorithm.MD2 => HashAlgorithmTag.MD2, 
				DigestAlgorithm.Tiger192 => throw new NotSupportedException("The Tiger-192 digest algorithm is not supported."), 
				DigestAlgorithm.Haval5160 => throw new NotSupportedException("The HAVAL 5 160 digest algorithm is not supported."), 
				DigestAlgorithm.Sha256 => HashAlgorithmTag.Sha256, 
				DigestAlgorithm.Sha384 => HashAlgorithmTag.Sha384, 
				DigestAlgorithm.Sha512 => HashAlgorithmTag.Sha512, 
				DigestAlgorithm.Sha224 => HashAlgorithmTag.Sha224, 
				DigestAlgorithm.MD4 => throw new NotSupportedException("The MD4 digest algorithm is not supported."), 
				_ => throw new ArgumentOutOfRangeException("digestAlgo"), 
			};
		}

		public override bool CanSign(MailboxAddress signer)
		{
			if (signer == null)
			{
				throw new ArgumentNullException("signer");
			}
			foreach (PgpSecretKeyRing keyRing in SecretKeyRingBundle.GetKeyRings())
			{
				foreach (PgpSecretKey secretKey in keyRing.GetSecretKeys())
				{
					if (PgpSecretKeyMatches(keyRing.GetSecretKey(), signer) && secretKey.IsSigningKey)
					{
						PgpPublicKey publicKey = secretKey.PublicKey;
						if (!publicKey.IsRevoked() && !IsExpired(publicKey))
						{
							return true;
						}
					}
				}
			}
			return false;
		}

		public override bool CanEncrypt(MailboxAddress mailbox)
		{
			if (mailbox == null)
			{
				throw new ArgumentNullException("mailbox");
			}
			foreach (PgpPublicKey item in EnumeratePublicKeys(mailbox))
			{
				if (item.IsEncryptionKey && !item.IsRevoked() && !IsExpired(item))
				{
					return true;
				}
			}
			return false;
		}

		public override MimePart Sign(MailboxAddress signer, DigestAlgorithm digestAlgo, Stream content)
		{
			if (signer == null)
			{
				throw new ArgumentNullException("signer");
			}
			if (content == null)
			{
				throw new ArgumentNullException("content");
			}
			PgpSecretKey signingKey = GetSigningKey(signer);
			return Sign(signingKey, digestAlgo, content);
		}

		public ApplicationPgpSignature Sign(PgpSecretKey signer, DigestAlgorithm digestAlgo, Stream content)
		{
			if (signer == null)
			{
				throw new ArgumentNullException("signer");
			}
			if (!signer.IsSigningKey)
			{
				throw new ArgumentException("The specified secret key cannot be used for signing.", "signer");
			}
			if (content == null)
			{
				throw new ArgumentNullException("content");
			}
			HashAlgorithmTag hashAlgorithm = GetHashAlgorithm(digestAlgo);
			MemoryBlockStream memoryBlockStream = new MemoryBlockStream();
			using (ArmoredOutputStream armoredOutputStream = new ArmoredOutputStream(memoryBlockStream))
			{
				armoredOutputStream.SetHeader("Version", null);
				using (Stream stream = new PgpCompressedDataGenerator(CompressionAlgorithmTag.ZLib).Open(armoredOutputStream))
				{
					PgpSignatureGenerator pgpSignatureGenerator = new PgpSignatureGenerator(signer.PublicKey.Algorithm, hashAlgorithm);
					byte[] array = new byte[4096];
					pgpSignatureGenerator.InitSign(1, GetPrivateKey(signer));
					int len;
					while ((len = content.Read(array, 0, array.Length)) > 0)
					{
						pgpSignatureGenerator.Update(array, 0, len);
					}
					pgpSignatureGenerator.Generate().Encode(stream);
					stream.Flush();
				}
				armoredOutputStream.Flush();
			}
			memoryBlockStream.Position = 0L;
			return new ApplicationPgpSignature(memoryBlockStream);
		}

		public static DigestAlgorithm GetDigestAlgorithm(HashAlgorithmTag hashAlgorithm)
		{
			return hashAlgorithm switch
			{
				HashAlgorithmTag.MD5 => DigestAlgorithm.MD5, 
				HashAlgorithmTag.Sha1 => DigestAlgorithm.Sha1, 
				HashAlgorithmTag.RipeMD160 => DigestAlgorithm.RipeMD160, 
				HashAlgorithmTag.DoubleSha => DigestAlgorithm.DoubleSha, 
				HashAlgorithmTag.MD2 => DigestAlgorithm.MD2, 
				HashAlgorithmTag.Tiger192 => DigestAlgorithm.Tiger192, 
				HashAlgorithmTag.Haval5pass160 => DigestAlgorithm.Haval5160, 
				HashAlgorithmTag.Sha256 => DigestAlgorithm.Sha256, 
				HashAlgorithmTag.Sha384 => DigestAlgorithm.Sha384, 
				HashAlgorithmTag.Sha512 => DigestAlgorithm.Sha512, 
				HashAlgorithmTag.Sha224 => DigestAlgorithm.Sha224, 
				_ => throw new ArgumentOutOfRangeException("hashAlgorithm"), 
			};
		}

		public static PublicKeyAlgorithm GetPublicKeyAlgorithm(PublicKeyAlgorithmTag algorithm)
		{
			return algorithm switch
			{
				PublicKeyAlgorithmTag.RsaGeneral => PublicKeyAlgorithm.RsaGeneral, 
				PublicKeyAlgorithmTag.RsaEncrypt => PublicKeyAlgorithm.RsaEncrypt, 
				PublicKeyAlgorithmTag.RsaSign => PublicKeyAlgorithm.RsaSign, 
				PublicKeyAlgorithmTag.ElGamalGeneral => PublicKeyAlgorithm.ElGamalGeneral, 
				PublicKeyAlgorithmTag.ElGamalEncrypt => PublicKeyAlgorithm.ElGamalEncrypt, 
				PublicKeyAlgorithmTag.Dsa => PublicKeyAlgorithm.Dsa, 
				PublicKeyAlgorithmTag.EC => PublicKeyAlgorithm.EllipticCurve, 
				PublicKeyAlgorithmTag.ECDsa => PublicKeyAlgorithm.EllipticCurveDsa, 
				PublicKeyAlgorithmTag.DiffieHellman => PublicKeyAlgorithm.DiffieHellman, 
				_ => throw new ArgumentOutOfRangeException("algorithm"), 
			};
		}

		private async Task<DigitalSignatureCollection> GetDigitalSignaturesAsync(PgpSignatureList signatureList, Stream content, bool doAsync, CancellationToken cancellationToken)
		{
			List<IDigitalSignature> signatures = new List<IDigitalSignature>();
			byte[] buf = new byte[4096];
			for (int i = 0; i < signatureList.Count; i++)
			{
				long keyId = signatureList[i].KeyId;
				KeyRetrievalResults keyRetrievalResults = ((!doAsync) ? GetPublicKeyRingAsync(keyId, doAsync, cancellationToken).GetAwaiter().GetResult() : (await GetPublicKeyRingAsync(keyId, doAsync, cancellationToken).ConfigureAwait(continueOnCapturedContext: false)));
				OpenPgpDigitalSignature item = new OpenPgpDigitalSignature(keyRetrievalResults.KeyRing, keyRetrievalResults.Key, signatureList[i])
				{
					PublicKeyAlgorithm = GetPublicKeyAlgorithm(signatureList[i].KeyAlgorithm),
					DigestAlgorithm = GetDigestAlgorithm(signatureList[i].HashAlgorithm),
					CreationDate = signatureList[i].CreationTime
				};
				if (keyRetrievalResults.Key != null)
				{
					signatureList[i].InitVerify(keyRetrievalResults.Key);
				}
				signatures.Add(item);
			}
			int length;
			while ((length = content.Read(buf, 0, buf.Length)) > 0)
			{
				for (int j = 0; j < signatures.Count; j++)
				{
					if (signatures[j].SignerCertificate != null)
					{
						((OpenPgpDigitalSignature)signatures[j]).Signature.Update(buf, 0, length);
					}
				}
			}
			return new DigitalSignatureCollection(signatures);
		}

		private Task<DigitalSignatureCollection> VerifyAsync(Stream content, Stream signatureData, bool doAsync, CancellationToken cancellationToken)
		{
			if (content == null)
			{
				throw new ArgumentNullException("content");
			}
			if (signatureData == null)
			{
				throw new ArgumentNullException("signatureData");
			}
			using ArmoredInputStream inputStream = new ArmoredInputStream(signatureData);
			PgpObject pgpObject = new PgpObjectFactory(inputStream).NextPgpObject();
			if (pgpObject is PgpCompressedData pgpCompressedData)
			{
				pgpObject = new PgpObjectFactory(pgpCompressedData.GetDataStream()).NextPgpObject();
			}
			if (pgpObject == null)
			{
				throw new FormatException("Invalid PGP format.");
			}
			PgpSignatureList signatureList = (PgpSignatureList)pgpObject;
			return GetDigitalSignaturesAsync(signatureList, content, doAsync, cancellationToken);
		}

		public override DigitalSignatureCollection Verify(Stream content, Stream signatureData, CancellationToken cancellationToken = default(CancellationToken))
		{
			return VerifyAsync(content, signatureData, doAsync: false, cancellationToken).GetAwaiter().GetResult();
		}

		public override Task<DigitalSignatureCollection> VerifyAsync(Stream content, Stream signatureData, CancellationToken cancellationToken = default(CancellationToken))
		{
			return VerifyAsync(content, signatureData, doAsync: true, cancellationToken);
		}

		private static Stream Compress(Stream content, byte[] buf)
		{
			PgpCompressedDataGenerator pgpCompressedDataGenerator = new PgpCompressedDataGenerator(CompressionAlgorithmTag.ZLib);
			MemoryBlockStream memoryBlockStream = new MemoryBlockStream();
			using (Stream stream = pgpCompressedDataGenerator.Open(memoryBlockStream))
			{
				using (Stream stream2 = new PgpLiteralDataGenerator().Open(stream, 't', "mime.txt", content.Length, DateTime.Now))
				{
					int count;
					while ((count = content.Read(buf, 0, buf.Length)) > 0)
					{
						stream2.Write(buf, 0, count);
					}
					stream2.Flush();
				}
				stream.Flush();
			}
			memoryBlockStream.Position = 0L;
			return memoryBlockStream;
		}

		private static Stream Encrypt(PgpEncryptedDataGenerator encrypter, Stream content)
		{
			MemoryBlockStream memoryBlockStream = new MemoryBlockStream();
			using (ArmoredOutputStream armoredOutputStream = new ArmoredOutputStream(memoryBlockStream))
			{
				byte[] array = new byte[4096];
				armoredOutputStream.SetHeader("Version", null);
				using (Stream stream = Compress(content, array))
				{
					using Stream stream2 = encrypter.Open(armoredOutputStream, stream.Length);
					int count;
					while ((count = stream.Read(array, 0, array.Length)) > 0)
					{
						stream2.Write(array, 0, count);
					}
					stream2.Flush();
				}
				armoredOutputStream.Flush();
			}
			memoryBlockStream.Position = 0L;
			return memoryBlockStream;
		}

		private static SymmetricKeyAlgorithmTag GetSymmetricKeyAlgorithm(EncryptionAlgorithm algorithm)
		{
			return algorithm switch
			{
				EncryptionAlgorithm.Aes128 => SymmetricKeyAlgorithmTag.Aes128, 
				EncryptionAlgorithm.Aes192 => SymmetricKeyAlgorithmTag.Aes192, 
				EncryptionAlgorithm.Aes256 => SymmetricKeyAlgorithmTag.Aes256, 
				EncryptionAlgorithm.Camellia128 => SymmetricKeyAlgorithmTag.Camellia128, 
				EncryptionAlgorithm.Camellia192 => SymmetricKeyAlgorithmTag.Camellia192, 
				EncryptionAlgorithm.Camellia256 => SymmetricKeyAlgorithmTag.Camellia256, 
				EncryptionAlgorithm.Cast5 => SymmetricKeyAlgorithmTag.Cast5, 
				EncryptionAlgorithm.Des => SymmetricKeyAlgorithmTag.Des, 
				EncryptionAlgorithm.TripleDes => SymmetricKeyAlgorithmTag.TripleDes, 
				EncryptionAlgorithm.Idea => SymmetricKeyAlgorithmTag.Idea, 
				EncryptionAlgorithm.Blowfish => SymmetricKeyAlgorithmTag.Blowfish, 
				EncryptionAlgorithm.Twofish => SymmetricKeyAlgorithmTag.Twofish, 
				_ => throw new NotSupportedException($"{algorithm} is not supported."), 
			};
		}

