		public override MimePart Export(IEnumerable<MailboxAddress> mailboxes)
		{
			if (mailboxes == null)
			{
				throw new ArgumentNullException("mailboxes");
			}
			List<PgpPublicKeyRing> list = new List<PgpPublicKeyRing>();
			foreach (MailboxAddress mailbox in mailboxes)
			{
				list.AddRange(EnumeratePublicKeyRings(mailbox));
			}
			PgpPublicKeyRingBundle keys = new PgpPublicKeyRingBundle(list);
			return Export(keys);
		}

		public MimePart Export(IEnumerable<PgpPublicKey> keys)
		{
			if (keys == null)
			{
				throw new ArgumentNullException("keys");
			}
			PgpPublicKeyRingBundle keys2 = new PgpPublicKeyRingBundle(keys.Select((PgpPublicKey key) => new PgpPublicKeyRing(key.GetEncoded())));
			return Export(keys2);
		}

		public MimePart Export(PgpPublicKeyRingBundle keys)
		{
			if (keys == null)
			{
				throw new ArgumentNullException("keys");
			}
			MemoryBlockStream memoryBlockStream = new MemoryBlockStream();
			Export(keys, memoryBlockStream, armor: true);
			memoryBlockStream.Position = 0L;
			return new MimePart("application", "pgp-keys")
			{
				ContentDisposition = new ContentDisposition("attachment"),
				Content = new MimeContent(memoryBlockStream)
			};
		}

		public void Export(IEnumerable<MailboxAddress> mailboxes, Stream stream, bool armor)
		{
			if (mailboxes == null)
			{
				throw new ArgumentNullException("mailboxes");
			}
			if (stream == null)
			{
				throw new ArgumentNullException("stream");
			}
			List<PgpPublicKeyRing> list = new List<PgpPublicKeyRing>();
			foreach (MailboxAddress mailbox in mailboxes)
			{
				list.AddRange(EnumeratePublicKeyRings(mailbox));
			}
			PgpPublicKeyRingBundle keys = new PgpPublicKeyRingBundle(list);
			Export(keys, stream, armor);
		}

		public void Export(IEnumerable<PgpPublicKey> keys, Stream stream, bool armor)
		{
			if (keys == null)
			{
				throw new ArgumentNullException("keys");
			}
			if (stream == null)
			{
				throw new ArgumentNullException("stream");
			}
			PgpPublicKeyRingBundle keys2 = new PgpPublicKeyRingBundle(keys.Select((PgpPublicKey key) => new PgpPublicKeyRing(key.GetEncoded())));
			Export(keys2, stream, armor);
		}

		public void Export(PgpPublicKeyRingBundle keys, Stream stream, bool armor)
		{
			if (keys == null)
			{
				throw new ArgumentNullException("keys");
			}
			if (stream == null)
			{
				throw new ArgumentNullException("stream");
			}
			if (armor)
			{
				using (ArmoredOutputStream armoredOutputStream = new ArmoredOutputStream(stream))
				{
					armoredOutputStream.SetHeader("Version", null);
					keys.Encode(armoredOutputStream);
					armoredOutputStream.Flush();
					return;
				}
			}
			keys.Encode(stream);
		}

		public void Delete(PgpPublicKeyRing keyring)
		{
			if (keyring == null)
			{
				throw new ArgumentNullException("keyring");
			}
			PublicKeyRingBundle = PgpPublicKeyRingBundle.RemovePublicKeyRing(PublicKeyRingBundle, keyring);
			SavePublicKeyRingBundle();
		}

		public void Delete(PgpSecretKeyRing keyring)
		{
			if (keyring == null)
			{
				throw new ArgumentNullException("keyring");
			}
			SecretKeyRingBundle = PgpSecretKeyRingBundle.RemoveSecretKeyRing(SecretKeyRingBundle, keyring);
			SaveSecretKeyRingBundle();
		}

		protected override void Dispose(bool disposing)
		{
			if (disposing && client != null)
			{
				client.Dispose();
				client = null;
			}
			base.Dispose(disposing);
		}
	}
	public enum OpenPgpDataType
	{
		None,
		SignedMessage,
		EncryptedMessage,
		PublicKey,
		PrivateKey
	}
	public class OpenPgpDetectionFilter : MimeFilterBase
	{
		private enum OpenPgpState
		{
			None = 0,
			BeginPgpMessage = 1,
			EndPgpMessage = 3,
			BeginPgpSignedMessage = 4,
			BeginPgpSignature = 12,
			EndPgpSignature = 28,
			BeginPgpPublicKeyBlock = 32,
			EndPgpPublicKeyBlock = 96,
			BeginPgpPrivateKeyBlock = 128,
			EndPgpPrivateKeyBlock = 384
		}

		private struct OpenPgpMarker(string marker, OpenPgpState initial, OpenPgpState detected, bool isEnd)
		{
			public byte[] Marker = CharsetUtils.UTF8.GetBytes(marker);

			public OpenPgpState InitialState = initial;

			public OpenPgpState DetectedState = detected;

			public bool IsEnd = isEnd;
		}

		private static readonly OpenPgpMarker[] OpenPgpMarkers = new OpenPgpMarker[9]
		{
			new OpenPgpMarker("-----BEGIN PGP MESSAGE-----", OpenPgpState.None, OpenPgpState.BeginPgpMessage, isEnd: false),
			new OpenPgpMarker("-----END PGP MESSAGE-----", OpenPgpState.BeginPgpMessage, OpenPgpState.EndPgpMessage, isEnd: true),
			new OpenPgpMarker("-----BEGIN PGP SIGNED MESSAGE-----", OpenPgpState.None, OpenPgpState.BeginPgpSignedMessage, isEnd: false),
			new OpenPgpMarker("-----BEGIN PGP SIGNATURE-----", OpenPgpState.BeginPgpSignedMessage, OpenPgpState.BeginPgpSignature, isEnd: false),
			new OpenPgpMarker("-----END PGP SIGNATURE-----", OpenPgpState.BeginPgpSignature, OpenPgpState.EndPgpSignature, isEnd: true),
			new OpenPgpMarker("-----BEGIN PGP PUBLIC KEY BLOCK-----", OpenPgpState.None, OpenPgpState.BeginPgpPublicKeyBlock, isEnd: false),
			new OpenPgpMarker("-----END PGP PUBLIC KEY BLOCK-----", OpenPgpState.BeginPgpPublicKeyBlock, OpenPgpState.EndPgpPublicKeyBlock, isEnd: true),
			new OpenPgpMarker("-----BEGIN PGP PRIVATE KEY BLOCK-----", OpenPgpState.None, OpenPgpState.BeginPgpPrivateKeyBlock, isEnd: false),
			new OpenPgpMarker("-----END PGP PRIVATE KEY BLOCK-----", OpenPgpState.BeginPgpPrivateKeyBlock, OpenPgpState.EndPgpPrivateKeyBlock, isEnd: false)
		};

		private OpenPgpState state;

		private int position;

		private int next;

		private bool seenEndMarker;

		private bool midline;

		public int? BeginOffset { get; private set; }

		public int? EndOffset { get; private set; }

		public OpenPgpDataType DataType => state switch
		{
			OpenPgpState.EndPgpPrivateKeyBlock => OpenPgpDataType.PrivateKey, 
			OpenPgpState.EndPgpPublicKeyBlock => OpenPgpDataType.PublicKey, 
			OpenPgpState.EndPgpSignature => OpenPgpDataType.SignedMessage, 
			OpenPgpState.EndPgpMessage => OpenPgpDataType.EncryptedMessage, 
			_ => OpenPgpDataType.None, 
		};

		private static bool IsMarker(byte[] input, int startIndex, int endIndex, byte[] marker, out bool cr)
		{
			int num = startIndex;
			int num2 = 0;
			cr = false;
			while (num2 < marker.Length && num < endIndex)
			{
				if (input[num++] != marker[num2++])
				{
					return false;
				}
			}
			if (num2 < marker.Length)
			{
				return false;
			}
			if (num < endIndex && input[num] == 13)
			{
				cr = true;
				num++;
			}
			if (num < endIndex)
			{
				return input[num] == 10;
			}
			return false;
		}

		private static bool IsPartialMatch(byte[] input, int startIndex, int endIndex, byte[] marker)
		{
			int num = startIndex;
			int num2 = 0;
			while (num2 < marker.Length && num < endIndex)
			{
				if (input[num++] != marker[num2++])
				{
					return false;
				}
			}
			if (num < endIndex && input[num] == 13)
			{
				num++;
			}
			return num == endIndex;
		}

		private void SetPosition(int offset, int marker, bool cr)
		{
			int num = OpenPgpMarkers[marker].Marker.Length + ((!cr) ? 1 : 2);
			switch (state)
			{
			case OpenPgpState.BeginPgpPrivateKeyBlock:
				BeginOffset = position + offset;
				break;
			case OpenPgpState.EndPgpPrivateKeyBlock:
				EndOffset = position + offset + num;
				break;
			case OpenPgpState.BeginPgpPublicKeyBlock:
				BeginOffset = position + offset;
				break;
			case OpenPgpState.EndPgpPublicKeyBlock:
				EndOffset = position + offset + num;
				break;
			case OpenPgpState.BeginPgpSignedMessage:
				BeginOffset = position + offset;
				break;
			case OpenPgpState.EndPgpSignature:
				EndOffset = position + offset + num;
				break;
			case OpenPgpState.BeginPgpMessage:
				BeginOffset = position + offset;
				break;
			case OpenPgpState.EndPgpMessage:
				EndOffset = position + offset + num;
				break;
			}
		}

		protected override byte[] Filter(byte[] input, int startIndex, int length, out int outputIndex, out int outputLength, bool flush)
		{
			int num = startIndex + length;
			int i = startIndex;
			outputIndex = startIndex;
			outputLength = 0;
			if (seenEndMarker || length == 0)
			{
				return input;
			}
			if (midline)
			{
				for (; i < num && input[i] != 10; i++)
				{
				}
				if (i == num)
				{
					if (state != OpenPgpState.None)
					{
						outputLength = i - startIndex;
					}
					position += i - startIndex;
					return input;
				}
				midline = false;
			}
			bool cr;
			if (state == OpenPgpState.None)
			{
				do
				{
					int num2 = i;
					for (; i < num && input[i] != 10; i++)
					{
					}
					if (i == num)
					{
						bool flag = false;
						for (int j = 0; j < OpenPgpMarkers.Length; j++)
						{
							if (OpenPgpMarkers[j].InitialState == state && IsPartialMatch(input, num2, i, OpenPgpMarkers[j].Marker))
							{
								flag = true;
								break;
							}
						}
						if (flag)
						{
							SaveRemainingInput(input, num2, i - num2);
							position += num2 - startIndex;
						}
						else
						{
							position += i - num2;
							midline = true;
						}
						return input;
					}
					i++;
					for (int k = 0; k < OpenPgpMarkers.Length; k++)
					{
						if (OpenPgpMarkers[k].InitialState == state && IsMarker(input, num2, num, OpenPgpMarkers[k].Marker, out cr))
						{
							state = OpenPgpMarkers[k].DetectedState;
							SetPosition(num2 - startIndex, k, cr);
							outputLength = i - num2;
							outputIndex = num2;
							next = k + 1;
							break;
						}
					}
				}
				while (i < num && state == OpenPgpState.None);
				if (i == num)
				{
					position += i - startIndex;
					return input;
				}
			}
			do
			{
				int num3 = i;
				for (; i < num && input[i] != 10; i++)
				{
				}
				if (i == num)
				{
					if (flush)
					{
						break;
					}
					if (IsPartialMatch(input, num3, i, OpenPgpMarkers[next].Marker))
					{
						SaveRemainingInput(input, num3, i - num3);
						outputLength = num3 - outputIndex;
						position += num3 - startIndex;
					}
					else
					{
						outputLength = i - outputIndex;
						position += i - startIndex;
						midline = true;
					}
					return input;
				}
				i++;
				if (IsMarker(input, num3, num, OpenPgpMarkers[next].Marker, out cr))
				{
					seenEndMarker = OpenPgpMarkers[next].IsEnd;
					state = OpenPgpMarkers[next].DetectedState;
					SetPosition(num3 - startIndex, next, cr);
					next++;
					if (seenEndMarker)
					{
						break;
					}
				}
			}
			while (i < num);
			outputLength = i - outputIndex;
			position += i - startIndex;
			return input;
		}

		public override void Reset()
		{
			state = OpenPgpState.None;
			seenEndMarker = false;
			BeginOffset = null;
			EndOffset = null;
			midline = false;
			position = 0;
			next = 0;
			base.Reset();
		}
	}
	public class OpenPgpDigitalCertificate : IDigitalCertificate
	{
		public PgpPublicKeyRing KeyRing { get; private set; }

		public PgpPublicKey PublicKey { get; private set; }

		public PublicKeyAlgorithm PublicKeyAlgorithm => OpenPgpContext.GetPublicKeyAlgorithm(PublicKey.Algorithm);

		public DateTime CreationDate => PublicKey.CreationTime;

		public DateTime ExpirationDate
		{
			get
			{
				long validSeconds = PublicKey.GetValidSeconds();
				if (validSeconds <= 0)
				{
					return DateTime.MaxValue;
				}
				return CreationDate.AddSeconds(validSeconds);
			}
		}

		public string Fingerprint { get; private set; }

		public string Email { get; private set; }

		public string Name { get; private set; }

		internal OpenPgpDigitalCertificate(PgpPublicKeyRing keyring, PgpPublicKey pubkey)
		{
			byte[] fingerprint = pubkey.GetFingerprint();
			StringBuilder stringBuilder = new StringBuilder();
			for (int i = 0; i < fingerprint.Length; i++)
			{
				stringBuilder.Append(fingerprint[i].ToString("X2"));
			}
			Fingerprint = stringBuilder.ToString();
			PublicKey = pubkey;
			KeyRing = keyring;
			if (UpdateUserId(pubkey) || pubkey.IsMasterKey)
			{
				return;
			}
			foreach (PgpPublicKey publicKey in keyring.GetPublicKeys())
			{
				if (publicKey.IsMasterKey)
				{
					UpdateUserId(publicKey);
					break;
				}
			}
		}

		private bool UpdateUserId(PgpPublicKey pubkey)
		{
			foreach (string userId in pubkey.GetUserIds())
			{
				byte[] bytes = Encoding.UTF8.GetBytes(userId);
				int index = 0;
				if (MailboxAddress.TryParse(ParserOptions.Default, bytes, ref index, bytes.Length, throwOnError: false, out var mailbox))
				{
					Email = mailbox.Address;
					Name = mailbox.Name;
					return true;
				}
			}
			return false;
		}
	}
	public class OpenPgpDigitalSignature : IDigitalSignature
	{
		private DigitalSignatureVerifyException vex;

		private bool? valid;

		internal PgpOnePassSignature OnePassSignature { get; private set; }

		internal PgpSignature Signature { get; set; }

		public IDigitalCertificate SignerCertificate { get; private set; }

		public PublicKeyAlgorithm PublicKeyAlgorithm { get; internal set; }

		public DigestAlgorithm DigestAlgorithm { get; internal set; }

		public DateTime CreationDate { get; internal set; }

		internal OpenPgpDigitalSignature(PgpPublicKeyRing keyring, PgpPublicKey pubkey, PgpOnePassSignature signature)
		{
			SignerCertificate = ((pubkey != null) ? new OpenPgpDigitalCertificate(keyring, pubkey) : null);
			OnePassSignature = signature;
		}

		internal OpenPgpDigitalSignature(PgpPublicKeyRing keyring, PgpPublicKey pubkey, PgpSignature signature)
		{
			SignerCertificate = ((pubkey != null) ? new OpenPgpDigitalCertificate(keyring, pubkey) : null);
			Signature = signature;
		}

		public bool Verify()
		{
			if (valid.HasValue)
			{
				return valid.Value;
			}
			if (vex != null)
			{
				throw vex;
			}
			if (SignerCertificate == null)
			{
				string message = $"Failed to verify digital signature: no public key found for {(int)Signature.KeyId:X8}";
				vex = new DigitalSignatureVerifyException(Signature.KeyId, message);
				throw vex;
			}
			try
			{
				if (OnePassSignature != null)
				{
					valid = OnePassSignature.Verify(Signature);
				}
				else
				{
					valid = Signature.Verify();
				}
				return valid.Value;
			}
			catch (Exception ex)
			{
				string message2 = $"Failed to verify digital signature: {ex.Message}";
				vex = new DigitalSignatureVerifyException(Signature.KeyId, message2, ex);
				throw vex;
			}
		}
	}
