		public virtual void Import(string fileName, string password)
		{
			if (fileName == null)
			{
				throw new ArgumentNullException("fileName");
			}
			if (password == null)
			{
				throw new ArgumentNullException("password");
			}
			using FileStream stream = File.OpenRead(fileName);
			Import(stream, password);
		}

		public abstract void Import(Org.BouncyCastle.X509.X509Certificate certificate);

		public abstract void Import(X509Crl crl);

		public override void Import(Stream stream)
		{
			if (stream == null)
			{
				throw new ArgumentNullException("stream");
			}
			CmsSignedDataParser cmsSignedDataParser = new CmsSignedDataParser(stream);
			foreach (Org.BouncyCastle.X509.X509Certificate match in cmsSignedDataParser.GetCertificates("Collection").GetMatches(null))
			{
				Import(match);
			}
			foreach (X509Crl match2 in cmsSignedDataParser.GetCrls("Collection").GetMatches(null))
			{
				Import(match2);
			}
		}
	}
	public class SecureMimeDigitalCertificate : IDigitalCertificate
	{
		public Org.BouncyCastle.X509.X509Certificate Certificate { get; private set; }

		public PublicKeyAlgorithm PublicKeyAlgorithm { get; private set; }

		public DateTime CreationDate => Certificate.NotBefore.ToUniversalTime();

		public DateTime ExpirationDate => Certificate.NotAfter.ToUniversalTime();

		public string Fingerprint { get; private set; }

		public string Email => Certificate.GetSubjectEmailAddress();

		public string Name => Certificate.GetCommonName();

		public SecureMimeDigitalCertificate(Org.BouncyCastle.X509.X509Certificate certificate)
		{
			if (certificate == null)
			{
				throw new ArgumentNullException("certificate");
			}
