			Fingerprint = certificate.GetFingerprint();
			PublicKeyAlgorithm = certificate.GetPublicKeyAlgorithm();
		}
	}
	public class SecureMimeDigitalSignature : IDigitalSignature
	{
		private DigitalSignatureVerifyException vex;

		private bool? valid;

		public SignerInformation SignerInfo { get; private set; }

		public EncryptionAlgorithm[] EncryptionAlgorithms { get; private set; }

		public PkixCertPath Chain { get; internal set; }

		public Exception ChainException { get; internal set; }

		public IDigitalCertificate SignerCertificate { get; private set; }

		public PublicKeyAlgorithm PublicKeyAlgorithm
		{
			get
			{
				if (SignerCertificate == null)
				{
					return PublicKeyAlgorithm.None;
				}
				return SignerCertificate.PublicKeyAlgorithm;
			}
		}

		public DigestAlgorithm DigestAlgorithm { get; private set; }

		public DateTime CreationDate { get; private set; }

		private static DateTime ToAdjustedDateTime(DerUtcTime time)
		{
			return DateUtils.Parse(time.AdjustedTimeString, "yyyyMMddHHmmsszzz");
		}

		public SecureMimeDigitalSignature(SignerInformation signerInfo, Org.BouncyCastle.X509.X509Certificate certificate)
		{
			if (signerInfo == null)
			{
				throw new ArgumentNullException("signerInfo");
			}
			SignerInfo = signerInfo;
			List<EncryptionAlgorithm> list = new List<EncryptionAlgorithm>();
			if (signerInfo.SignedAttributes != null)
			{
				{
					IEnumerator enumerator = signerInfo.SignedAttributes.GetAll(CmsAttributes.SigningTime).GetEnumerator();
					try
					{
						if (enumerator.MoveNext())
						{
							DerUtcTime time = (DerUtcTime)((DerSet)((Org.BouncyCastle.Asn1.Cms.Attribute)enumerator.Current).AttrValues)[0];
							CreationDate = ToAdjustedDateTime(time);
						}
					}
					finally
					{
						IDisposable disposable = enumerator as IDisposable;
						if (disposable != null)
						{
							disposable.Dispose();
						}
					}
				}
				foreach (Org.BouncyCastle.Asn1.Cms.Attribute item in signerInfo.SignedAttributes.GetAll(SmimeAttributes.SmimeCapabilities))
				{
					foreach (Asn1Sequence attrValue in item.AttrValues)
					{
						for (int i = 0; i < attrValue.Count; i++)
						{
							if (BouncyCastleSecureMimeContext.TryGetEncryptionAlgorithm(AlgorithmIdentifier.GetInstance(attrValue[i]), out var algorithm))
							{
								list.Add(algorithm);
							}
						}
					}
				}
			}
			EncryptionAlgorithms = list.ToArray();
			if (BouncyCastleSecureMimeContext.TryGetDigestAlgorithm(signerInfo.DigestAlgorithmID, out var algorithm2))
			{
				DigestAlgorithm = algorithm2;
			}
			if (certificate != null)
			{
				SignerCertificate = new SecureMimeDigitalCertificate(certificate);
			}
		}

		public bool Verify()
		{
			if (valid.HasValue)
			{
				return valid.Value;
			}
			if (vex != null)
			{
				throw vex;
			}
			if (SignerCertificate == null)
			{
				string message = $"Failed to verify digital signature: missing certificate.";
				vex = new DigitalSignatureVerifyException(message);
				throw vex;
			}
			if (ChainException != null)
			{
				string message2 = $"Failed to verify digital signature: {ChainException.Message}";
				vex = new DigitalSignatureVerifyException(message2, ChainException);
				throw vex;
			}
			try
			{
				Org.BouncyCastle.X509.X509Certificate certificate = ((SecureMimeDigitalCertificate)SignerCertificate).Certificate;
				valid = SignerInfo.Verify(certificate);
				return valid.Value;
			}
			catch (Exception ex)
			{
				string message3 = $"Failed to verify digital signature: {ex.Message}";
				vex = new DigitalSignatureVerifyException(message3, ex);
				throw vex;
			}
		}
	}
	public enum SecureMimeType
	{
		CompressedData,
		EnvelopedData,
		SignedData,
		CertsOnly,
		Unknown
	}
	public abstract class SqlCertificateDatabase : X509CertificateDatabase
	{
		private readonly DbConnection connection;

		private bool disposed;

		protected SqlCertificateDatabase(DbConnection connection, string password)
			: base(password)
		{
			if (connection == null)
			{
				throw new ArgumentNullException("connection");
			}
			this.connection = connection;
			if (connection.State != ConnectionState.Open)
			{
				connection.Open();
			}
			CreateCertificatesTable();
			CreateCrlsTable();
		}

		protected abstract DbCommand GetCreateCertificatesTableCommand(DbConnection connection);

		protected abstract DbCommand GetCreateCrlsTableCommand(DbConnection connection);

		private static void CreateIndex(DbConnection connection, string tableName, string[] columnNames)
		{
			string arg = string.Format("{0}_{1}_INDEX", tableName, string.Join("_", columnNames));
			string commandText = string.Format("CREATE INDEX IF NOT EXISTS {0} ON {1}({2})", arg, tableName, string.Join(", ", columnNames));
			using DbCommand dbCommand = connection.CreateCommand();
			dbCommand.CommandText = commandText;
			dbCommand.ExecuteNonQuery();
		}

		private void CreateCertificatesTable()
		{
			using (DbCommand dbCommand = GetCreateCertificatesTableCommand(connection))
			{
				dbCommand.ExecuteNonQuery();
			}
			CreateIndex(connection, "CERTIFICATES", new string[3] { "ISSUERNAME", "SERIALNUMBER", "FINGERPRINT" });
			CreateIndex(connection, "CERTIFICATES", new string[2] { "BASICCONSTRAINTS", "FINGERPRINT" });
			CreateIndex(connection, "CERTIFICATES", new string[2] { "BASICCONSTRAINTS", "SUBJECTEMAIL" });
			CreateIndex(connection, "CERTIFICATES", new string[1] { "TRUSTED" });
			CreateIndex(connection, "CERTIFICATES", new string[4] { "TRUSTED", "BASICCONSTRAINTS", "ISSUERNAME", "SERIALNUMBER" });
			CreateIndex(connection, "CERTIFICATES", new string[3] { "BASICCONSTRAINTS", "ISSUERNAME", "SERIALNUMBER" });
		}

		private void CreateCrlsTable()
		{
			using (DbCommand dbCommand = GetCreateCrlsTableCommand(connection))
			{
				dbCommand.ExecuteNonQuery();
			}
			CreateIndex(connection, "CRLS", new string[1] { "ISSUERNAME" });
			CreateIndex(connection, "CRLS", new string[3] { "DELTA", "ISSUERNAME", "THISUPDATE" });
		}

		protected override DbCommand GetSelectCommand(Org.BouncyCastle.X509.X509Certificate certificate, X509CertificateRecordFields fields)
		{
			string text = "SELECT " + string.Join(", ", X509CertificateDatabase.GetColumnNames(fields)) + " FROM CERTIFICATES ";
			string value = certificate.GetFingerprint().ToLowerInvariant();
			string value2 = certificate.SerialNumber.ToString();
			string value3 = certificate.IssuerDN.ToString();
			DbCommand dbCommand = connection.CreateCommand();
			dbCommand.CommandText = text + "WHERE ISSUERNAME = @ISSUERNAME AND SERIALNUMBER = @SERIALNUMBER AND FINGERPRINT = @FINGERPRINT LIMIT 1";
			dbCommand.AddParameterWithValue("@ISSUERNAME", value3);
			dbCommand.AddParameterWithValue("@SERIALNUMBER", value2);
			dbCommand.AddParameterWithValue("@FINGERPRINT", value);
			dbCommand.CommandType = CommandType.Text;
			return dbCommand;
		}

		protected override DbCommand GetSelectCommand(MailboxAddress mailbox, DateTime now, bool requirePrivateKey, X509CertificateRecordFields fields)
		{
			string text = "SELECT " + string.Join(", ", X509CertificateDatabase.GetColumnNames(fields)) + " FROM CERTIFICATES";
			SecureMailboxAddress secureMailboxAddress = mailbox as SecureMailboxAddress;
			DbCommand dbCommand = connection.CreateCommand();
			string text2 = " WHERE ";
			text2 += "BASICCONSTRAINTS = @BASICCONSTRAINTS ";
			dbCommand.AddParameterWithValue("@BASICCONSTRAINTS", -1);
			if (secureMailboxAddress != null && !string.IsNullOrEmpty(secureMailboxAddress.Fingerprint))
			{
				if (secureMailboxAddress.Fingerprint.Length < 40)
				{
					text2 += "AND FINGERPRINT LIKE @FINGERPRINT ";
					dbCommand.AddParameterWithValue("@FINGERPRINT", secureMailboxAddress.Fingerprint.ToLowerInvariant() + "%");
				}
				else
				{
					text2 += "AND FINGERPRINT = @FINGERPRINT ";
					dbCommand.AddParameterWithValue("@FINGERPRINT", secureMailboxAddress.Fingerprint.ToLowerInvariant());
				}
			}
			else
			{
				text2 += "AND SUBJECTEMAIL = @SUBJECTEMAIL ";
				dbCommand.AddParameterWithValue("@SUBJECTEMAIL", mailbox.Address.ToLowerInvariant());
			}
			text2 += "AND NOTBEFORE < @NOW AND NOTAFTER > @NOW ";
			dbCommand.AddParameterWithValue("@NOW", now.ToUniversalTime());
			if (requirePrivateKey)
			{
				text2 += "AND PRIVATEKEY IS NOT NULL";
			}
			dbCommand.CommandText = text + text2;
			dbCommand.CommandType = CommandType.Text;
			return dbCommand;
		}

		protected override DbCommand GetSelectCommand(IX509Selector selector, bool trustedOnly, bool requirePrivateKey, X509CertificateRecordFields fields)
		{
			string text = "SELECT " + string.Join(", ", X509CertificateDatabase.GetColumnNames(fields)) + " FROM CERTIFICATES";
			X509CertStoreSelector x509CertStoreSelector = selector as X509CertStoreSelector;
			DbCommand dbCommand = connection.CreateCommand();
			string text2 = " WHERE ";
			if (trustedOnly)
			{
				dbCommand.AddParameterWithValue("@TRUSTED", true);
				text2 += "TRUSTED = @TRUSTED";
			}
			if (x509CertStoreSelector != null)
			{
				if (x509CertStoreSelector.BasicConstraints != -1)
				{
					if (dbCommand.Parameters.Count > 0)
					{
						text2 += " AND ";
					}
					dbCommand.AddParameterWithValue("@BASICCONSTRAINTS", x509CertStoreSelector.BasicConstraints);
					text2 += "BASICCONSTRAINTS = @BASICCONSTRAINTS";
				}
				if (x509CertStoreSelector.Issuer != null)
				{
					if (dbCommand.Parameters.Count > 0)
					{
						text2 += " AND ";
					}
					dbCommand.AddParameterWithValue("@ISSUERNAME", x509CertStoreSelector.Issuer.ToString());
					text2 += "ISSUERNAME = @ISSUERNAME";
				}
				if (x509CertStoreSelector.SerialNumber != null)
				{
					if (dbCommand.Parameters.Count > 0)
					{
						text2 += " AND ";
					}
					dbCommand.AddParameterWithValue("@SERIALNUMBER", x509CertStoreSelector.SerialNumber.ToString());
					text2 += "SERIALNUMBER = @SERIALNUMBER";
				}
				if (x509CertStoreSelector.KeyUsage != null)
				{
					X509KeyUsageFlags keyUsageFlags = BouncyCastleCertificateExtensions.GetKeyUsageFlags(x509CertStoreSelector.KeyUsage);
					if (keyUsageFlags != X509KeyUsageFlags.None)
					{
						if (dbCommand.Parameters.Count > 0)
						{
							text2 += " AND ";
						}
						dbCommand.AddParameterWithValue("@FLAGS", (int)keyUsageFlags);
						text2 += "(KEYUSAGE == 0 OR (KEYUSAGE & @FLAGS) == @FLAGS)";
					}
				}
			}
			if (requirePrivateKey)
			{
				if (dbCommand.Parameters.Count > 0)
				{
					text2 += " AND ";
				}
				text2 += "PRIVATEKEY IS NOT NULL";
			}
			else if (dbCommand.Parameters.Count == 0)
			{
				text2 = string.Empty;
			}
			dbCommand.CommandText = text + text2;
			dbCommand.CommandType = CommandType.Text;
			return dbCommand;
		}

