	public class TemporarySecureMimeContext : BouncyCastleSecureMimeContext
	{
		private readonly Dictionary<string, EncryptionAlgorithm[]> capabilities;

		internal readonly Dictionary<string, AsymmetricKeyParameter> keys;

		internal readonly List<Org.BouncyCastle.X509.X509Certificate> certificates;

		private readonly HashSet<string> fingerprints;

		private readonly List<X509Crl> crls;

		public TemporarySecureMimeContext()
		{
			capabilities = new Dictionary<string, EncryptionAlgorithm[]>(StringComparer.Ordinal);
			keys = new Dictionary<string, AsymmetricKeyParameter>(StringComparer.Ordinal);
			certificates = new List<Org.BouncyCastle.X509.X509Certificate>();
			fingerprints = new HashSet<string>();
			crls = new List<X509Crl>();
		}

		public override bool CanSign(MailboxAddress signer)
		{
			if (signer == null)
			{
				throw new ArgumentNullException("signer");
			}
			AsymmetricKeyParameter key;
			return GetCmsSignerCertificate(signer, out key) != null;
		}

		public override bool CanEncrypt(MailboxAddress mailbox)
		{
			if (mailbox == null)
			{
				throw new ArgumentNullException("mailbox");
			}
			return GetCmsRecipientCertificate(mailbox) != null;
		}

		protected override Org.BouncyCastle.X509.X509Certificate GetCertificate(IX509Selector selector)
		{
			if (selector == null && certificates.Count > 0)
			{
				return certificates[0];
			}
			foreach (Org.BouncyCastle.X509.X509Certificate certificate in certificates)
			{
				if (selector.Match(certificate))
				{
					return certificate;
				}
			}
			return null;
		}

		protected override AsymmetricKeyParameter GetPrivateKey(IX509Selector selector)
		{
			foreach (Org.BouncyCastle.X509.X509Certificate certificate in certificates)
			{
				string fingerprint = certificate.GetFingerprint();
				if (keys.TryGetValue(fingerprint, out var value) && (selector == null || selector.Match(certificate)))
				{
					return value;
				}
			}
			return null;
		}

		protected override HashSet GetTrustedAnchors()
		{
			HashSet hashSet = new HashSet();
			foreach (Org.BouncyCastle.X509.X509Certificate certificate in certificates)
			{
				hashSet.Add(new TrustAnchor(certificate, null));
			}
			return hashSet;
		}

		protected override IX509Store GetIntermediateCertificates()
		{
			X509CertificateStore x509CertificateStore = new X509CertificateStore();
			foreach (Org.BouncyCastle.X509.X509Certificate certificate in certificates)
			{
				x509CertificateStore.Add(certificate);
			}
			return x509CertificateStore;
		}

		protected override IX509Store GetCertificateRevocationLists()
		{
			return X509StoreFactory.Create("Crl/Collection", new X509CollectionStoreParameters(crls));
		}

		protected override DateTime GetNextCertificateRevocationListUpdate(X509Name issuer)
		{
			DateTime minValue = DateTime.MinValue;
			DateTime dateTime = minValue.ToUniversalTime();
			foreach (X509Crl crl in crls)
			{
				if (crl.IssuerDN.Equals(issuer))
				{
					dateTime = ((crl.NextUpdate.Value > dateTime) ? crl.NextUpdate.Value : dateTime);
				}
			}
			return dateTime;
		}

		private Org.BouncyCastle.X509.X509Certificate GetCmsRecipientCertificate(MailboxAddress mailbox)
		{
			SecureMailboxAddress secureMailboxAddress = mailbox as SecureMailboxAddress;
			DateTime utcNow = DateTime.UtcNow;
			foreach (Org.BouncyCastle.X509.X509Certificate certificate in certificates)
			{
				if (certificate.NotBefore > utcNow || certificate.NotAfter < utcNow)
				{
					continue;
				}
				X509KeyUsageFlags keyUsageFlags = certificate.GetKeyUsageFlags();
				if (keyUsageFlags != X509KeyUsageFlags.None && (keyUsageFlags & X509KeyUsageFlags.KeyEncipherment) == 0)
				{
					continue;
				}
				if (secureMailboxAddress != null)
				{
					if (!certificate.GetFingerprint().Equals(secureMailboxAddress.Fingerprint, StringComparison.OrdinalIgnoreCase))
					{
						continue;
					}
				}
				else if (!certificate.GetSubjectEmailAddress().Equals(mailbox.Address, StringComparison.OrdinalIgnoreCase))
				{
					continue;
				}
				return certificate;
			}
			return null;
		}

		protected override CmsRecipient GetCmsRecipient(MailboxAddress mailbox)
		{
			Org.BouncyCastle.X509.X509Certificate cmsRecipientCertificate;
			if ((cmsRecipientCertificate = GetCmsRecipientCertificate(mailbox)) == null)
			{
				throw new CertificateNotFoundException(mailbox, "A valid certificate could not be found.");
			}
			CmsRecipient cmsRecipient = new CmsRecipient(cmsRecipientCertificate);
			if (capabilities.TryGetValue(cmsRecipientCertificate.GetFingerprint(), out var value))
			{
				cmsRecipient.EncryptionAlgorithms = value;
			}
			return cmsRecipient;
		}

		private Org.BouncyCastle.X509.X509Certificate GetCmsSignerCertificate(MailboxAddress mailbox, out AsymmetricKeyParameter key)
		{
			SecureMailboxAddress secureMailboxAddress = mailbox as SecureMailboxAddress;
			DateTime utcNow = DateTime.UtcNow;
			foreach (Org.BouncyCastle.X509.X509Certificate certificate in certificates)
			{
				if (certificate.NotBefore > utcNow || certificate.NotAfter < utcNow)
				{
					continue;
				}
				X509KeyUsageFlags keyUsageFlags = certificate.GetKeyUsageFlags();
				if (keyUsageFlags != X509KeyUsageFlags.None && (keyUsageFlags & (X509KeyUsageFlags.NonRepudiation | X509KeyUsageFlags.DigitalSignature)) == 0)
				{
					continue;
				}
				string fingerprint = certificate.GetFingerprint();
				if (!keys.TryGetValue(fingerprint, out key))
				{
					continue;
				}
				if (secureMailboxAddress != null)
				{
					if (!fingerprint.Equals(secureMailboxAddress.Fingerprint, StringComparison.OrdinalIgnoreCase))
					{
						continue;
					}
				}
				else if (!certificate.GetSubjectEmailAddress().Equals(mailbox.Address, StringComparison.OrdinalIgnoreCase))
				{
					continue;
				}
				return certificate;
			}
			key = null;
			return null;
		}

		protected override CmsSigner GetCmsSigner(MailboxAddress mailbox, DigestAlgorithm digestAlgo)
		{
			AsymmetricKeyParameter key;
			return new CmsSigner(GetCmsSignerCertificate(mailbox, out key) ?? throw new CertificateNotFoundException(mailbox, "A valid signing certificate could not be found."), key)
			{
				DigestAlgorithm = digestAlgo
			};
		}

		protected override void UpdateSecureMimeCapabilities(Org.BouncyCastle.X509.X509Certificate certificate, EncryptionAlgorithm[] algorithms, DateTime timestamp)
		{
			capabilities[certificate.GetFingerprint()] = algorithms;
		}

		public override void Import(Stream stream, string password)
		{
			if (stream == null)
			{
				throw new ArgumentNullException("stream");
			}
			if (password == null)
			{
				throw new ArgumentNullException("password");
			}
			Pkcs12Store pkcs12Store = new Pkcs12Store(stream, password.ToCharArray());
			foreach (string alias in pkcs12Store.Aliases)
			{
				if (pkcs12Store.IsKeyEntry(alias))
				{
					X509CertificateEntry[] certificateChain = pkcs12Store.GetCertificateChain(alias);
					AsymmetricKeyEntry key = pkcs12Store.GetKey(alias);
					for (int i = 0; i < certificateChain.Length; i++)
					{
						Import(certificateChain[i].Certificate);
					}
					string fingerprint = certificateChain[0].Certificate.GetFingerprint();
					if (!keys.ContainsKey(fingerprint))
					{
						keys.Add(fingerprint, key.Key);
					}
				}
				else if (pkcs12Store.IsCertificateEntry(alias))
				{
					X509CertificateEntry certificate = pkcs12Store.GetCertificate(alias);
					Import(certificate.Certificate);
				}
			}
		}

		public override void Import(Org.BouncyCastle.X509.X509Certificate certificate)
		{
			if (certificate == null)
			{
				throw new ArgumentNullException("certificate");
			}
			if (fingerprints.Add(certificate.GetFingerprint()))
			{
				certificates.Add(certificate);
			}
		}

		public override void Import(X509Crl crl)
		{
			if (crl == null)
			{
				throw new ArgumentNullException("crl");
			}
			crls.Add(crl);
		}
	}
	public static class X509Certificate2Extensions
	{
		public static Org.BouncyCastle.X509.X509Certificate AsBouncyCastleCertificate(this X509Certificate2 certificate)
		{
			if (certificate == null)
			{
				throw new ArgumentNullException("certificate");
			}
			byte[] rawCertData = certificate.GetRawCertData();
			return new X509CertificateParser().ReadCertificate(rawCertData);
		}

		public static PublicKeyAlgorithm GetPublicKeyAlgorithm(this X509Certificate2 certificate)
		{
			if (certificate == null)
			{
				throw new ArgumentNullException("certificate");
			}
			return new Oid(certificate.GetKeyAlgorithm()).FriendlyName switch
			{
				"DSA" => PublicKeyAlgorithm.Dsa, 
				"RSA" => PublicKeyAlgorithm.RsaGeneral, 
				"ECC" => PublicKeyAlgorithm.EllipticCurve, 
				"DH" => PublicKeyAlgorithm.DiffieHellman, 
				_ => PublicKeyAlgorithm.None, 
			};
		}

		private static EncryptionAlgorithm[] DecodeEncryptionAlgorithms(byte[] rawData)
		{
			using MemoryStream inputStream = new MemoryStream(rawData, writable: false);
			using Asn1InputStream asn1InputStream = new Asn1InputStream(inputStream);
			List<EncryptionAlgorithm> list = new List<EncryptionAlgorithm>();
			if (!(asn1InputStream.ReadObject() is Asn1Sequence asn1Sequence))
			{
				return null;
			}
			for (int i = 0; i < asn1Sequence.Count; i++)
			{
				if (BouncyCastleSecureMimeContext.TryGetEncryptionAlgorithm(AlgorithmIdentifier.GetInstance(asn1Sequence[i]), out var algorithm))
				{
					list.Add(algorithm);
				}
			}
			return list.ToArray();
		}

		public static EncryptionAlgorithm[] GetEncryptionAlgorithms(this X509Certificate2 certificate)
		{
			if (certificate == null)
			{
				throw new ArgumentNullException("certificate");
			}
			X509ExtensionEnumerator enumerator = certificate.Extensions.GetEnumerator();
			while (enumerator.MoveNext())
			{
				System.Security.Cryptography.X509Certificates.X509Extension current = enumerator.Current;
				if (current.Oid.Value == "1.2.840.113549.1.9.15")
				{
					EncryptionAlgorithm[] array = DecodeEncryptionAlgorithms(current.RawData);
					if (array == null)
					{
						break;
					}
					return array;
				}
			}
			return new EncryptionAlgorithm[1] { EncryptionAlgorithm.TripleDes };
		}
	}
	public class X509CertificateChain : IList<Org.BouncyCastle.X509.X509Certificate>, ICollection<Org.BouncyCastle.X509.X509Certificate>, IEnumerable<Org.BouncyCastle.X509.X509Certificate>, IEnumerable, IX509Store
	{
