		public void AddRange(IEnumerable<Org.BouncyCastle.X509.X509Certificate> certificates)
		{
			if (certificates == null)
			{
				throw new ArgumentNullException("certificates");
			}
			foreach (Org.BouncyCastle.X509.X509Certificate certificate in certificates)
			{
				Add(certificate);
			}
		}

		public void Clear()
		{
			certificates.Clear();
		}

		public bool Contains(Org.BouncyCastle.X509.X509Certificate certificate)
		{
