		public X509CertificateRecord Find(Org.BouncyCastle.X509.X509Certificate certificate, X509CertificateRecordFields fields)
		{
			if (certificate == null)
			{
				throw new ArgumentNullException("certificate");
			}
			using (DbCommand dbCommand = GetSelectCommand(certificate, fields))
			{
				DbDataReader dbDataReader = dbCommand.ExecuteReader();
				try
				{
					if (dbDataReader.Read())
					{
						X509CertificateParser parser = new X509CertificateParser();
						byte[] buffer = new byte[4096];
						return LoadCertificateRecord(dbDataReader, parser, ref buffer);
					}
				}
				finally
				{
					dbDataReader.Close();
				}
			}
			return null;
		}

		public IEnumerable<Org.BouncyCastle.X509.X509Certificate> FindCertificates(IX509Selector selector)
		{
			using DbCommand command = GetSelectCommand(selector, trustedOnly: false, requirePrivateKey: false, X509CertificateRecordFields.Certificate);
			DbDataReader reader = command.ExecuteReader();
			try
			{
				X509CertificateParser parser = new X509CertificateParser();
				byte[] buffer = new byte[4096];
				while (reader.Read())
				{
					X509CertificateRecord x509CertificateRecord = LoadCertificateRecord(reader, parser, ref buffer);
					if (selector == null || selector.Match(x509CertificateRecord.Certificate))
					{
						yield return x509CertificateRecord.Certificate;
					}
				}
			}
			finally
			{
				reader.Close();
			}
		}

