	[Flags]
	public enum X509CertificateRecordFields
	{
		Id = 1,
		Trusted = 2,
		Algorithms = 8,
		AlgorithmsUpdated = 0x10,
		Certificate = 0x20,
		PrivateKey = 0x40
	}
	public class X509CertificateRecord
	{
		internal static readonly string[] ColumnNames = new string[14]
		{
			"ID", "BASICCONSTRAINTS", "TRUSTED", "KEYUSAGE", "NOTBEFORE", "NOTAFTER", "ISSUERNAME", "SERIALNUMBER", "SUBJECTEMAIL", "FINGERPRINT",
			"ALGORITHMS", "ALGORITHMSUPDATED", "CERTIFICATE", "PRIVATEKEY"
		};

		public int Id { get; internal set; }

		public int BasicConstraints => Certificate.GetBasicConstraints();

		public bool IsTrusted { get; set; }

		public X509KeyUsageFlags KeyUsage => Certificate.GetKeyUsageFlags();

		public DateTime NotBefore => Certificate.NotBefore.ToUniversalTime();

		public DateTime NotAfter => Certificate.NotAfter.ToUniversalTime();

		public string IssuerName => Certificate.IssuerDN.ToString();

		public string SerialNumber => Certificate.SerialNumber.ToString();

		public string SubjectEmail => Certificate.GetSubjectEmailAddress();

		public string Fingerprint => Certificate.GetFingerprint();

		public EncryptionAlgorithm[] Algorithms { get; set; }

		public DateTime AlgorithmsUpdated { get; set; }

		public Org.BouncyCastle.X509.X509Certificate Certificate { get; internal set; }

		public AsymmetricKeyParameter PrivateKey { get; set; }

		public X509CertificateRecord(Org.BouncyCastle.X509.X509Certificate certificate, AsymmetricKeyParameter key)
		{
			if (certificate == null)
			{
				throw new ArgumentNullException("certificate");
			}
			if (key == null)
			{
				throw new ArgumentNullException("key");
			}
			if (!key.IsPrivate)
			{
				throw new ArgumentException("The key must be private.", "key");
			}
			AlgorithmsUpdated = DateTime.MinValue;
			Certificate = certificate;
			PrivateKey = key;
		}

		public X509CertificateRecord(Org.BouncyCastle.X509.X509Certificate certificate)
		{
			if (certificate == null)
			{
				throw new ArgumentNullException("certificate");
			}
			AlgorithmsUpdated = DateTime.MinValue;
			Certificate = certificate;
		}

		public X509CertificateRecord()
		{
		}
	}
	public class X509CertificateStore : IX509Store
	{
		private readonly Dictionary<Org.BouncyCastle.X509.X509Certificate, AsymmetricKeyParameter> keys;

		private readonly HashSet<Org.BouncyCastle.X509.X509Certificate> unique;

		private readonly List<Org.BouncyCastle.X509.X509Certificate> certs;

		public IEnumerable<Org.BouncyCastle.X509.X509Certificate> Certificates => certs;

		public X509CertificateStore()
		{
			keys = new Dictionary<Org.BouncyCastle.X509.X509Certificate, AsymmetricKeyParameter>();
			unique = new HashSet<Org.BouncyCastle.X509.X509Certificate>();
			certs = new List<Org.BouncyCastle.X509.X509Certificate>();
		}

		public AsymmetricKeyParameter GetPrivateKey(Org.BouncyCastle.X509.X509Certificate certificate)
		{
			if (!keys.TryGetValue(certificate, out var value))
			{
				return null;
			}
			return value;
		}

		public void Add(Org.BouncyCastle.X509.X509Certificate certificate)
		{
			if (certificate == null)
			{
				throw new ArgumentNullException("certificate");
			}
			if (unique.Add(certificate))
			{
				certs.Add(certificate);
			}
		}

		public void AddRange(IEnumerable<Org.BouncyCastle.X509.X509Certificate> certificates)
		{
			if (certificates == null)
			{
				throw new ArgumentNullException("certificates");
			}
			foreach (Org.BouncyCastle.X509.X509Certificate certificate in certificates)
			{
				if (unique.Add(certificate))
				{
					certs.Add(certificate);
				}
			}
		}

		public void Remove(Org.BouncyCastle.X509.X509Certificate certificate)
		{
			if (certificate == null)
			{
				throw new ArgumentNullException("certificate");
			}
			if (unique.Remove(certificate))
			{
				certs.Remove(certificate);
			}
		}

		public void RemoveRange(IEnumerable<Org.BouncyCastle.X509.X509Certificate> certificates)
		{
			if (certificates == null)
			{
				throw new ArgumentNullException("certificates");
			}
			foreach (Org.BouncyCastle.X509.X509Certificate certificate in certificates)
			{
				if (unique.Remove(certificate))
				{
					certs.Remove(certificate);
				}
			}
		}

		public void Import(Stream stream)
		{
			if (stream == null)
			{
				throw new ArgumentNullException("stream");
			}
			foreach (Org.BouncyCastle.X509.X509Certificate item in new X509CertificateParser().ReadCertificates(stream))
			{
				if (unique.Add(item))
				{
					certs.Add(item);
				}
			}
		}

