		public void Import(Stream stream, string password)
		{
			if (stream == null)
			{
				throw new ArgumentNullException("stream");
			}
			if (password == null)
			{
				throw new ArgumentNullException("password");
			}
			Pkcs12Store pkcs12Store = new Pkcs12Store(stream, password.ToCharArray());
			foreach (string alias in pkcs12Store.Aliases)
			{
				if (pkcs12Store.IsKeyEntry(alias))
				{
					X509CertificateEntry[] certificateChain = pkcs12Store.GetCertificateChain(alias);
					AsymmetricKeyEntry key = pkcs12Store.GetKey(alias);
					for (int i = 0; i < certificateChain.Length; i++)
					{
						if (unique.Add(certificateChain[i].Certificate))
						{
							certs.Add(certificateChain[i].Certificate);
						}
					}
					if (key.Key.IsPrivate)
					{
						keys.Add(certificateChain[0].Certificate, key.Key);
					}
				}
				else if (pkcs12Store.IsCertificateEntry(alias))
				{
					X509CertificateEntry certificate = pkcs12Store.GetCertificate(alias);
					if (unique.Add(certificate.Certificate))
					{
						certs.Add(certificate.Certificate);
					}
				}
			}
		}

		public void Import(string fileName, string password)
		{
			if (fileName == null)
			{
				throw new ArgumentNullException("fileName");
			}
			using FileStream stream = File.OpenRead(fileName);
			Import(stream, password);
		}

		public void Import(byte[] rawData, string password)
		{
			if (rawData == null)
			{
				throw new ArgumentNullException("rawData");
			}
			using MemoryStream stream = new MemoryStream(rawData, writable: false);
			Import(stream, password);
		}

		public void Export(Stream stream)
		{
			if (stream == null)
			{
				throw new ArgumentNullException("stream");
			}
			foreach (Org.BouncyCastle.X509.X509Certificate cert in certs)
			{
				byte[] encoded = cert.GetEncoded();
				stream.Write(encoded, 0, encoded.Length);
			}
		}

		public void Export(string fileName)
		{
			if (fileName == null)
			{
				throw new ArgumentNullException("fileName");
			}
			using FileStream stream = File.Create(fileName);
			Export(stream);
		}

		public void Export(Stream stream, string password)
		{
			if (stream == null)
			{
				throw new ArgumentNullException("stream");
			}
			if (password == null)
			{
				throw new ArgumentNullException("password");
			}
			Pkcs12Store pkcs12Store = new Pkcs12Store();
			foreach (Org.BouncyCastle.X509.X509Certificate cert in certs)
			{
				if (!keys.ContainsKey(cert))
				{
					string commonName = cert.GetCommonName();
					if (commonName != null)
					{
						X509CertificateEntry certEntry = new X509CertificateEntry(cert);
						pkcs12Store.SetCertificateEntry(commonName, certEntry);
					}
				}
			}
			foreach (KeyValuePair<Org.BouncyCastle.X509.X509Certificate, AsymmetricKeyParameter> key in keys)
			{
				string commonName2 = key.Key.GetCommonName();
				if (commonName2 != null)
				{
					AsymmetricKeyEntry keyEntry = new AsymmetricKeyEntry(key.Value);
					X509CertificateEntry item = new X509CertificateEntry(key.Key);
					List<X509CertificateEntry> list = new List<X509CertificateEntry>();
					list.Add(item);
					pkcs12Store.SetKeyEntry(commonName2, keyEntry, list.ToArray());
				}
			}
			pkcs12Store.Save(stream, password.ToCharArray(), new SecureRandom());
		}

		public void Export(string fileName, string password)
		{
			if (fileName == null)
			{
				throw new ArgumentNullException("fileName");
			}
			if (password == null)
			{
				throw new ArgumentNullException("password");
			}
			using FileStream stream = File.Create(fileName);
			Export(stream, password);
		}

		public IEnumerable<Org.BouncyCastle.X509.X509Certificate> GetMatches(IX509Selector selector)
		{
			foreach (Org.BouncyCastle.X509.X509Certificate cert in certs)
			{
				if (selector == null || selector.Match(cert))
				{
					yield return cert;
				}
			}
		}

		ICollection IX509Store.GetMatches(IX509Selector selector)
		{
			List<Org.BouncyCastle.X509.X509Certificate> list = new List<Org.BouncyCastle.X509.X509Certificate>();
			foreach (Org.BouncyCastle.X509.X509Certificate match in GetMatches(selector))
			{
				list.Add(match);
			}
			return list;
		}
	}
	[Flags]
	public enum X509CrlRecordFields
	{
		Id = 1,
		IsDelta = 2,
		IssuerName = 4,
		ThisUpdate = 8,
		NextUpdate = 0x10,
		Crl = 0x20
	}
	public class X509CrlRecord
	{
		internal static readonly string[] ColumnNames = new string[6] { "ID", "DELTA", "ISSUERNAME", "THISUPDATE", "NEXTUPDATE", "CRL" };

		public int Id { get; internal set; }

		public bool IsDelta { get; internal set; }

		public string IssuerName { get; internal set; }

		public DateTime ThisUpdate { get; internal set; }

		public DateTime NextUpdate { get; internal set; }

		public X509Crl Crl { get; set; }

		public X509CrlRecord(X509Crl crl)
		{
			if (crl == null)
			{
				throw new ArgumentNullException("crl");
			}
			if (crl.NextUpdate != null)
			{
				NextUpdate = crl.NextUpdate.Value.ToUniversalTime();
			}
			IssuerName = crl.IssuerDN.ToString();
			ThisUpdate = crl.ThisUpdate.ToUniversalTime();
			IsDelta = crl.IsDelta();
			Crl = crl;
		}

		public X509CrlRecord()
		{
		}
	}
	[Flags]
	public enum X509KeyUsageFlags
	{
		None = 0,
		EncipherOnly = 1,
		CrlSign = 2,
		KeyCertSign = 4,
		KeyAgreement = 8,
		DataEncipherment = 0x10,
		KeyEncipherment = 0x20,
		NonRepudiation = 0x40,
		DigitalSignature = 0x80,
		DecipherOnly = 0x8000
	}
	internal enum X509KeyUsageBits
	{
		DigitalSignature,
		NonRepudiation,
		KeyEncipherment,
		DataEncipherment,
		KeyAgreement,
		KeyCertSign,
		CrlSign,
		EncipherOnly,
		DecipherOnly
	}
}
